const StoreCtx = createContext(null);
const useStore = () => useContext(StoreCtx);
const LS_KEY = "tanmay_edits_v1";
const EMPTY_H = [0, 0, 0, 0, 0, 0, 0, 0, 0];
function loadEdits() { try { const r = window.localStorage.getItem(LS_KEY); return r ? JSON.parse(r) : {}; } catch (e) { return {}; } }
function saveEdits(e) { try { window.localStorage.setItem(LS_KEY, JSON.stringify(e)); } catch (err) {} }
function shiftISO(iso, delta) { const [y, m, d] = iso.split("-").map(Number); const dt = new Date(y, m - 1, d); dt.setDate(dt.getDate() + delta); return dt.getFullYear() + "-" + String(dt.getMonth() + 1).padStart(2, "0") + "-" + String(dt.getDate()).padStart(2, "0"); }
const LS_COLL = "tanmay_coll_v1";
// ---- ČISTÝ START · 20. 7. 2026. Jednorázová migrace zařízení: smaže denní
// záznamy návyků a těla, rozdělané/hotové cíle a všechny příjmy a výdaje.
// Deník, zápisník, prameny, oblasti, nastavení i struktura zůstávají netknuté.
// Běží jedinkrát — pak si zapíše vlajku a už se nikdy nespustí.
(function tmFreshStart() {
  try {
    if (typeof window === "undefined" || !window.localStorage) return;
    const FLAG = "tmFresh20260720";
    if (localStorage.getItem(FLAG)) return;
    // denní záznamy (klíče ve tvaru ISO data) pryč, struktura zůstává
    try {
      const raw = localStorage.getItem("tanmay_edits_v1");
      if (raw) {
        const e = JSON.parse(raw);
        Object.keys(e).forEach((k) => { if (/^\d{4}-\d{2}-\d{2}$/.test(k)) delete e[k]; });
        localStorage.setItem("tanmay_edits_v1", JSON.stringify(e));
      }
    } catch (err) {}
    try {
      const raw = localStorage.getItem("tanmay_coll_v1");
      if (raw) {
        const c = JSON.parse(raw);
        // finance · vše zapsané pryč
        c.expenses = []; c.income = [];
        // cíle · zůstávají jen nezačaté (seedové i vlastní)
        const seedKeep = ["Bratrstvo ticha a síly", "Create highlights with my offer", "Zajít na pojistovnu", "Pencake stretch to press handstand", "90 degree press to handstand", "Lotus", "Front lever row", "Straddle planche 5s"];
        const effStatus = (name, own) => {
          const p = (c.goalEdits || {})[name] || {};
          if (p.status != null) return p.status;
          if (c.goals && c.goals[name] != null) return c.goals[name];
          return own || "Not started";
        };
        const survivors = new Set();
        seedKeep.forEach((n) => { if (effStatus(n, "Not started") === "Not started") survivors.add(n); else c.goalEdits = { ...(c.goalEdits || {}), [n]: { trashed: true } }; });
        c.userGoals = (c.userGoals || []).filter((g) => { const ok = effStatus(g.name, g.status) === "Not started"; if (ok) survivors.add(g.name); return ok; });
        ["goalEdits", "goals", "goalNotes", "goalMeta"].forEach((key) => {
          if (!c[key]) return;
          const nx = {};
          Object.keys(c[key]).forEach((n) => { if (survivors.has(n) || ((c[key][n] || {}).trashed)) nx[n] = c[key][n]; });
          c[key] = nx;
        });
        if (Array.isArray(c.goalOrder)) c.goalOrder = c.goalOrder.filter((n) => survivors.has(n));
        localStorage.setItem("tanmay_coll_v1", JSON.stringify(c));
      }
    } catch (err) {}
    localStorage.setItem(FLAG, "1");
  } catch (err) {}
})();

function loadColl() { try { const r = window.localStorage.getItem(LS_COLL); return r ? JSON.parse(r) : { goals: {}, journal: [], notebook: [] }; } catch (e) { return { goals: {}, journal: [], notebook: [] }; } }
function saveColl(c) { try { window.localStorage.setItem(LS_COLL, JSON.stringify(c)); } catch (err) {} }
function uid() { return Date.now().toString(36) + Math.random().toString(36).slice(2, 6); }
function todayISO() { const d = new Date(); return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0") + "-" + String(d.getDate()).padStart(2, "0"); }
function fmtSize(n) { if (!n && n !== 0) return ""; if (n < 1024) return n + " B"; if (n < 1048576) return Math.round(n / 1024) + " kB"; return (n / 1048576).toFixed(1) + " MB"; }
function idbOpen() {
  return new Promise((res, rej) => {
    const r = indexedDB.open("tanmay_files", 1);
    r.onupgradeneeded = () => { r.result.createObjectStore("files"); };
    r.onsuccess = () => res(r.result);
    r.onerror = () => rej(r.error);
  });
}
async function idbPut(id, blob) { const db = await idbOpen(); return new Promise((res, rej) => { const tx = db.transaction("files", "readwrite"); tx.objectStore("files").put(blob, id); tx.oncomplete = () => res(); tx.onerror = () => rej(tx.error); }); }
async function idbGet(id) { const db = await idbOpen(); return new Promise((res, rej) => { const tx = db.transaction("files", "readonly"); const q = tx.objectStore("files").get(id); q.onsuccess = () => res(q.result || null); q.onerror = () => rej(q.error); }); }
function idbDel(id) { idbOpen().then((db) => { const tx = db.transaction("files", "readwrite"); tx.objectStore("files").delete(id); }).catch(() => {}); }
// ---- R2 file store (cloud, cross-device) ----
// Media (images, files, audio, covers, icons) live in R2, referenced by id.
// The IndexedDB helpers above are kept as the substrate for a future per-page
// "save offline" toggle; new media goes straight to R2.
function r2Url(id) { return "/api/files/" + encodeURIComponent(id); }
function r2Del(id) { fetch("/api/files/" + encodeURIComponent(id), { method: "DELETE" }).catch(() => {}); }
async function r2Put(id, blob, name) {
  const res = await fetch("/api/files/" + encodeURIComponent(id), {
    method: "PUT",
    headers: { "Content-Type": (blob && blob.type) || "application/octet-stream", "X-File-Name": encodeURIComponent(name || "") },
    body: blob,
  });
  if (!res.ok) throw new Error("upload failed: " + res.status);
  return true;
}
// cover/icon ref: new R2 { r2id } or legacy inline dataURL string
function imgSrc(v) { if (!v) return ""; if (typeof v === "string") return v; if (v.r2id) return r2Url(v.r2id); return ""; }
// attachment ref: R2 (id) or legacy inline base64 (data)
function attUrl(a) { return a && a.r2 ? r2Url(a.id) : (a ? a.data : ""); }
const R2_MAX = 95 * 1024 * 1024; // Worker request-body limit is 100 MB; stay under.
// Collect every R2 file id referenced anywhere in a document subtree.
// Used by garbage collection (and later by the offline "pin page" toggle).
function collectFileRefs(node, out) {
  if (!node) return;
  if (Array.isArray(node)) { for (const x of node) collectFileRefs(x, out); return; }
  if (typeof node === "string") {
    const m = node.match(/^\/api\/files\/([^?#]+)$/);
    if (m) out.add(decodeURIComponent(m[1]));
    return;
  }
  if (typeof node === "object") {
    if (node.r2 === true && node.id) out.add(node.id);
    if (node.r2id) out.add(node.r2id);
    for (const k of Object.keys(node)) collectFileRefs(node[k], out);
  }
}

// ---- Offline pinning (per-device; not synced) ----
// A pinned entry has its media cached so it opens offline. Registry lives in
// localStorage; the service worker serves /api/files/<id> from the "pinned"
// cache when present. Text is always offline (localStorage), so only entries
// with media are pinnable.
function pinnedRegistry() { try { return JSON.parse(localStorage.getItem("tm_pinned") || "{}"); } catch (e) { return {}; } }
function savePinnedRegistry(r) { try { localStorage.setItem("tm_pinned", JSON.stringify(r)); } catch (e) {} }
function isEntryPinned(id) { return !!pinnedRegistry()[id]; }
function entryFileIds(entry) { const set = new Set(); collectFileRefs(entry, set); return [...set]; }
async function pinEntry(entry) {
  const ids = entryFileIds(entry);
  try {
    const cache = await caches.open("pinned");
    for (const id of ids) {
      const url = "/api/files/" + encodeURIComponent(id);
      try { const res = await fetch(url, { cache: "no-store" }); if (res.ok) await cache.put(url, res.clone()); } catch (e) {}
    }
  } catch (e) {}
  const reg = pinnedRegistry(); reg[entry.id] = ids; savePinnedRegistry(reg);
  return ids.length;
}
async function unpinEntry(entryId) {
  const reg = pinnedRegistry();
  const mine = reg[entryId] || [];
  delete reg[entryId];
  const stillNeeded = new Set();
  for (const ids of Object.values(reg)) for (const id of ids) stillNeeded.add(id);
  try {
    const cache = await caches.open("pinned");
    for (const id of mine) if (!stillNeeded.has(id)) { try { await cache.delete("/api/files/" + encodeURIComponent(id)); } catch (e) {} }
  } catch (e) {}
  savePinnedRegistry(reg);
}
function PinDot({ id }) {
  const { t } = useT();
  if (!isEntryPinned(id)) return null;
  return <span title={L("Uloženo offline", "Saved offline")} style={{ width: 6, height: 6, borderRadius: "50%", background: t.accent, flexShrink: 0, display: "inline-block" }} />;
}
function PinToggle({ entry }) {
  const { t } = useT();
  const ids = entryFileIds(entry);
  const [pinned, setPinned] = useState(() => isEntryPinned(entry.id));
  const [busy, setBusy] = useState(false);
  if (!ids.length) return null;
  const toggle = async () => {
    setBusy(true);
    try { if (pinned) { await unpinEntry(entry.id); setPinned(false); } else { await pinEntry(entry); setPinned(true); } } catch (e) {}
    setBusy(false);
  };
  return (
    <button onClick={toggle} disabled={busy} title={pinned ? L("Uloženo offline — klikni pro odebrání", "Saved offline — click to remove") : L("Uložit média této stránky offline", "Save this page's media offline")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: pinned ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${pinned ? t.accent : t.border}`, borderRadius: 999, padding: "4px 11px", cursor: busy ? "default" : "pointer", color: pinned ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5, opacity: busy ? 0.6 : 1, whiteSpace: "nowrap" }}>
      <span style={{ width: 6, height: 6, borderRadius: "50%", background: pinned ? t.accent : t.textMuted, flexShrink: 0 }} />
      {busy ? L("Ukládám…", "Saving…") : pinned ? L("Uloženo offline", "Saved offline") : L("Uložit offline", "Save offline")}
    </button>
  );
}
// One-time migration of legacy inline media (base64 attachments, IndexedDB audio,
// dataURL covers/icons/bg) into R2. Idempotent + safe: upload first, swap the
// reference only after; on any failure the original is left untouched. Works on a
// deep clone; nothing local is deleted. Run from the console via tmMigrateMedia().
async function _dataUrlToBlob(u) { return (await fetch(u)).blob(); }
async function migrateNode(node, stats, dryRun) {
  if (Array.isArray(node)) {
    for (let i = 0; i < node.length; i++) node[i] = await migrateNode(node[i], stats, dryRun);
    return node;
  }
  if (node && typeof node === "object") {
    if (node.id && typeof node.data === "string" && node.data.startsWith("data:")) {
      stats.found++;
      if (dryRun) return node;
      try {
        const blob = await _dataUrlToBlob(node.data);
        await r2Put(node.id, blob, node.name);
        stats.uploaded++;
        return { id: node.id, name: node.name, type: node.type, size: node.size, r2: true };
      } catch (e) { stats.failed++; return node; }
    }
    if (node.id && node.idb === true) {
      stats.found++;
      if (dryRun) return node;
      try {
        const blob = await idbGet(node.id);
        if (!blob) { stats.skipped++; return node; }
        await r2Put(node.id, blob, node.name);
        stats.uploaded++;
        const { idb, ...rest } = node;
        return { ...rest, r2: true };
      } catch (e) { stats.failed++; return node; }
    }
    for (const k of Object.keys(node)) {
      const v = node[k];
      if (typeof v === "string" && v.startsWith("data:") && (k === "cover" || k === "icon" || k === "bg")) {
        stats.foundImg++;
        if (!dryRun) {
          try {
            const blob = await _dataUrlToBlob(v);
            const id = uid() + "m";
            await r2Put(id, blob, k);
            stats.uploaded++;
            node[k] = (k === "bg") ? r2Url(id) : { r2id: id };
          } catch (e) { stats.failed++; }
        }
      } else {
        node[k] = await migrateNode(v, stats, dryRun);
      }
    }
    return node;
  }
  return node;
}
async function makeAudioAtt(file) {
  const id = uid() + "a";
  await r2Put(id, file, file.name);
  return { id, name: file.name, type: file.type || "audio/mpeg", size: file.size, r2: true };
}
async function filesToAtts(fileList, askFn) {
  const out = [];
  for (const f of Array.from(fileList || [])) {
    const isAudio = (f.type || "").startsWith("audio/");
    const max = R2_MAX;
    if (f.size > max) { if (askFn) askFn(`„${f.name}" je příliš velký (${fmtSize(f.size)}). Limit ${fmtSize(max)}.`, null); continue; }
    try { out.push(isAudio ? await makeAudioAtt(f) : await readFileAsAtt(f)); } catch (e) {}
  }
  return out;
}
function resizeImageToBlob(file, maxSide) {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const img = new Image();
    img.onload = () => {
      const scale = Math.min(1, (maxSide || 320) / Math.max(img.width, img.height));
      const w = Math.round(img.width * scale), h = Math.round(img.height * scale);
      const c = document.createElement("canvas");
      c.width = w; c.height = h;
      c.getContext("2d").drawImage(img, 0, 0, w, h);
      URL.revokeObjectURL(url);
      c.toBlob((b) => b ? resolve(b) : reject(new Error("blob failed")), "image/jpeg", 0.82);
    };
    img.onerror = () => { URL.revokeObjectURL(url); reject(new Error("img load failed")); };
    img.src = url;
  });
}
async function readFileAsAtt(file) {
  const id = uid();
  await r2Put(id, file, file.name);
  return { id, name: file.name, type: file.type || "application/octet-stream", size: file.size, r2: true };
}
