function PageAtomic() {
  const { t } = useT();
  const li = { fontFamily: FONT_BODY, fontSize: 13.5, lineHeight: 1.7, color: t.textSec, paddingLeft: 20, margin: "4px 0" };
  const chip = { fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.heading, background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 999, padding: "6px 13px", whiteSpace: "nowrap" };
  const card = { background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 12, padding: "14px 16px", boxShadow: t.shadow };
  const loop = [["Spouštěč", "Cue"], ["Touha", "Craving"], ["Reakce", "Response"], ["Odměna", "Reward"]];
  const laws = [
    { n: "1", cz: "Udělej to zřejmé", en: "Make it obvious", inv: L("skryj to", "make it invisible") },
    { n: "2", cz: "Udělej to přitažlivé", en: "Make it attractive", inv: L("znechuť to", "make it unattractive") },
    { n: "3", cz: "Udělej to snadné", en: "Make it easy", inv: L("ztěž to", "make it difficult") },
    { n: "4", cz: "Udělej to uspokojivé", en: "Make it satisfying", inv: L("znechuť následek", "make it unsatisfying") },
  ];
  return (
    <>
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><BookIcon size={34} /></span>} pageKey="atomic" kicker={L("Výpisek · James Clear", "Notes · James Clear")}>Atomic Habits</PageTitle>
      <p style={{ ...pProse(t), fontSize: 14 }}>{L("Rychlá referenční karta — jak zvyky fungují.", "A quick reference — how habits work.")} <span style={{ fontFamily: FONT_DISPLAY, fontStyle: "italic", color: t.sand }}>Malé zisky, které se skládají.</span></p>

      <Eyebrow>{L("Smyčka zvyku", "The habit loop")}</Eyebrow>
      <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 8, marginBottom: 20 }}>
        {loop.map(([cz, en], i) => (
          <React.Fragment key={cz}>
            <span style={chip}>{L(cz, en)}</span>
            <span style={{ color: t.sand, fontSize: 15 }}>{i < loop.length - 1 ? "→" : "↺"}</span>
          </React.Fragment>
        ))}
      </div>

      <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><PenIcon size={16} /></span>} title={L("Recept na zvyk", "The habit recipe")}>
        <div style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.textSec, lineHeight: 1.7 }}>
          <div><span style={{ color: t.accent }}>I will</span> [behaviour] <span style={{ color: t.accent }}>at</span> [time] <span style={{ color: t.accent }}>in</span> [location].</div>
          <div style={{ marginTop: 4 }}><span style={{ color: t.accent }}>After</span> [current habit], <span style={{ color: t.accent }}>I will</span> [new habit].</div>
        </div>
      </Callout>

      <Eyebrow>{L("Čtyři zákony", "The four laws")}</Eyebrow>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 10, marginBottom: 20 }}>
        {laws.map((law) => (
          <div key={law.n} style={card}>
            <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
              <span style={{ fontFamily: FONT_DISPLAY, fontSize: 22, color: t.accent, lineHeight: 1 }}>{law.n}</span>
              <span style={{ fontFamily: FONT_DISPLAY, fontSize: 16.5, color: t.heading }}>{L(law.cz, law.en)}</span>
            </div>
            <div style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textMuted, marginTop: 4 }}>{L("zlozvyk: ", "break it: ")}{law.inv}</div>
          </div>
        ))}
      </div>

      <Eyebrow>{L("Do hloubky", "In depth")}</Eyebrow>
      <Toggle summary={L("1 · Udělej to zřejmé", "1 · Make It Obvious")} color="orange">
        <p style={{ margin: "0 0 6px" }}>Habit Scorecard — {L("výpis denních zvyků a jejich vědomé ohodnocení", "list your daily habits and rate them")} (+ / − / =).</p>
        <ul style={li}>
          <li>Implementation intention: „I will meditate for 5 mins at 7am on the balcony."</li>
          <li>Habit stacking: „After [current habit], I will [new habit]."</li>
          <li>{L("Prostředí: malé změny prostředí → velké změny chování v čase.", "Environment: small changes of place → big changes of behaviour over time.")}</li>
        </ul>
      </Toggle>
      <Toggle summary={L("2 · Udělej to přitažlivé", "2 · Make It Attractive")} color="orange">
        <ul style={li}>
          <li>Temptation bundling: {L("po zvyku, který potřebuji, následuje zvyk, který chci.", "after a habit I need, do a habit I want.")}</li>
          <li>{L("Příklad: vezmu telefon → 10 kliků → teprve pak Instagram.", "Example: pick up the phone → 10 pull-ups → only then Instagram.")}</li>
          <li>{L("Vstup do kultury, kde je tvé žádoucí chování normou.", "Join a culture where your desired behaviour is the norm.")}</li>
        </ul>
      </Toggle>
      <Toggle summary={L("3 · Udělej to snadné", "3 · Make It Easy")} color="orange">
        <ul style={li}>
          <li>{L("Sniž tření: méně kroků mezi tebou a dobrým zvykem.", "Reduce friction: fewer steps between you and the good habit.")}</li>
          <li>{L("Pravidlo dvou minut: zmenši zvyk tak, aby šel udělat do dvou minut.", "Two-minute rule: shrink the habit so it takes under two minutes.")}</li>
          <li>{L("Automatizace: jednorázová investice, která uzamkne budoucí chování.", "Automation: a one-time investment that locks in future behaviour.")}</li>
        </ul>
      </Toggle>
      <Toggle summary={L("4 · Udělej to uspokojivé", "4 · Make It Satisfying")} color="orange">
        <ul style={li}>
          <li>{L("Okamžitá odměna, jakákoliv — mozek opakuje, co se hned vyplatí.", "Immediate reward, any — the brain repeats what pays off now.")}</li>
          <li>{L("Nikdy nevynech dvakrát za sebou — tracker drží řadu.", "Never miss twice — the tracker keeps the streak.")}</li>
        </ul>
      </Toggle>

      <div style={{ marginTop: 26 }}>
        <Eyebrow>{L("Zlatý kruh · proč, jak, co", "Golden circle · why, how, what")}</Eyebrow>
        <svg viewBox="0 0 300 300" role="img" aria-label={L("Zlatý kruh a vrstvy identity", "Golden circle and identity layers")} style={{ display: "block", width: "100%", maxWidth: 330, margin: "4px auto 0" }}>
          <circle cx="150" cy="150" r="132" fill="none" stroke={t.border} strokeWidth="1" />
          <circle cx="150" cy="150" r="88" fill="none" stroke={t.border} strokeWidth="1" />
          <circle cx="150" cy="150" r="46" fill={hexA(t.accent, 0.12)} stroke={t.accent} strokeWidth="1.2" />
          <text x="150" y="33" textAnchor="middle" style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.24em", fontSize: 12, fill: t.heading }}>What</text>
          <text x="150" y="48" textAnchor="middle" style={{ fontFamily: FONT_BODY, fontSize: 11, fill: t.textMuted }}>výsledky · co získáš</text>
          <text x="150" y="76" textAnchor="middle" style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.24em", fontSize: 12, fill: t.heading }}>How</text>
          <text x="150" y="91" textAnchor="middle" style={{ fontFamily: FONT_BODY, fontSize: 11, fill: t.textMuted }}>procesy · co děláš</text>
          <text x="150" y="147" textAnchor="middle" style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.24em", fontSize: 13, fill: t.accent }}>Why</text>
          <text x="150" y="163" textAnchor="middle" style={{ fontFamily: FONT_BODY, fontSize: 11, fill: t.sand }}>identita · kým jsi</text>
        </svg>
        <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textSec, textAlign: "center", maxWidth: 470, margin: "10px auto 0", lineHeight: 1.7 }}>{L("Změna jde zevnitř ven: od toho, kým jsi (proč), přes to, co děláš (jak), k tomu, co získáš (co).", "Change moves from the inside out: from who you are (why), through what you do (how), to what you get (what).")}</p>
      </div>
    </>
  );
}

function PageAreas({ go }) {
  const { t } = useT();
  const st = useStore();
  const [sel, setSel] = useState(null);
  const [full, setFull] = useState(null); // {type, id} · full-page detail
  const [adding, setAdding] = useState(false);
  if (full) {
    return (
      <>
        <button onClick={() => setFull(null)} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "0 0 16px", display: "inline-flex", alignItems: "center", gap: 6 }}>{L("‹ Zpět", "‹ Back")}</button>
        {full.type === "area"
          ? <AreaDetail name={full.id} wide openGoal={(n) => setFull({ type: "goal", id: n })} onClose={() => setFull(null)} />
          : <GoalDetail name={full.id} wide openArea={(n) => setFull({ type: "area", id: n })} onClose={() => setFull(null)} />}
      </>
    );
  }
  return (
    <>
      {go && <button onClick={() => go("kompas")} className="tm-nav-item" style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "0 8px 14px 0", display: "inline-flex", alignItems: "center", gap: 6, borderRadius: 8 }}>‹ {L("Kompas", "Compass")}</button>}
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcOblasti size={34} /></span>} pageKey="oblasti" kicker={L("Kompas", "Compass")}>{L("Oblasti", "Areas")}</PageTitle>
      <p style={pProse(t)}>{st.listAreas().length} {L("oblastí života · poslední hodnocení · splněné cíle včetně archivovaných.", "life areas · latest ratings · completed goals including archived.")}{st.editMode && <span style={{ color: t.textMuted }}>{L(" Klikni na oblast a otevři detail s měsíčním hodnocením.", " Click an area to open its detail with monthly ratings.")}</span>}</p>
      {adding ? <AddAreaForm onDone={() => setAdding(false)} /> : (
        <button onClick={() => setAdding(true)} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "9px 13px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 13.5, marginBottom: 12 }}>＋ {L("Nová oblast", "New area")}</button>
      )}
      <AreaTable onOpen={(name) => setSel({ type: "area", id: name })} />
      <Drawer open={!!sel} onClose={() => setSel(null)}>
        {sel && sel.type === "area" && <AreaDetail name={sel.id} openGoal={(n) => setSel({ type: "goal", id: n })} onClose={() => setSel(null)} onExpand={() => { setFull(sel); setSel(null); }} />}
        {sel && sel.type === "goal" && <GoalDetail name={sel.id} openArea={(n) => setSel({ type: "area", id: n })} onClose={() => setSel(null)} onExpand={() => { setFull(sel); setSel(null); }} />}
      </Drawer>
    </>
  );
}

function Select({ value, onChange, options, placeholder, style, small, ghost }) {
  const { t } = useT();
  const [open, setOpen] = useState(false);
  const wrapRef = React.useRef(null);
  React.useEffect(() => {
    if (!open) return;
    const onDoc = (e) => { if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false); };
    const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("mousedown", onDoc);
    document.addEventListener("keydown", onKey);
    return () => { document.removeEventListener("mousedown", onDoc); document.removeEventListener("keydown", onKey); };
  }, [open]);
  const opts = options.map((o) => typeof o === "string" ? { v: o, label: o } : o);
  const cur = opts.find((o) => o.v === value);
  const trigStyle = {
    display: "inline-flex", alignItems: "center", justifyContent: "space-between", gap: 8,
    background: ghost ? "transparent" : t.card, border: ghost ? "none" : `1px solid ${t.border}`, borderRadius: 8, color: t.text,
    fontFamily: FONT_BODY, cursor: "pointer", outline: "none", width: "100%",
    padding: ghost ? "4px 6px" : small ? "5px 9px" : "9px 11px", fontSize: ghost ? 12 : small ? 12.5 : 14,
    ...(style || {}),
  };
  return (
    <div ref={wrapRef} style={{ position: "relative", display: "inline-block", ...(style && style.maxWidth ? { maxWidth: style.maxWidth } : {}), width: (style && style.width) || "auto" }}>
      <button type="button" onClick={() => setOpen((x) => !x)} style={trigStyle}>
        <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", color: ghost ? t.textMuted : (cur || value) ? t.text : t.textMuted }}>{cur ? cur.label : (value || placeholder || "—")}</span>
        <span style={{ color: t.textMuted, fontSize: 10, flexShrink: 0, transform: open ? "rotate(180deg)" : "none", transition: "transform .15s" }}>▾</span>
      </button>
      {open && (
        <div style={{ animation: "tmsettle .18s ease both", position: "absolute", top: "calc(100% + 4px)", left: 0, minWidth: "100%", maxWidth: "min(320px, 86vw)", maxHeight: 280, overflowY: "auto", background: t.bg, border: `1px solid ${t.border}`, borderRadius: 8, boxShadow: "0 10px 24px rgba(0,0,0,0.18)", zIndex: 60, padding: 4 }}>
          {opts.map((o) => (
            <button key={o.v} type="button" onClick={() => { onChange(o.v); setOpen(false); }} className="tm-nav-item" style={{ display: "block", width: "100%", textAlign: "left", background: o.v === value ? t.card : "transparent", border: "none", cursor: "pointer", color: t.text, fontFamily: FONT_BODY, fontSize: small ? 12.5 : 14, padding: "7px 10px", borderRadius: 6, whiteSpace: "nowrap" }}>{o.label}</button>
          ))}
        </div>
      )}
    </div>
  );
}

