// hold ~0.4s on touch, then drag over rows carrying `attr` to reorder
function useHoldReorder(ref, id, attr, onOverRef, disabledRef) {
  const [dragging, setDragging] = useState(false);
  React.useEffect(() => {
    const el = ref.current;
    if (!el) return;
    let timer = null, sx = 0, sy = 0, active = false;
    const onStart = (e) => {
      if (disabledRef && disabledRef.current) return;
      if (e.target && e.target.closest && e.target.closest("textarea, input, button, a, select")) return;
      const p = e.touches[0]; sx = p.clientX; sy = p.clientY;
      timer = setTimeout(() => { active = true; setDragging(true); try { navigator.vibrate && navigator.vibrate(12); } catch (err) {} }, 400);
    };
    const onMove = (e) => {
      const p = e.touches[0];
      if (!active) { if (Math.abs(p.clientX - sx) > 12 || Math.abs(p.clientY - sy) > 12) clearTimeout(timer); return; }
      e.preventDefault();
      const hit = document.elementFromPoint(p.clientX, p.clientY);
      const row = hit && hit.closest && hit.closest(`[${attr}]`);
      const overId = row && row.getAttribute(attr);
      if (overId && overId !== id && onOverRef.current) onOverRef.current(overId);
    };
    const onEnd = () => { clearTimeout(timer); if (active) { active = false; setDragging(false); } };
    el.addEventListener("touchstart", onStart, { passive: true });
    el.addEventListener("touchmove", onMove, { passive: false });
    el.addEventListener("touchend", onEnd);
    el.addEventListener("touchcancel", onEnd);
    return () => { el.removeEventListener("touchstart", onStart); el.removeEventListener("touchmove", onMove); el.removeEventListener("touchend", onEnd); el.removeEventListener("touchcancel", onEnd); };
  }, [id]);
  return dragging;
}

function AudioRow({ a, onRemove }) {
  const { t } = useT();
  const [src, setSrc] = useState(a.r2 ? r2Url(a.id) : (a.idb ? null : a.data));
  React.useEffect(() => {
    if (a.r2) { setSrc(r2Url(a.id)); return; }
    if (!a.idb) { setSrc(a.data); return; }
    let url = null, dead = false;
    idbGet(a.id).then((b) => { if (!dead && b) { url = URL.createObjectURL(b); setSrc(url); } }).catch(() => {});
    return () => { dead = true; if (url) URL.revokeObjectURL(url); };
  }, [a.id]);
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 8 }}>
      {src
        ? <audio controls src={src} style={{ height: 34, maxWidth: "100%", flex: 1 }} />
        : <span style={{ flex: 1, fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted, fontStyle: "italic" }}>{L("Načítám audio…", "Loading audio…")}</span>}
      <span style={{ fontFamily: FONT_BODY, fontSize: 11, color: t.textMuted, flexShrink: 0 }}>{a.name} · {fmtSize(a.size)}</span>
      {onRemove && <button title="Odebrat" onClick={() => { if (a.idb) idbDel(a.id); if (a.r2) r2Del(a.id); onRemove(a.id); }} style={{ background: "transparent", border: "none", color: t.textMuted, cursor: "pointer", fontSize: 12, padding: 0 }}>✕</button>}
    </div>
  );
}

function AttachmentStrip({ att, onRemove }) {
  const { t } = useT();
  const [zoom, setZoom] = useState(null); // id of zoomed image
  if (!att || !att.length) return null;
  const imgs = att.filter((a) => (a.type || "").startsWith("image/"));
  const files = att.filter((a) => !(a.type || "").startsWith("image/"));
  return (
    <div style={{ marginTop: 10 }}>
      {imgs.length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
          {imgs.map((a) => (
            <div key={a.id} style={{ position: "relative" }}>
              <img
                src={attUrl(a)} alt={a.name} title={a.name}
                onClick={() => setZoom(zoom === a.id ? null : a.id)}
                style={{ display: "block", borderRadius: 8, border: `1px solid ${t.borderSoft}`, cursor: "zoom-in", ...(zoom === a.id ? { maxWidth: "100%", height: "auto" } : { height: 96, width: "auto", maxWidth: 200, objectFit: "cover" }) }}
              />
              {onRemove && (
                <button title={L("Odebrat přílohu", "Remove attachment")} onClick={() => { if (a.r2) r2Del(a.id); onRemove(a.id); }} style={{ ...iconBtn(t), position: "absolute", top: 4, right: 4, background: t.bg }}>✕</button>
              )}
            </div>
          ))}
        </div>
      )}
      {files.filter((a) => (a.type || "").startsWith("audio/")).map((a) => (
        <AudioRow key={a.id} a={a} onRemove={onRemove} />
      ))}
      {files.filter((a) => !(a.type || "").startsWith("audio/")).length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: imgs.length ? 8 : 0 }}>
          {files.filter((a) => !(a.type || "").startsWith("audio/")).map((a) => (
            <span key={a.id} style={{ display: "inline-flex", alignItems: "center", gap: 6, border: `1px solid ${t.border}`, borderRadius: 20, padding: "4px 12px", background: t.card }}>
              <a href={attUrl(a)} download={a.name} style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.sand, textDecoration: "none" }}>📎 {a.name}</a>
              <span style={{ fontFamily: FONT_BODY, fontSize: 11, color: t.textMuted }}>{fmtSize(a.size)}</span>
              {onRemove && <button title="Odebrat" onClick={() => { if (a.r2) r2Del(a.id); onRemove(a.id); }} style={{ background: "transparent", border: "none", color: t.textMuted, cursor: "pointer", fontSize: 12, padding: 0 }}>✕</button>}
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

function EntryForm({ tags, initial, onSave, onCancel }) {
  const { t } = useT();
  const [title, setTitle] = useState((initial && initial.title) || "");
  const [selTags, setSelTags] = useState(initial && initial.tags && initial.tags.length ? initial.tags : (initial && initial.tag ? [initial.tag] : (tags[0] ? [tags[0][0]] : [])));
  const [text, setText] = useState((initial && initial.text) || "");
  const [att, setAtt] = useState((initial && initial.att) || []);
  const [busy, setBusy] = useState(false);
  const fileRef = React.useRef(null);
  const st = useStore();
  const addFiles = async (fileList) => {
    if (!fileList || !fileList.length) return;
    setBusy(true);
    const ok = await filesToAtts(fileList, st.ask);
    setAtt((a) => [...a, ...ok]);
    setBusy(false);
    if (fileRef.current) fileRef.current.value = "";
  };
  return (
    <div style={{ background: t.callout, border: `1px solid ${t.border}`, borderRadius: 10, padding: 14, margin: "10px 0" , boxShadow: t.shadow }}>
      <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder={L("Název…", "Title…")} style={{ ...fieldStyle(t), fontFamily: FONT_DISPLAY, fontSize: 18, marginBottom: 8 }} />
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
        {tags.map(([label, color]) => (
          <button key={label} onClick={() => setSelTags((cur) => cur.includes(label) ? cur.filter((x) => x !== label) : [...cur, label])} style={{ border: "none", cursor: "pointer", background: "transparent", padding: 0, opacity: selTags.includes(label) ? 1 : 0.4 }}><Tag label={label} color={color} /></button>
        ))}
      </div>
      <div style={{ ...fieldStyle(t), minHeight: 96, cursor: "text", padding: "9px 12px" }}>
        <RichArea value={text} onChange={setText} placeholder="Text…" />
      </div>
      <input ref={fileRef} type="file" multiple onChange={(e) => addFiles(e.target.files)} style={{ display: "none" }} />
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: att.length ? 0 : 10 }}>
        <button onClick={() => fileRef.current && fileRef.current.click()} disabled={busy} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 13, display: "inline-flex", alignItems: "center", gap: 7 }}>
          <ClipIcon size={13} />{busy ? L("Načítám…", "Loading…") : L("Přiložit soubor / obrázek", "Attach file / image")}
        </button>
        {att.length > 0 && <span style={{ fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted }}>{att.length} {L("příloh", "attachments")} · {fmtSize(att.reduce((s, a) => s + (a.size || 0), 0))}</span>}
      </div>
      <AttachmentStrip att={att} onRemove={(id) => setAtt((a) => a.filter((x) => x.id !== id))} />
      <div style={{ display: "flex", gap: 8, marginTop: att.length ? 10 : 0 }}>
        <button onClick={() => { if (title.trim() || text.trim() || att.length) onSave({ title: title.trim() || L("(bez názvu)", "(untitled)"), tag: selTags[0] || "", tags: selTags, text: text.trim(), att }); }} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14, fontWeight: 500 }}>{L("Uložit", "Save")}</button>
        <button onClick={onCancel} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14 }}>{L("Zrušit", "Cancel")}</button>
      </div>
    </div>
  );
}

function AddEntry({ kind, tags, label }) {
  const { t } = useT();
  const st = useStore();
  const [open, setOpen] = useState(false);
  if (open) return <EntryForm tags={tags} onSave={(e) => { st.addEntry(kind, { id: uid(), date: todayISO(), ...e }); setOpen(false); }} onCancel={() => setOpen(false)} />;
  return <button onClick={() => setOpen(true)} className="tm-dash" style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "11px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 14, width: "100%", textAlign: "left" }}>＋ {label}</button>;
}


function GoalCard({ g, onOpen }) {
  const { t, tags } = useT();
  const st = useStore();
  const today = todayISO();
  const overdue = g.target && g.target < today && g.status !== "Completed";
  const inToday = st.getDay(today).tasks.some((task) => task.text === g.name);
  const fmtT = (iso) => { if (!iso) return null; const [y, m, d] = iso.split("-"); return (+d) + ". " + (+m) + ". " + y; };
  return (
    <div onClick={() => onOpen && onOpen(g.name)} style={{ background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "12px 14px", marginBottom: 10, cursor: "pointer" , boxShadow: t.shadow }} className="tm-nav-item tm-lift">
      <div style={{ display: "flex", gap: 8, alignItems: "flex-start", marginBottom: 8 }}>
        <span style={{ color: t.textMuted, fontSize: 14, lineHeight: "20px" }}>◎</span>
        <span style={{ fontFamily: FONT_BODY, fontSize: 14.5, fontWeight: 500, color: g.status === "Completed" ? t.textMuted : t.heading, textDecoration: g.status === "Completed" ? "line-through" : "none", lineHeight: 1.4 }}>{g.name}</span>
      </div>
      {g.area && (
        <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 6 }}>
          <span style={{ fontSize: 13 }}>{st.areaIcon(g.area)}</span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textSec, borderBottom: `1px solid ${t.border}` }}>{g.area}</span>
        </div>
      )}
      {g.target && <div style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: overdue ? tags.red.fg : t.textMuted, marginBottom: 7 }}>{fmtT(g.target)}</div>}
      <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
        {g.prio && <Tag label={PL(g.prio)} color={PRIO_COLOR[g.prio] || "default"} />}
        {g.status !== "Completed" && (
          inToday
            ? <span style={{ fontFamily: FONT_BODY, fontSize: 11, color: t.sage, marginLeft: "auto" }}>{L("✓ dnes", "✓ today")}</span>
            : <button onClick={(e) => { e.stopPropagation(); st.pushGoalToDay(g.name); }} title={L("Přidat do dnešních cílů", "Add to today's goals")} style={{ marginLeft: "auto", background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 12, padding: "1px 9px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 11 }}>{L("→ dnes", "→ today")}</button>
        )}
      </div>
    </div>
  );
}

// ---- Side drawer (Notion-like peek panel) ----
// Rendered through a portal to <body>: no animated/transformed ancestor can
// trap its position:fixed. Desktop slides in from the right; on mobile
// (≤820px, via CSS) it becomes a bottom sheet with a grab handle — drag the
// handle down past ~90px to close, otherwise it snaps back.
function Drawer({ open, onClose, children }) {
  const { t } = useT();
  const [dragY, setDragY] = React.useState(0);
  const [snapping, setSnapping] = React.useState(false);
  const [touched, setTouched] = React.useState(false); // once true, the entry animation yields to the finger
  const startRef = React.useRef(null);
  React.useEffect(() => { if (!open) { setDragY(0); setSnapping(false); setTouched(false); } }, [open]);
  if (!open) return null;
  const onGripStart = (e) => { startRef.current = e.touches[0].clientY; setTouched(true); setSnapping(false); };
  const onGripMove = (e) => {
    if (startRef.current == null) return;
    const dy = e.touches[0].clientY - startRef.current;
    setDragY(dy > 0 ? dy : 0);
  };
  const onGripEnd = () => {
    if (startRef.current == null) return;
    startRef.current = null;
    if (dragY > 90) { setDragY(0); onClose(); }
    else { setSnapping(true); setDragY(0); }
  };
  return createPortal(
    <>
      <div onClick={onClose} className="tm-dim" style={{ position: "fixed", inset: 0, background: "rgba(20,18,15,0.45)", backdropFilter: "blur(2.5px)", WebkitBackdropFilter: "blur(2.5px)", zIndex: 180, animation: "tmDim .28s ease both" }} />
      <div
        className="tm-drawer"
        style={{
          position: "fixed", zIndex: 190, background: t.bg, overflowY: "auto", WebkitOverflowScrolling: "touch",
          animation: touched ? "none" : undefined,
          transform: dragY ? `translateY(${dragY}px)` : undefined,
          transition: snapping ? "transform .26s cubic-bezier(.23,.62,.22,.99)" : undefined,
        }}
      >
        <div className="tm-drawer-grip" onTouchStart={onGripStart} onTouchMove={onGripMove} onTouchEnd={onGripEnd} onTouchCancel={onGripEnd}>
          <span />
        </div>
        <div style={{ padding: "22px 26px calc(40px + env(safe-area-inset-bottom))" }}>
          <button onClick={onClose} title={L("Zavřít", "Close")} style={{ background: "transparent", border: "none", color: t.textMuted, cursor: "pointer", fontSize: 16, padding: 4, float: "right" }}>✕</button>
          <div style={{ clear: "none" }}>{children}</div>
        </div>
      </div>
    </>,
    document.body
  );
}

function PropRow({ icon, label, children }) {
  const { t } = useT();
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "7px 0", minHeight: 34 }}>
      <span style={{ width: 150, display: "flex", alignItems: "center", gap: 9, color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, flexShrink: 0 }}>
        <span style={{ fontSize: 13, width: 16, textAlign: "center" }}>{icon}</span>{label}
      </span>
      <span style={{ flex: 1, minWidth: 0 }}>{children}</span>
    </div>
  );
}

// shared notes + attachments block for goals and areas · mirrors ContentDetail
function MetaSection({ meta, onPatch, placeholder = L("Piš…", "Write…") }) {
  const { t } = useT();
  const st = useStore();
  const fileRef = React.useRef(null);
  const attach = async (fl) => {
    const added = await filesToAtts(fl, st.ask);
    if (added.length) onPatch({ att: [...(meta.att || []), ...added] });
    if (fileRef.current) fileRef.current.value = "";
  };
  return (
    <div style={{ borderTop: `1px solid ${t.borderSoft}`, marginTop: 16, paddingTop: 12 }}>
      <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 6 }}>{L("Zápisky", "Notes")}</div>
      <RichArea value={meta.text || ""} onChange={(v) => onPatch({ text: v })} placeholder={placeholder} />
      <div style={{ marginTop: 10 }}>
        <input ref={fileRef} type="file" multiple onChange={(e) => attach(e.target.files)} style={{ display: "none" }} />
        <button onClick={() => fileRef.current && fileRef.current.click()} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5 }}>＋ {L("Přiložit soubor", "Attach file")}</button>
        <AttachmentStrip att={meta.att} onRemove={st.editMode ? ((id) => onPatch({ att: (meta.att || []).filter((x) => x.id !== id) })) : undefined} />
      </div>
    </div>
  );
}

function GoalDetail({ name, openArea, onClose, onExpand, wide }) {
  const { t } = useT();
  const st = useStore();
  const g = st.allGoals().find((x) => x.name === name);
  const [note, setNote] = useState("");
  if (!g) return null;
  const cycle = (list, cur, apply) => apply(list[(list.indexOf(cur) + 1) % list.length]);
  const pill = (label, color, onClick, title) => (
    <button onClick={onClick} title={title || L("Klikni a přepínej", "Click to cycle")} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0 }}><Tag label={label} color={color} /></button>
  );
  const notes = st.goalNotes(g.name);
  const addNote = () => { const v = note.trim(); if (!v) return; st.addGoalNote(g.name, v); setNote(""); };
  const today = todayISO();
  const inToday = st.getDay(today).tasks.some((task) => task.text === g.name);
  return (
    <div>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 10, marginBottom: 10 }}>
        <div style={{ fontSize: 30, color: t.textMuted }}>◎</div>
        {onExpand && <button title={L("Otevřít jako stránku", "Open as page")} onClick={onExpand} style={{ ...iconBtn(t), border: "none", color: t.textMuted, fontSize: 14 }}>⤢</button>}
      </div>
      <h2 style={{ fontFamily: FONT_DISPLAY, fontSize: wide ? 34 : 30, fontWeight: 500, color: t.heading, margin: "0 0 18px", lineHeight: 1.2, maxWidth: wide ? 720 : "none" }}>{g.name}</h2>
      <PropRow icon="◍" label="Achievability">
        {pill(g.ach ? ACH_SHORT[g.ach] || g.ach : "—", "default", () => cycle(ACHIEVES, g.ach, (v) => st.editGoal(g.name, { ach: v })))}
      </PropRow>
      <PropRow icon="◌" label="Status">
        {pill(GS(g.status), GSTATUS_COLOR[g.status] || "default", () => cycle(GOAL_STATUSES, g.status, (v) => st.editGoal(g.name, { status: v })))}
      </PropRow>
      <PropRow icon="⊙" label="Priority">
        {pill(g.prio || "—", PRIO_COLOR[g.prio] || "default", () => cycle(PRIOS, g.prio, (v) => st.editGoal(g.name, { prio: v })))}
      </PropRow>
      <PropRow icon="⌖" label="Goals">
        {g.area ? (
          <button onClick={() => openArea && openArea(g.area)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0, display: "inline-flex", alignItems: "center", gap: 7 }}>
            <span style={{ fontSize: 14 }}>{st.areaIcon(g.area)}</span>
            <span style={{ fontFamily: FONT_BODY, fontSize: 14, fontWeight: 500, color: t.text, borderBottom: `1px solid ${t.textMuted}` }}>{g.area}</span>
          </button>
        ) : <span style={{ color: t.textMuted }}>—</span>}
      </PropRow>
      <PropRow icon="▦" label="Target Date">
        <input type="date" value={g.target || ""} onChange={(e) => st.editGoal(g.name, { target: e.target.value })} style={{ background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 14, outline: "none", colorScheme: t.mode === "light" ? "light" : "dark" }} />
      </PropRow>
      <PropRow icon="▤" label={L("Archiv", "Archive")}>
        <button onClick={() => st.editGoal(g.name, { archive: !g.archive })} title={L("Archivovat / vrátit", "Archive / restore")} style={{ width: 18, height: 18, borderRadius: 4, border: `1.5px solid ${g.archive ? t.accent : t.border}`, background: g.archive ? t.accent : "transparent", cursor: "pointer", color: t.bg, fontSize: 11, lineHeight: 1, padding: 0 }}>{g.archive ? "✓" : ""}</button>
      </PropRow>
      <div style={{ padding: "10px 0 4px" }}>
        {g.status !== "Completed" && !inToday && (
          <button onClick={() => st.pushGoalToDay(g.name)} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 14, padding: "4px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("→ poslat do dnešních cílů", "→ send to today's goals")}</button>
        )}
        {inToday && <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.sage }}>✓ {L("v dnešním plánu", "in today's plan")}</span>}
        {st.editMode && (
        <button
          onClick={() => st.ask(L(`Přesunout „${g.name}" do koše?`, `Move "${g.name}" to trash?`), () => { if (g.user) st.removeUserGoal(g.id); else st.trashBuiltinGoal(g.name); onClose && onClose(); })}
          style={{ marginLeft: 12, background: "transparent", border: `1px solid ${t.border}`, borderRadius: 14, padding: "4px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}
        >{L("Do koše", "To trash")}</button>
        )}
      </div>
      <MetaSection meta={st.goalMetaOf(g.name)} onPatch={(p) => st.setGoalMeta(g.name, p)} placeholder={L("Piš k tomuto cíli…", "Write about this goal…")} />
      <div style={{ borderTop: `1px solid ${t.borderSoft}`, marginTop: 14, paddingTop: 14 }}>
        <div style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textMuted, marginBottom: 8 }}>Comments</div>
        {notes.map((n) => (
          <div key={n.id} style={{ display: "flex", gap: 10, alignItems: "flex-start", marginBottom: 10 }}>
            <span style={{ width: 26, height: 26, borderRadius: "50%", background: t.card, border: `1px solid ${t.border}`, display: "inline-flex", alignItems: "center", justifyContent: "center", fontSize: 12, flexShrink: 0 }}>🐉</span>
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted }}>{fmtCZ(n.date)}</div>
              <div style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.text, lineHeight: 1.6, whiteSpace: "pre-wrap" }}>{n.text}</div>
            </div>
            <button onClick={() => st.ask(L("Smazat komentář?", "Delete comment?"), () => st.removeGoalNote(g.name, n.id))} title={L("Smazat", "Delete")} style={{ background: "transparent", border: "none", color: t.textMuted, cursor: "pointer", fontSize: 12 }}>✕</button>
          </div>
        ))}
        <div style={{ display: "flex", gap: 10, alignItems: "center", marginTop: 6 }}>
          <span style={{ width: 26, height: 26, borderRadius: "50%", background: t.card, border: `1px solid ${t.border}`, display: "inline-flex", alignItems: "center", justifyContent: "center", fontSize: 12, flexShrink: 0 }}>🐉</span>
          <input value={note} onChange={(e) => setNote(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") addNote(); }} placeholder="Add a comment…" style={{ flex: 1, background: "transparent", border: "none", borderBottom: `1px solid ${t.borderSoft}`, color: t.text, fontFamily: FONT_BODY, fontSize: 14, padding: "4px 2px 7px", outline: "none" }} />
        </div>
      </div>
    </div>
  );
}

function AreaDetail({ name, openGoal, onClose, onExpand, wide }) {
  const { t, tags } = useT();
  const st = useStore();
  const a = st.listAreas().find((x) => x.name === name);
  if (!a) return null;
  const months = st.monthsOf(a);
  const gs = st.allGoals().filter((g) => g.area === name || (g.areas || []).includes(name));
  const done = gs.filter((g) => g.status === "Completed").length;
  const em = st.editMode;
  return (
    <div>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 10, marginBottom: 10 }}>
        <div style={{ fontSize: 34 }}>{a.icon}</div>
        {onExpand && <button title={L("Otevřít jako stránku", "Open as page")} onClick={onExpand} style={{ ...iconBtn(t), border: "none", color: t.textMuted, fontSize: 14 }}>⤢</button>}
      </div>
      <h2 style={{ fontFamily: FONT_DISPLAY, fontSize: 28, fontWeight: 500, color: t.heading, margin: "0 0 16px", lineHeight: 1.2 }}>{a.name}</h2>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
        <span style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage }}>Goals progress</span>
        <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textSec }}>{done} / {gs.length}</span>
      </div>
      <ProgressBar value={gs.length ? done / gs.length : 0} />
      <div style={{ height: 18 }} />
      <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 8 }}>{L("Hodnocení po měsících", "Ratings by month")}</div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: 6, marginBottom: 18 }}>
        {ROM.map((r) => (
          <div key={r} style={{ textAlign: "center", border: `1px solid ${months[r] != null ? t.border : t.borderSoft}`, borderRadius: 8, padding: "6px 2px", background: months[r] != null ? t.card : "transparent" }}>
            <div style={{ fontFamily: FONT_TAG, fontSize: 10, letterSpacing: "0.08em", color: t.textMuted }}>{r}</div>
            {em ? (
              <input type="number" min="0" max="10" value={months[r] != null ? months[r] : ""} placeholder="—"
                onChange={(e) => st.setAreaMonth(a.name, r, e.target.value === "" ? null : Math.max(0, Math.min(10, +e.target.value)))}
                style={{ width: "100%", background: "transparent", border: "none", textAlign: "center", color: t.heading, fontFamily: FONT_DISPLAY, fontSize: 16, outline: "none" }} />
            ) : (
              <div style={{ fontFamily: FONT_DISPLAY, fontSize: 17, color: months[r] != null ? t.sand : t.borderSoft }}>{months[r] != null ? months[r] : "·"}</div>
            )}
          </div>
        ))}
      </div>
      <MetaSection meta={st.areaMetaOf(a.name)} onPatch={(p) => st.setAreaMeta(a.name, p)} placeholder={L("Piš k této oblasti…", "Write about this area…")} />
      <div style={{ height: 14 }} />
      <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 6 }}>{L("Cíle", "Goals")} · {gs.length}</div>
      {gs.length === 0 && <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>{L("Zatím žádné cíle v této oblasti.", "No goals in this area yet.")}</div>}
      {gs.map((g) => (
        <button key={g.name} onClick={() => openGoal && openGoal(g.name)} style={{ display: "flex", width: "100%", alignItems: "center", gap: 9, padding: "8px 4px", background: "transparent", border: "none", borderBottom: `1px solid ${t.borderSoft}`, cursor: "pointer", textAlign: "left" }}>
        <span style={{ color: t.textMuted, fontSize: 12 }}>◎</span>
          <span style={{ flex: 1, fontFamily: FONT_BODY, fontSize: 13.5, color: g.status === "Completed" ? t.textMuted : t.text, textDecoration: g.status === "Completed" ? "line-through" : "none" }}>{g.name}</span>
          <Tag label={GS(g.status)} color={GSTATUS_COLOR[g.status] || "default"} />
        </button>
      ))}
      <div style={{ marginTop: 18, paddingTop: 14, borderTop: `1px solid ${t.borderSoft}` }}>
        {st.editMode && (
        <button
          onClick={() => { const msg = gs.length ? L(`Přesunout „${a.name}" do koše? ${gs.length} cílů v této oblasti tam zůstane, jen ztratí přiřazení.`, `Move "${a.name}" to trash? ${gs.length} goals in this area will stay, they just lose the assignment.`) : L(`Přesunout „${a.name}" do koše?`, `Move "${a.name}" to trash?`); st.ask(msg, () => { st.removeArea(a.name); onClose && onClose(); }); }}
          style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 14, padding: "4px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}
        >🗑 {L("Přesunout oblast do koše", "Move area to trash")}</button>
        )}
      </div>
    </div>
  );
}

function AddGoalForm() {
  const { t } = useT();
  const st = useStore();
  const areas = st.listAreas();
  const [open, setOpen] = useState(false);
  const [name, setName] = useState("");
  const [area, setArea] = useState(areas[0] ? areas[0].name : "");
  const [prio, setPrio] = useState("Normal");
  const [target, setTarget] = useState("");
  if (!open) return <button onClick={() => setOpen(true)} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "10px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 14, width: "100%", textAlign: "left", marginBottom: 12 }}>＋ {L("Nový cíl", "New goal")}</button>;
  return (
    <div style={{ background: t.callout, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12, marginBottom: 12 , boxShadow: t.shadow }}>
      <input autoFocus value={name} onChange={(e) => setName(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter" && name.trim()) { st.addGoal({ id: uid(), name: name.trim(), area, areas: [area], status: "Not started", prio, ach: "", target }); setName(""); setTarget(""); setOpen(false); } }} placeholder={L("Název cíle…", "Goal name…")} style={{ ...fieldStyle(t), marginBottom: 8 }} />
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 10 }}>
        <Select value={area} onChange={setArea} style={{ maxWidth: 220, width: 220 }} options={areas.map((a) => ({ v: a.name, label: `${a.icon} ${a.name}` }))} />
        <Select value={prio} onChange={setPrio} style={{ maxWidth: 130, width: 130 }} options={PRIOS.map((x) => ({ v: x, label: PL(x) }))} />
        <input type="date" value={target} onChange={(e) => setTarget(e.target.value)} style={{ ...fieldStyle(t), maxWidth: 170, colorScheme: t.mode === "light" ? "light" : "dark" }} />
      </div>
      <div style={{ display: "flex", gap: 8 }}>
        <button onClick={() => { if (!name.trim()) return; st.addGoal({ id: uid(), name: name.trim(), area, areas: [area], status: "Not started", prio, ach: "", target }); setName(""); setTarget(""); setOpen(false); }} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14, fontWeight: 500 }}>{L("Uložit", "Save")}</button>
        <button onClick={() => setOpen(false)} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14 }}>{L("Zrušit", "Cancel")}</button>
      </div>
    </div>
  );
}

function Board({ groups, onOpen, onMove }) {
  const { t, tags } = useT();
  const [overCol, setOverCol] = useState(null);
  const dnd = !!onMove;
  const getName = (e) => { const d = (e.dataTransfer.getData("text/plain") || "").split(":"); return d[0] === "goal" ? d.slice(1).join(":") : null; };
  return (
    <div style={{ display: "flex", gap: 12, overflowX: "auto", paddingBottom: 8, WebkitOverflowScrolling: "touch" }}>
      {groups.map(([title, color, items, dropVal]) => {
        const c = (tags[color] || tags.default).fg;
        const colOver = overCol === title;
        return (
          <div
            key={title}
            onDragOver={dnd ? (e) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; setOverCol(title); } : undefined}
            onDragLeave={dnd ? () => setOverCol((x) => (x === title ? null : x)) : undefined}
            onDrop={dnd ? (e) => {
              e.preventDefault(); setOverCol(null);
              const n = getName(e); if (!n) return;
              onMove(n, dropVal, null); // column body -> end of column
            } : undefined}
            style={{ minWidth: 240, maxWidth: 285, flex: "1 0 240px", display: "flex", flexDirection: "column", maxHeight: "min(560px, 64vh)", background: hexA(c, colOver ? 0.12 : 0.055), border: `1px solid ${hexA(c, colOver ? 0.4 : 0.14)}`, borderRadius: 10, padding: "10px 6px 4px 10px", transition: "background .15s ease, border-color .15s ease" }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, paddingLeft: 2, flexShrink: 0 }}>
              <Tag label={title} color={color} />
              <span style={{ fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted }}>{items.length}</span>
            </div>
            <div style={{ overflowY: "auto", flex: 1, minHeight: 0, paddingRight: 4 }}>
              {items.map((g) => (
                <div
                  key={g.name}
                  draggable={dnd}
                  onDragStart={dnd ? (e) => { e.dataTransfer.setData("text/plain", "goal:" + g.name); e.dataTransfer.effectAllowed = "move"; } : undefined}
                  onDragOver={dnd ? (e) => { e.preventDefault(); e.stopPropagation(); setOverCol(title); } : undefined}
                  onDrop={dnd ? (e) => {
                    e.preventDefault(); e.stopPropagation(); setOverCol(null);
                    const n = getName(e); if (!n || n === g.name) return;
                    onMove(n, dropVal, g.name); // relative to this card, direction-aware
                  } : undefined}
                  style={dnd ? { cursor: "grab" } : undefined}
                >
                  <GoalCard g={g} onOpen={onOpen} />
                </div>
              ))}
              {items.length === 0 && <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 12.5, color: t.textMuted, padding: "2px 4px 8px" }}>"—"</div>}
            </div>
          </div>
        );
      })}
    </div>
  );
}

const G_VIEWS = ["Status", "Area", "Priority", "Completed", "Archiv"];

function GoalWorkspace({ withAreas }) {
  const { t } = useT();
  const st = useStore();
  const [view, setView] = useState("Status");
  const [fArea, setFArea] = useState("Vše");
  const [fPrio, setFPrio] = useState("Vše");
  const [sortBy, setSortBy] = useState("prio");
  const [sel, setSel] = useState(null); // {type:'goal'|'area', id}
  const [full, setFull] = useState(null); // {type, id} · full-page detail
  const [addingArea, setAddingArea] = useState(false);

  const openGoal = (name) => setSel({ type: "goal", id: name });
  const applyMove = (patchOf) => (n, v, over) => { st.dragGoal(n, over, patchOf(v)); if (sortBy !== "manual") setSortBy("manual"); };
  const openArea = (name) => setSel({ type: "area", id: name });

  const all = st.allGoals();
  const areaNames = st.listAreas().map((a) => a.name);
  const sorters = {
    prio: (a, b) => (PRIO_ORDER[a.prio] ?? 9) - (PRIO_ORDER[b.prio] ?? 9) || (a.target || "9999").localeCompare(b.target || "9999"),
    dateAsc: (a, b) => (a.target || "9999").localeCompare(b.target || "9999"),
    dateDesc: (a, b) => (b.target || "0000").localeCompare(a.target || "0000"),
    name: (a, b) => a.name.localeCompare(b.name, "cs"),
  };
  let rows = st.orderGoals(all.filter((g) => {
    if (fArea !== "Vše" && g.area !== fArea && !(g.areas || []).includes(fArea)) return false;
    if (fPrio !== "Vše" && g.prio !== fPrio) return false;
    return true;
  }));
  if (sortBy !== "manual") rows = [...rows].sort(sorters[sortBy] || sorters.prio);
  const nonArch = rows.filter((g) => !g.archive);
  const archived = rows.filter((g) => g.archive);
  const completed = nonArch.filter((g) => g.status === "Completed");

  const selStyle = { ...fieldStyle(t), width: "auto", maxWidth: 168, padding: "5px 8px", fontSize: 12.5 };
  const grid = { display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(250px, 1fr))", gap: 10 };

  if (full) {
    return (
      <>
        <button onClick={() => setFull(null)} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "0 0 16px", display: "inline-flex", alignItems: "center", gap: 6 }}>{L("‹ Zpět", "‹ Back")}</button>
        {full.type === "area"
          ? <AreaDetail name={full.id} wide openGoal={(n) => setFull({ type: "goal", id: n })} onClose={() => setFull(null)} />
          : <GoalDetail name={full.id} wide openArea={(n) => setFull({ type: "area", id: n })} onClose={() => setFull(null)} />}
      </>
    );
  }
  return (
    <>
      {withAreas && (
        <div style={{ marginBottom: 14 }}>
          {addingArea && <AddAreaForm onDone={() => setAddingArea(false)} />}
          <AreaChips onOpen={openArea} onAdd={() => setAddingArea(true)} />
        </div>
      )}
      <div style={{ display: "flex", gap: 2, flexWrap: "wrap", alignItems: "center", borderBottom: `1px solid ${t.border}` }}>
        {G_VIEWS.map((v) => (
          <button key={v} onClick={() => setView(v)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: "8px 11px 9px", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 12, color: view === v ? t.accent : t.textMuted, borderBottom: view === v ? `2px solid ${t.accent}` : "2px solid transparent", marginBottom: -1 }}>{LV(v)}</button>
        ))}
        <span style={{ flex: 1 }} />
      </div>
      <div style={{ display: "flex", gap: 8, alignItems: "center", margin: "12px 0" }}>
        <Select small value={fArea} onChange={setFArea} style={{ flex: "1 1 0", minWidth: 0, maxWidth: 180 }} options={[{ v: "Vše", label: L("Vše", "All") }, ...areaNames]} />
        <Select small value={fPrio} onChange={setFPrio} style={{ flex: "1 1 0", minWidth: 0, maxWidth: 140 }} options={[{ v: "Vše", label: L("Vše", "All") }, ...PRIOS.map((x) => ({ v: x, label: PL(x) }))]} />
        <Select small value={sortBy} onChange={setSortBy} style={{ flex: "1 1 0", minWidth: 0, maxWidth: 150 }} options={[{ v: "manual", label: L("vlastní pořadí", "custom order") }, { v: "prio", label: L("priorita", "priority") }, { v: "dateAsc", label: L("datum ↑", "date ↑") }, { v: "dateDesc", label: L("datum ↓", "date ↓") }, { v: "name", label: "A–Z" }]} />
      </div>

      <AddGoalForm />

      {view === "Status" && (
        <Board onOpen={openGoal} onMove={applyMove((v) => ({ status: v }))} groups={GOAL_STATUSES.map((sx) => [GS(sx), GSTATUS_COLOR[sx], nonArch.filter((g) => g.status === sx), sx])} />
      )}
      {view === "Area" && (
        <Board onOpen={openGoal} onMove={applyMove((v) => ({ area: v, areas: v ? [v] : [] }))} groups={[...areaNames, ""].map((n) => [n || "Bez oblasti", n ? (AREA_COLOR[n] || "default") : "default", nonArch.filter((g) => (g.area || "") === n), n]).filter(([, , items]) => items.length > 0)} />
      )}
      {view === "Priority" && (
        <Board onOpen={openGoal} onMove={applyMove((v) => ({ prio: v }))} groups={PRIOS.map((p) => [PL(p), PRIO_COLOR[p], nonArch.filter((g) => g.prio === p), p])} />
      )}
      {view === "Completed" && (completed.length ? <div style={grid}>{completed.map((g) => <GoalCard key={g.name} g={g} onOpen={openGoal} />)}</div> : <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>{L("Zatím nic dokončeného v tomto filtru.", "Nothing completed in this filter yet.")}</p>)}
      {view === "Archiv" && (archived.length ? <div style={grid}>{archived.map((g) => <GoalCard key={g.name} g={g} onOpen={openGoal} />)}</div> : <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>{L("Archiv je prázdný.", "The archive is empty.")}</p>)}

      <Drawer open={!!sel} onClose={() => setSel(null)}>
        {sel && sel.type === "goal" && <GoalDetail name={sel.id} openArea={openArea} onClose={() => setSel(null)} onExpand={() => { setFull(sel); setSel(null); }} />}
        {sel && sel.type === "area" && <AreaDetail name={sel.id} openGoal={openGoal} onClose={() => setSel(null)} onExpand={() => { setFull(sel); setSel(null); }} />}
      </Drawer>
    </>
  );
}

// ---- Notion-style page cover + animated icon ----
function PageCover({ cover, icon }) {
  const { t } = useT();
  return (
    <div style={{ margin: "-48px -36px 0", position: "relative" }}>
      <div style={{ height: 200, overflow: "hidden", position: "relative" }}>
        <img src={imgSrc(cover)} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
        <div style={{ position: "absolute", inset: 0, background: `linear-gradient(180deg, transparent 55%, ${hexA(t.mode === "light" ? "#F4F0EB" : "#1C1C1A", 0.55)} 100%)` }} />
      </div>
      {icon && (
        <div style={{ padding: "0 36px" }}>
          <div style={{ width: 84, height: 84, borderRadius: 14, overflow: "hidden", border: `3px solid ${t.bg}`, boxShadow: "0 6px 18px rgba(0,0,0,0.28)", marginTop: -42, position: "relative", background: t.bg }}>
            <img src={imgSrc(icon)} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
          </div>
        </div>
      )}
    </div>
  );
}

// ---- Pomodoro ----
// Pomodoro · kategorie soustředění. Univerzální pětice: Práce, Studium,
// Tvorba (umění i řemeslo), Meditace, Ostatní — pokrývá pracovní den,
// učení, tvorbu i praxi, a Ostatní chytá zbytek bez přemýšlení.
const POMO_CATS = [
  { k: "prace", cz: "Práce", en: "Work" },
  { k: "studium", cz: "Studium", en: "Study" },
  { k: "tvorba", cz: "Tvorba", en: "Creation" },
  { k: "meditace", cz: "Meditace", en: "Meditation" },
  { k: "ostatni", cz: "Ostatní", en: "Other" },
];
const pomoCatLabel = (k) => { const c = POMO_CATS.find((x) => x.k === k); return c ? L(c.cz, c.en) : k; };
const pomoCatColor = (t, tags, k) => ({ prace: t.accent, studium: (tags.slate || tags.blue).fg, tvorba: (tags.plum || tags.purple).fg, meditace: (tags.moss || tags.green).fg, ostatni: (tags.stone || tags.gray).fg }[k] || t.sand);

function pomoChime(extCtx) {
  // Déšť · závoj tiše filtrovaného šumu, do kterého spadnou tři měkké kapky
  // (G4 · C5 · E5) s pomalým náběhem — příroda, ne budík.
  try {
    const Ctx = window.AudioContext || window.webkitAudioContext;
    if (!Ctx && !extCtx) return;
    const ctx = extCtx || new Ctx();
    const t0 = ctx.currentTime + 0.02;
    const dur = 2.8;
    const buf = ctx.createBuffer(1, Math.floor(ctx.sampleRate * dur), ctx.sampleRate);
    const ch = buf.getChannelData(0);
    for (let i2 = 0; i2 < ch.length; i2++) ch[i2] = Math.random() * 2 - 1;
    const src = ctx.createBufferSource(); src.buffer = buf;
    const lp = ctx.createBiquadFilter(); lp.type = "lowpass"; lp.frequency.value = 850; lp.Q.value = 0.4;
    const ng = ctx.createGain();
    ng.gain.setValueAtTime(0.0001, t0);
    ng.gain.exponentialRampToValueAtTime(0.045, t0 + 0.6);
    ng.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    src.connect(lp); lp.connect(ng); ng.connect(ctx.destination);
    src.start(t0); src.stop(t0 + dur);
    [[392.0, 0.2], [523.25, 0.85], [659.25, 1.5]].forEach(([f, dt]) => {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = "sine"; o.frequency.value = f;
      o.connect(g); g.connect(ctx.destination);
      const ts = t0 + dt;
      g.gain.setValueAtTime(0.0001, ts);
      g.gain.exponentialRampToValueAtTime(0.05, ts + 0.1);
      g.gain.exponentialRampToValueAtTime(0.0001, ts + 1.7);
      o.start(ts); o.stop(ts + 1.8);
    });
  } catch (e) {}
}

// ---- Pomodoro · běžec na úrovni modulu. Časovač nepatří stránce, ale domu:
// přežije přepnutí karty i zavření aplikace (stav žije v localStorage,
// dokončené bloky čekají ve frontě, než si je Kompas vyzvedne do záznamů).
let POMO_KEEP = null;
function pomoKeep(on) {
  try {
    const Ctx = window.AudioContext || window.webkitAudioContext;
    if (!Ctx) return;
    if (on) {
      if (!POMO_KEEP) {
        const ctx = new Ctx();
        const o = ctx.createOscillator(); const g = ctx.createGain();
        o.type = "sine"; o.frequency.value = 30; g.gain.value = 0.001;
        o.connect(g); g.connect(ctx.destination); o.start();
        POMO_KEEP = { ctx, o, g };
      }
      POMO_KEEP.ctx.resume && POMO_KEEP.ctx.resume();
    } else if (POMO_KEEP) {
      try { POMO_KEEP.o.stop(); POMO_KEEP.ctx.close(); } catch (e) {}
      POMO_KEEP = null;
    }
  } catch (e) {}
}
const pomoRunLoad = () => { try { return JSON.parse(localStorage.getItem("tmPomoRun") || "null"); } catch (e) { return null; } };
const pomoRunSave = (rt) => { try { if (rt) localStorage.setItem("tmPomoRun", JSON.stringify(rt)); else localStorage.removeItem("tmPomoRun"); } catch (e) {} };
const pomoQueueLoad = () => { try { return JSON.parse(localStorage.getItem("tmPomoQueue") || "[]"); } catch (e) { return []; } };
const pomoQueueSave = (q) => { try { localStorage.setItem("tmPomoQueue", JSON.stringify(q)); } catch (e) {} };
const pomoIsoOf = (ts) => { const d = new Date(ts); return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`; };
const POMO_LS = new Set();
function pomoAdvance() {
  let rt = pomoRunLoad();
  if (!rt || !rt.running || !rt.endAt) return;
  const c = rt.cfg || {};
  const durMin = (m) => ((m === "focus" ? c.focus : m === "custom" ? (c.custom || 45) : m === "short" ? c.short : c.long) || 25);
  let guard = 0, chimed = false, changed = false;
  while (rt.running && rt.endAt && Date.now() >= rt.endAt && guard++ < 60) {
    changed = true;
    const focusType = rt.mode === "focus" || rt.mode === "custom";
    if (!chimed) {
      chimed = true;
      try { if (c.sound !== false) pomoChime(POMO_KEEP && POMO_KEEP.ctx); } catch (e) {}
      try { if (typeof document !== "undefined" && document.hidden && "Notification" in window && Notification.permission === "granted") new Notification("tanmay", { body: focusType ? L("Blok soustředění dokončen.", "Focus block finished.") : L("Pauza skončila.", "The break is over.") }); } catch (e) {}
    }
    if (focusType) {
      const q = pomoQueueLoad();
      q.unshift({ id: uid(), d: pomoIsoOf(rt.endAt), ts: rt.endAt, min: durMin(rt.mode), cat: rt.cat || "ostatni", note: rt.note || "" });
      pomoQueueSave(q);
      const cyc = (rt.cycle || 0) + 1;
      const nextMode = cyc % (c.every || 4) === 0 ? "long" : "short";
      rt = { ...rt, cycle: cyc, mode: nextMode, endAt: rt.endAt + durMin(nextMode) * 60000, running: true };
    } else {
      rt = { ...rt, mode: "focus", running: false, endAt: null, remaining: durMin("focus") * 60 };
      pomoKeep(false);
    }
  }
  if (changed) pomoRunSave(rt);
}
let POMO_IV = null;
function pomoEnsureTicker() {
  if (POMO_IV || typeof window === "undefined") return;
  POMO_IV = setInterval(() => {
    pomoAdvance();
    POMO_LS.forEach((f) => { try { f(); } catch (e) {} });
    const rt = pomoRunLoad();
    if ((!rt || !rt.running) && pomoQueueLoad().length === 0) { clearInterval(POMO_IV); POMO_IV = null; }
  }, 500);
}
if (typeof window !== "undefined") { try { const r0 = pomoRunLoad(); if (r0 && r0.running) pomoEnsureTicker(); } catch (e) {} }

// Přehledy soustředění · kolik, kdy a v čem. Čte pomoLog (kategorie, minuty,
// časy) a skládá donut, čísla, měsíční kalendář a poslední bloky.
function PomoOverview() {
  const { t, tags } = useT();
  const st = useStore();
  const [per, setPer] = useState("tyden"); // den | tyden | mesic
  const log = st.coll.pomoLog || [];
  const today = todayISO();
  const startISO = (() => {
    if (per === "den") return today;
    const d = new Date(today + "T12:00:00");
    if (per === "tyden") { const w = (d.getDay() + 6) % 7; d.setDate(d.getDate() - w); }
    else d.setDate(1);
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  })();
  const inPer = log.filter((e) => (e.d || "") >= startISO);
  const total = inPer.reduce((a, e) => a + (e.min || 0), 0);
  const byCat = POMO_CATS.map((c) => ({ ...c, min: inPer.filter((e) => e.cat === c.k).reduce((a, e) => a + (e.min || 0), 0) })).filter((c) => c.min > 0);
  const byCatAll = POMO_CATS.map((c) => ({ ...c, min: log.filter((e) => e.cat === c.k).reduce((a, e) => a + (e.min || 0), 0) })).filter((c) => c.min > 0).sort((a, b) => b.min - a.min);
  const fmtH = (m) => (m >= 60 ? `${Math.floor(m / 60)} h ${m % 60 ? (m % 60) + " m" : ""}`.trim() : `${m} m`);
  const hhmm = (ts) => { const d = new Date(ts); return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`; };

  // donut
  const R = 46, C = 2 * Math.PI * R;
  let acc = 0;
  const segs = byCat.map((c) => { const f = total ? c.min / total : 0; const seg = { c, off: acc, f }; acc += f; return seg; });

  // měsíční kalendář · minuty po dnech
  const [y, mo] = [Number(today.slice(0, 4)), Number(today.slice(5, 7))];
  const first = new Date(y, mo - 1, 1);
  const startW = (first.getDay() + 6) % 7;
  const ndays = new Date(y, mo, 0).getDate();
  const dayMin = {};
  log.forEach((e) => { if ((e.d || "").slice(0, 7) === today.slice(0, 7)) dayMin[e.d] = (dayMin[e.d] || 0) + (e.min || 0); });
  const cells = []; for (let i = 0; i < startW; i++) cells.push(null); for (let d = 1; d <= ndays; d++) cells.push(d);

  return (
    <div>
      <div style={{ display: "flex", gap: 6, marginBottom: 16 }}>
        {[["den", L("Dnes", "Today")], ["tyden", L("Týden", "Week")], ["mesic", L("Měsíc", "Month")]].map(([k, lbl]) => (
          <button key={k} onClick={() => setPer(k)} style={{ background: per === k ? t.card : "transparent", border: `1px solid ${per === k ? t.border : "transparent"}`, borderRadius: 20, padding: "5px 14px", cursor: "pointer", color: per === k ? t.heading : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, boxShadow: per === k ? t.shadow : "none" }}>{lbl}</button>
        ))}
      </div>

      <div style={{ display: "flex", gap: 20, alignItems: "center", flexWrap: "wrap", marginBottom: 18 }}>
        <svg width="120" height="120" viewBox="0 0 120 120" style={{ flexShrink: 0, transform: "rotate(-90deg)" }}>
          <circle cx="60" cy="60" r={R} fill="none" stroke={t.borderSoft} strokeWidth="11" />
          {segs.map((sg, i) => (
            <circle key={i} cx="60" cy="60" r={R} fill="none" stroke={pomoCatColor(t, tags, sg.c.k)} strokeWidth="11" strokeLinecap="butt"
              strokeDasharray={`${Math.max(0.001, sg.f) * C} ${C}`} strokeDashoffset={-sg.off * C} style={{ transition: "stroke-dasharray .5s ease" }} />
          ))}
        </svg>
        <div style={{ flex: 1, minWidth: 180 }}>
          <div style={{ fontFamily: FONT_DISPLAY, fontSize: 30, color: t.heading, marginBottom: 8 }}>{fmtH(total)}<span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textMuted, marginLeft: 8 }}>{inPer.length} {L("bloků", "blocks")}</span></div>
          {byCat.length === 0 && <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>{L("V tomto období zatím žádné soustředění.", "No focus in this period yet.")}</div>}
          {byCat.sort((a, b) => b.min - a.min).map((c) => (
            <div key={c.k} style={{ display: "flex", alignItems: "center", gap: 9, padding: "3px 0" }}>
              <span style={{ width: 8, height: 8, borderRadius: "50%", background: pomoCatColor(t, tags, c.k), flexShrink: 0 }} />
              <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.text, flex: 1 }}>{L(c.cz, c.en)}</span>
              <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textSec }}>{fmtH(c.min)}</span>
              <span style={{ fontFamily: FONT_TAG, fontSize: 10.5, letterSpacing: "0.08em", color: t.textMuted, width: 38, textAlign: "right" }}>{total ? Math.round((c.min / total) * 100) : 0} %</span>
            </div>
          ))}
        </div>
      </div>

      <Eyebrow>{L("Tento měsíc", "This month")}</Eyebrow>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4, maxWidth: 380, marginBottom: 6 }}>
        {L(["Po", "Út", "St", "Čt", "Pá", "So", "Ne"], ["Mo", "Tu", "We", "Th", "Fr", "Sa", "Su"]).map((w) => (
          <div key={w} style={{ textAlign: "center", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.08em", fontSize: 10, color: t.textMuted }}>{w}</div>
        ))}
        {cells.map((d, i) => {
          if (!d) return <div key={i} />;
          const iso = `${y}-${String(mo).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
          const m = dayMin[iso] || 0;
          const o = m ? Math.min(1, 0.3 + m / 120) : 0;
          return (
            <div key={i} title={m ? `${iso} · ${fmtH(m)}` : iso} style={{ aspectRatio: "1", borderRadius: 7, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 2, fontFamily: FONT_BODY, fontSize: 10.5, color: iso === today ? t.heading : t.textMuted, border: iso === today ? `1px solid ${hexA(t.accent, 0.55)}` : `1px solid transparent`, background: t.mode === "light" ? "rgba(0,0,0,0.025)" : "rgba(255,255,255,0.03)" }}>
              <span>{d}</span>
              <span style={{ width: 5, height: 5, borderRadius: "50%", background: m ? hexA(t.accent, o) : "transparent" }} />
            </div>
          );
        })}
      </div>

      <div style={{ height: 14 }} />
      <Eyebrow>{per === "den" ? L("Dnešní bloky", "Today's blocks") : per === "tyden" ? L("Bloky tohoto týdne", "This week's blocks") : L("Bloky tohoto měsíce", "This month's blocks")}</Eyebrow>
      {inPer.length === 0 && <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>{L("Zatím prázdno — první blok to změní.", "Empty so far — the first block will change that.")}</p>}
      {(() => {
        const byTs = [...inPer].sort((a, b) => (b.ts || 0) - (a.ts || 0));
        const out = []; let lastD = null;
        byTs.forEach((e) => {
          if (e.d !== lastD) {
            lastD = e.d;
            const dm = byTs.filter((x) => x.d === e.d).reduce((a, x) => a + (x.min || 0), 0);
            out.push(
              <div key={"d" + e.d} style={{ display: "flex", alignItems: "center", gap: 10, margin: "12px 0 4px" }}>
                <span style={{ fontFamily: FONT_DISPLAY, fontSize: 15.5, color: t.textSec }}>{e.d === today ? L("Dnes", "Today") : (e.d || "").slice(8) + ". " + (e.d || "").slice(5, 7) + "."}</span>
                <span style={{ flex: 1, height: 1, background: t.borderSoft }} />
                <span style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.08em", fontSize: 10, color: t.textMuted }}>{fmtH(dm)}</span>
              </div>
            );
          }
          out.push(
            <div key={e.id} style={{ display: "flex", alignItems: "center", gap: 9, padding: "4px 0" }}>
              <span style={{ fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted, width: 42, flexShrink: 0 }}>{e.ts ? hhmm(e.ts) : ""}</span>
              <span style={{ width: 7, height: 7, borderRadius: "50%", background: pomoCatColor(t, tags, e.cat), flexShrink: 0 }} />
              <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.text, flexShrink: 0 }}>{pomoCatLabel(e.cat)}</span>
              {e.note ? <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textSec, flex: 1, minWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>· {e.note}</span> : <span style={{ flex: 1 }} />}
              <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.sand, flexShrink: 0 }}>{e.min} m</span>
            </div>
          );
        });
        return out;
      })()}

      <div style={{ height: 18 }} />
      <Eyebrow>{L("Celkem · od začátku", "All time · in numbers")}</Eyebrow>
      {(() => {
        const allMin = log.reduce((a, e) => a + (e.min || 0), 0);
        const days = new Set(log.map((e) => e.d)).size;
        return (
          <div style={{ background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 12, boxShadow: t.shadow, padding: "12px 14px" }}>
            <div style={{ display: "flex", gap: 18, flexWrap: "wrap", marginBottom: byCatAll.length ? 10 : 0 }}>
              <span><span style={{ fontFamily: FONT_DISPLAY, fontSize: 22, color: t.heading }}>{fmtH(allMin)}</span> <span style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted }}>{L("soustředění", "of focus")}</span></span>
              <span><span style={{ fontFamily: FONT_DISPLAY, fontSize: 22, color: t.heading }}>{log.length}</span> <span style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted }}>{L("bloků", "blocks")}</span></span>
              <span><span style={{ fontFamily: FONT_DISPLAY, fontSize: 22, color: t.heading }}>{days}</span> <span style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted }}>{L("dní", "days")}</span></span>
            </div>
            {byCatAll.map((c) => (
              <div key={c.k} style={{ display: "flex", alignItems: "center", gap: 9, padding: "2px 0" }}>
                <span style={{ width: 7, height: 7, borderRadius: "50%", background: pomoCatColor(t, tags, c.k), flexShrink: 0 }} />
                <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.text, flex: 1 }}>{L(c.cz, c.en)}</span>
                <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textSec }}>{fmtH(c.min)}</span>
              </div>
            ))}
          </div>
        );
      })()}
    </div>
  );
}

function PomodoroTimer() {
  const { t, tags } = useT();
  const st = useStore();
  const cfg = st.pomoSettings();
  const [rtv, setRtv] = useState(() => (typeof window !== "undefined" ? pomoRunLoad() : null));
  const [cfgOpen, setCfgOpen] = useState(false);
  const [pickOpen, setPickOpen] = useState(false); // výběr kategorie před startem
  const [ovOpen, setOvOpen] = useState(false);     // přehledy
  const [fs, setFs] = useState(false);             // celá obrazovka

  const isFocusMode = (m) => m === "focus" || m === "custom";
  const durOf = (m) => (m === "focus" ? cfg.focus : m === "custom" ? (cfg.custom || 45) : m === "short" ? cfg.short : cfg.long) * 60;
  const snap = () => ({ focus: cfg.focus, short: cfg.short, long: cfg.long, custom: cfg.custom || 45, every: cfg.every, sound: cfg.sound });
  const defRt = () => ({ mode: "focus", running: false, endAt: null, remaining: durOf("focus"), cycle: 0, cat: null, note: "", cfg: snap() });
  const rt = rtv || defRt();
  const mode = rt.mode || "focus";
  const running = !!rt.running;
  const cycle = rt.cycle || 0;
  const cat = rt.cat || null;
  const note = rt.note || "";
  const patchRt = (px) => { const nx = { ...(pomoRunLoad() || defRt()), ...px }; pomoRunSave(nx); setRtv(nx); };
  const setNote = (v) => patchRt({ note: v });

  const secsLeft = running && rt.endAt ? Math.max(0, Math.round((rt.endAt - Date.now()) / 1000)) : (rt.remaining != null ? rt.remaining : durOf(mode));
  const total = durOf(mode);
  const p = 1 - secsLeft / Math.max(1, total);

  // Dům běží i bez této stránky — komponenta jen poslouchá modulového běžce.
  React.useEffect(() => {
    const f = () => setRtv(pomoRunLoad());
    POMO_LS.add(f);
    pomoEnsureTicker();
    const vis = () => { pomoAdvance(); setRtv(pomoRunLoad()); };
    document.addEventListener("visibilitychange", vis);
    return () => { POMO_LS.delete(f); document.removeEventListener("visibilitychange", vis); };
  }, []);
  // Dokončené bloky z fronty běžce → do záznamů (i ty dokončené jinde/po zavření).
  React.useEffect(() => {
    const q = pomoQueueLoad();
    if (!q.length) return;
    pomoQueueSave([]);
    q.reverse().forEach((e) => { st.addEntry("pomoLog", e); st.addPomoTree(); });
  });

  const beginRun = (extra) => {
    pomoKeep(true);
    try { if ("Notification" in window && Notification.permission === "default") Notification.requestPermission().catch(() => {}); } catch (e) {}
    patchRt({ ...(extra || {}), running: true, endAt: Date.now() + secsLeft * 1000, cfg: snap() });
    pomoEnsureTicker();
  };
  const start = () => { if (isFocusMode(mode) && !cat) { setPickOpen(true); return; } beginRun(); };
  const pickCat = (k) => { setPickOpen(false); beginRun({ cat: k }); };
  const pause = () => { patchRt({ running: false, remaining: secsLeft, endAt: null }); pomoKeep(false); };
  const reset = (m) => { const mmx = m || mode; patchRt({ mode: mmx, running: false, endAt: null, remaining: durOf(mmx) }); pomoKeep(false); };
  const giveUp = () => st.ask(L("Přerušit soustředění? Tento blok se nezapočítá.", "Interrupt focus? This block won't count."), () => reset("focus"));

  const mm = String(Math.floor(secsLeft / 60)).padStart(2, "0");
  const ss = String(secsLeft % 60).padStart(2, "0");
  const bg = cfg.bg || POMO_BG;
  const MODES = [["focus", "Focus"], ["short", "Short"], ["long", "Long"], ["custom", L("Vlastní", "Custom")]];

  const onPickPhoto = async (file) => {
    if (!file) return;
    if (file.size > 1.5 * 1024 * 1024) { st.ask(L(`Fotka je moc velká (${fmtSize(file.size)}). Limit 1,5 MB — localStorage.`, `The photo is too large (${fmtSize(file.size)}). Limit 1.5 MB — localStorage.`), null); return; }
    try { const att = await readFileAsAtt(file); st.setPomoSettings({ bg: attUrl(att) }); } catch (e) {}
  };
  const numField = (label, key, min, max) => { const val = cfg[key] != null ? cfg[key] : (key === "custom" ? 45 : 0); return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10, padding: "7px 0" }}>
      <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.textSec }}>{label}</span>
      <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
        <button onClick={() => st.setPomoSettings({ [key]: Math.max(min, val - (key === "every" ? 1 : 5)) })} style={{ ...iconBtn(t), width: 24, height: 24 }}>−</button>
        <span style={{ fontFamily: FONT_DISPLAY, fontSize: 18, color: t.heading, minWidth: 44, textAlign: "center" }}>{val}{key === "every" ? "×" : " m"}</span>
        <button onClick={() => st.setPomoSettings({ [key]: Math.min(max, val + (key === "every" ? 1 : 5)) })} style={{ ...iconBtn(t), width: 24, height: 24 }}>＋</button>
      </span>
    </div>
  ); };

  // Výběr kategorie · překryje ciferník, klepnutí na kategorii rovnou spouští
  const renderPicker = () => (
    <div style={{ position: "absolute", inset: 0, zIndex: 5, background: "rgba(16,14,12,0.86)", backdropFilter: "blur(6px)", WebkitBackdropFilter: "blur(6px)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 18, animation: "tmDim .2s ease both" }} onClick={() => setPickOpen(false)}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "100%", maxWidth: 360, textAlign: "center" }}>
        <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.2em", fontSize: 11, color: "rgba(244,240,235,0.7)", marginBottom: 10 }}>{L("Na co se soustředíš?", "What are you focusing on?")}</div>
        <input value={note} onChange={(e) => setNote(e.target.value)} placeholder={L("konkrétně… (nepovinné)", "specifically… (optional)")} style={{ width: "100%", boxSizing: "border-box", background: "rgba(244,240,235,0.08)", border: "1px solid rgba(244,240,235,0.25)", borderRadius: 10, padding: "9px 12px", color: "#F4F0EB", fontFamily: FONT_BODY, fontSize: 13.5, outline: "none", textAlign: "center", marginBottom: 12 }} />
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, justifyContent: "center" }}>
          {POMO_CATS.map((c) => (
            <button key={c.k} onClick={() => pickCat(c.k)} style={{ display: "inline-flex", alignItems: "center", gap: 8, background: cat === c.k ? "rgba(244,240,235,0.16)" : "rgba(244,240,235,0.07)", border: `1px solid ${cat === c.k ? "rgba(244,240,235,0.6)" : "rgba(244,240,235,0.28)"}`, borderRadius: 999, padding: "9px 16px", cursor: "pointer", color: "#F4F0EB", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11.5 }}>
              <span style={{ width: 7, height: 7, borderRadius: "50%", background: pomoCatColor(t, tags, c.k) }} />
              {L(c.cz, c.en)}
            </button>
          ))}
        </div>
        <button onClick={() => setPickOpen(false)} style={{ marginTop: 14, background: "transparent", border: "none", cursor: "pointer", color: "rgba(244,240,235,0.55)", fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("zpět", "back")}</button>
      </div>
    </div>
  );

  return (
    <div>
      <div style={{ position: "relative", borderRadius: 12, overflow: "hidden", border: `1px solid ${t.border}` }}>
        {pickOpen && !fs && renderPicker()}
        <div style={{ position: "absolute", inset: 0, backgroundImage: `url(${bg})`, backgroundSize: "cover", backgroundPosition: "center" }} />
        <div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg, rgba(20,22,18,0.35) 0%, rgba(20,22,18,0.72) 100%)" }} />
        <div style={{ position: "relative", padding: "18px 18px 14px", textAlign: "center" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
            <div style={{ display: "flex", gap: 4 }}>
              {MODES.map(([k, label]) => (
                <button key={k} onClick={() => reset(k)} style={{ background: mode === k ? "rgba(244,240,235,0.14)" : "transparent", border: "none", borderRadius: 12, padding: "3px 10px", cursor: "pointer", color: mode === k ? "#F4F0EB" : "rgba(244,240,235,0.55)", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5 }}>{label}</button>
              ))}
            </div>
            <span style={{ display: "inline-flex", gap: 10, alignItems: "center" }}>
              <button title={L("Na celou obrazovku", "Fullscreen")} onClick={() => setFs(true)} style={{ background: "transparent", border: "none", cursor: "pointer", color: "rgba(244,240,235,0.75)", padding: 2, display: "inline-flex" }}><ArrowOutIcon size={15} /></button>
              <button title={L("Nastavení", "Settings")} onClick={() => setCfgOpen(true)} style={{ background: "transparent", border: "none", cursor: "pointer", color: "rgba(244,240,235,0.75)", padding: 2, display: "inline-flex" }}><TmIcNastaveni size={16} /></button>
            </span>
          </div>
          <div style={{ padding: "10px 0 4px" }}>
            <div style={{ fontFamily: FONT_DISPLAY, fontSize: 58, fontWeight: 300, color: "#F4F0EB", lineHeight: 1, letterSpacing: "0.02em" }}>{mm}:{ss}</div>
            <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.16em", fontSize: 10, color: "rgba(244,240,235,0.6)", marginTop: 8 }}>
              {mode === "focus" || mode === "custom" ? L("Soustředění", "Focus") : mode === "short" ? L("Krátká pauza", "Short break") : L("Dlouhá pauza", "Long break")} · {cycle % cfg.every}/{cfg.every}
            </div>
          </div>
          {isFocusMode(mode) && cat && (
            <button onClick={() => setPickOpen(true)} style={{ display: "inline-flex", alignItems: "center", gap: 7, background: "rgba(20,22,18,0.4)", border: "1px solid rgba(244,240,235,0.28)", borderRadius: 999, padding: "3px 11px", cursor: "pointer", color: "#F4F0EB", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10, marginTop: 6 }}>
              <span style={{ width: 6, height: 6, borderRadius: "50%", background: pomoCatColor(t, tags, cat) }} />
              {pomoCatLabel(cat)}{note.trim() ? " · " + note.trim() : ""}
            </button>
          )}
          <div style={{ height: 3, background: "rgba(244,240,235,0.15)", borderRadius: 2, margin: "12px 0", overflow: "hidden" }}>
            <div style={{ height: "100%", width: `${Math.round(p * 100)}%`, background: "var(--tm-accent, #B87333)", transition: "width .5s linear" }} />
          </div>
          <div style={{ display: "flex", justifyContent: "center", gap: 10 }}>
            {!running ? (
              <button onClick={start} style={{ display: "inline-flex", alignItems: "center", gap: 8, background: "transparent", color: "#F4F0EB", border: "1px solid rgba(244,240,235,0.5)", borderRadius: 20, padding: "8px 24px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.14em", fontSize: 12 }}><TmIcon name="play" size={12} /> Start</button>
            ) : (
              <>
                <button onClick={pause} style={{ background: "transparent", color: "#F4F0EB", border: "1px solid rgba(244,240,235,0.4)", borderRadius: 20, padding: "8px 22px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.14em", fontSize: 12 }}>‖ Pauza</button>
                {mode === "focus" && <button onClick={giveUp} style={{ background: "transparent", color: "rgba(244,240,235,0.55)", border: "1px solid rgba(244,240,235,0.25)", borderRadius: 20, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.14em", fontSize: 12 }}>{L("Vzdát", "Give up")}</button>}
              </>
            )}
          </div>
        </div>
      </div>

      <button onClick={() => setOvOpen(true)} style={{ ...subLabel(t), marginBottom: 0, marginTop: 12, display: "inline-flex", alignItems: "center", gap: 8, background: "transparent", border: "none", cursor: "pointer", padding: 0 }}>
        <span style={{ width: 5, height: 5, borderRadius: "50%", background: t.accent, display: "inline-block" }} />
        {L("Přehledy", "Overview")}
      </button>

      {fs && createPortal(
        <div style={{ position: "fixed", inset: 0, zIndex: 120, background: "#100E0C" }}>
          <div style={{ position: "absolute", inset: 0, backgroundImage: `url(${bg})`, backgroundSize: "cover", backgroundPosition: "center" }} />
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg, rgba(20,22,18,0.4) 0%, rgba(20,22,18,0.78) 100%)" }} />
          {pickOpen && renderPicker()}
          <div style={{ position: "relative", height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "calc(20px + env(safe-area-inset-top)) 20px calc(24px + env(safe-area-inset-bottom))", textAlign: "center" }}>
            <button onClick={() => setFs(false)} title="Esc" style={{ position: "absolute", top: "calc(16px + env(safe-area-inset-top))", right: 18, background: "rgba(244,240,235,0.1)", border: "1px solid rgba(244,240,235,0.3)", borderRadius: 999, width: 34, height: 34, cursor: "pointer", color: "#F4F0EB", fontSize: 16, lineHeight: 1 }}>×</button>
            <div style={{ display: "flex", gap: 6, marginBottom: 26 }}>
              {MODES.map(([k, label]) => (
                <button key={k} onClick={() => reset(k)} style={{ background: mode === k ? "rgba(244,240,235,0.14)" : "transparent", border: "none", borderRadius: 12, padding: "4px 12px", cursor: "pointer", color: mode === k ? "#F4F0EB" : "rgba(244,240,235,0.55)", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.12em", fontSize: 11.5 }}>{label}</button>
              ))}
            </div>
            <div style={{ fontFamily: FONT_DISPLAY, fontWeight: 300, fontSize: "clamp(88px, 24vw, 150px)", color: "#F4F0EB", lineHeight: 1, letterSpacing: "0.02em" }}>{mm}:{ss}</div>
            <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.2em", fontSize: 11.5, color: "rgba(244,240,235,0.65)", marginTop: 14 }}>
              {mode === "focus" || mode === "custom" ? L("Soustředění", "Focus") : mode === "short" ? L("Krátká pauza", "Short break") : L("Dlouhá pauza", "Long break")} · {cycle % cfg.every}/{cfg.every}
            </div>
            {isFocusMode(mode) && cat && (
              <button onClick={() => setPickOpen(true)} style={{ display: "inline-flex", alignItems: "center", gap: 7, background: "rgba(20,22,18,0.4)", border: "1px solid rgba(244,240,235,0.28)", borderRadius: 999, padding: "4px 13px", cursor: "pointer", color: "#F4F0EB", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, marginTop: 12 }}>
                <span style={{ width: 6, height: 6, borderRadius: "50%", background: pomoCatColor(t, tags, cat) }} />
                {pomoCatLabel(cat)}{note.trim() ? " · " + note.trim() : ""}
              </button>
            )}
            <div style={{ width: "min(420px, 78vw)", height: 3, background: "rgba(244,240,235,0.15)", borderRadius: 2, margin: "26px 0", overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${Math.round(p * 100)}%`, background: "var(--tm-accent, #B87333)", transition: "width .5s linear" }} />
            </div>
            <div style={{ display: "flex", justifyContent: "center", gap: 12 }}>
              {!running ? (
                <button onClick={start} style={{ display: "inline-flex", alignItems: "center", gap: 9, background: "transparent", color: "#F4F0EB", border: "1px solid rgba(244,240,235,0.5)", borderRadius: 22, padding: "11px 32px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.16em", fontSize: 13 }}><TmIcon name="play" size={13} /> Start</button>
              ) : (
                <>
                  <button onClick={pause} style={{ background: "transparent", color: "#F4F0EB", border: "1px solid rgba(244,240,235,0.4)", borderRadius: 22, padding: "11px 28px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.16em", fontSize: 13 }}>‖ Pauza</button>
                  {isFocusMode(mode) && <button onClick={giveUp} style={{ background: "transparent", color: "rgba(244,240,235,0.55)", border: "1px solid rgba(244,240,235,0.25)", borderRadius: 22, padding: "11px 20px", cursor: "pointer", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.16em", fontSize: 13 }}>{L("Vzdát", "Give up")}</button>}
                </>
              )}
            </div>
          </div>
        </div>,
        document.body
      )}

      {ovOpen && (
        <CenterSheet center title={L("Soustředění · přehledy", "Focus · overview")} onClose={() => setOvOpen(false)}>
          <PomoOverview />
        </CenterSheet>
      )}

      <Drawer open={cfgOpen} onClose={() => setCfgOpen(false)}>
        <h2 style={{ fontFamily: FONT_DISPLAY, fontSize: 26, fontWeight: 500, color: t.heading, margin: "0 0 14px" }}>{L("Pomodoro · nastavení", "Pomodoro · settings")}</h2>
        {numField(L("Soustředění", "Focus"), "focus", 5, 120)}
        {numField(L("Krátká pauza", "Short break"), "short", 5, 30)}
        {numField(L("Dlouhá pauza", "Long break"), "long", 10, 60)}
        {numField(L("Vlastní blok", "Custom block"), "custom", 15, 180)}
        {numField(L("Dlouhá pauza po", "Long break after"), "every", 2, 8)}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 0", borderTop: `1px solid ${t.borderSoft}`, marginTop: 8 }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.textSec }}>{L("Zvukové upozornění", "Sound alert")}</span>
          <button onClick={() => st.setPomoSettings({ sound: !cfg.sound })} style={{ background: cfg.sound ? t.accent : "transparent", border: `1px solid ${cfg.sound ? t.accent : t.border}`, borderRadius: 14, width: 42, height: 22, cursor: "pointer", position: "relative" }}>
            <span style={{ position: "absolute", top: 2, left: cfg.sound ? 22 : 2, width: 16, height: 16, borderRadius: "50%", background: cfg.sound ? t.bg : t.textMuted, transition: "left .15s" }} />
          </button>
        </div>
        <button onClick={() => { if (cfg.sound) pomoChime(); }} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5, marginBottom: 14 }}>♪ {L("přehrát zvuk", "play sound")}</button>
        <div style={{ borderTop: `1px solid ${t.borderSoft}`, paddingTop: 14 }}>
          <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 8 }}>{L("Pozadí", "Background")}</div>
          <div style={{ width: "100%", height: 90, borderRadius: 8, backgroundImage: `url(${bg})`, backgroundSize: "cover", backgroundPosition: "center", border: `1px solid ${t.border}`, marginBottom: 8 }} />
          <input type="file" accept="image/*" id="pomo-bg-file" onChange={(e) => onPickPhoto(e.target.files && e.target.files[0])} style={{ display: "none" }} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => { const el = document.getElementById("pomo-bg-file"); if (el) el.click(); }} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5 }}>📷 {L("Vlastní fotka", "Custom photo")}</button>
            {cfg.bg && <button onClick={() => st.setPomoSettings({ bg: null })} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Vrátit výchozí", "Restore default")}</button>}
          </div>
        </div>
      </Drawer>
    </div>
  );
}

// buffered name field — rename migration runs on commit, not per keystroke
function AreaTileName({ name, onCommit }) {
  const { t } = useT();
  const [v, setV] = useState(name);
  React.useEffect(() => setV(name), [name]);
  const commit = () => { if (v.trim() && v.trim() !== name) onCommit(v.trim()); else setV(name); };
  return (
    <input
      value={v}
      onChange={(e) => setV(e.target.value)}
      onBlur={commit}
      onKeyDown={(e) => { if (e.key === "Enter") e.currentTarget.blur(); if (e.key === "Escape") { setV(name); e.currentTarget.blur(); } }}
      placeholder={L("Název oblasti…", "Area name…")}
      style={{ flex: 1, minWidth: 70, background: "transparent", border: "none", outline: "none", borderBottom: `1px dashed ${t.borderSoft}`, fontFamily: FONT_BODY, fontSize: 13.5, color: t.text, padding: "1px 0" }}
    />
  );
}

// inline area management · edit mode only · mirrors habit tiles
function AreaInlineEditor() {
  const { t } = useT();
  const st = useStore();
  const areas = st.listAreas();
  const all = st.allGoals();
  const [dragN, setDragN] = useState(null);
  const [overN, setOverN] = useState(null);
  const [adding, setAdding] = useState(false);
  const [newName, setNewName] = useState("");
  const [newIcon, setNewIcon] = useState("▦");
  const remove = (a) => {
    const gs = all.filter((g) => g.area === a.name || (g.areas || []).includes(a.name));
    const msg = gs.length ? L(`Přesunout „${a.name}" do koše? ${gs.length} cílů v této oblasti tam zůstane, jen ztratí přiřazení.`, `Move "${a.name}" to trash? ${gs.length} goals in this area will stay, they just lose the assignment.`) : L(`Přesunout „${a.name}" do koše?`, `Move "${a.name}" to trash?`);
    st.ask(msg, () => st.removeArea(a.name));
  };
  const add = () => { const v = newName.trim(); if (!v) return; st.addArea({ name: v, icon: newIcon.trim() || "▦" }); setNewName(""); setNewIcon("▦"); setAdding(false); };
  return (
    <div style={{ marginBottom: 4 }}>
      <div style={{ ...subLabel(t), marginBottom: 6 }}>{L("Přepiš název přímo v dlaždici · ⠿ přetáhni pro změnu pořadí", "Rename directly in the tile · ⠿ drag to reorder")}</div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px,1fr))", gap: 8 }}>
        {areas.map((a) => (
          <div
            key={a.name}
            onDragOver={(e) => { e.preventDefault(); setOverN(a.name); }}
            onDragLeave={() => setOverN((x) => (x === a.name ? null : x))}
            onDrop={(e) => { e.preventDefault(); if (dragN && dragN !== a.name) st.reorderArea(dragN, a.name); setDragN(null); setOverN(null); }}
            style={{ display: "flex", alignItems: "center", gap: 5, padding: "5px 8px", borderRadius: 8, background: t.card, border: `1px dashed ${overN === a.name && dragN !== a.name ? t.accent : t.border}`, opacity: dragN === a.name ? 0.45 : 1, transition: "border-color .12s ease, opacity .12s ease" }}
          >
            <span
              draggable
              onDragStart={(e) => { setDragN(a.name); e.dataTransfer.effectAllowed = "move"; e.dataTransfer.setData("text/plain", "areaTile:" + a.name); }}
              onDragEnd={() => { setDragN(null); setOverN(null); }}
              title={L("Přetáhni pro změnu pořadí", "Drag to reorder")}
              style={{ cursor: "grab", color: t.textMuted, fontSize: 13, padding: "2px 2px", userSelect: "none", touchAction: "none" }}
            >⠿</span>
            <input value={a.icon} onChange={(e) => st.setAreaIcon(a.name, e.target.value.slice(0, 4))} style={{ width: 30, background: "transparent", border: "none", outline: "none", textAlign: "center", fontSize: 14 }} />
            <AreaTileName name={a.name} onCommit={(nw) => st.renameArea(a.name, nw)} />
            <button title={L("Do koše", "To trash")} onClick={() => remove(a)} style={{ ...iconBtn(t), width: 22, height: 22, minWidth: 22, padding: 0, fontSize: 11, border: "none", color: t.textMuted }}>✕</button>
          </div>
        ))}
        {adding ? (
          <div style={{ display: "flex", alignItems: "center", gap: 5, padding: "5px 8px", borderRadius: 8, border: `1px dashed ${t.accent}` }}>
            <input value={newIcon} onChange={(e) => setNewIcon(e.target.value.slice(0, 4))} style={{ width: 30, background: "transparent", border: "none", outline: "none", textAlign: "center", fontSize: 14 }} />
            <input autoFocus value={newName} onChange={(e) => setNewName(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") add(); if (e.key === "Escape") setAdding(false); }} placeholder={L("Nová oblast…", "New area…")} style={{ flex: 1, minWidth: 70, background: "transparent", border: "none", outline: "none", fontFamily: FONT_BODY, fontSize: 13.5, color: t.text }} />
            <button onClick={add} style={{ ...iconBtn(t), width: 22, height: 22, minWidth: 22, padding: 0, fontSize: 11, color: t.accent }}>✓</button>
          </div>
        ) : (
          <button onClick={() => setAdding(true)} style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6, padding: "8px 10px", borderRadius: 8, background: "transparent", border: `1px dashed ${t.border}`, cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 13 }}>＋ oblast</button>
        )}
      </div>
    </div>
  );
}

function AreaChips({ onOpen, onAdd }) {
  const { t } = useT();
  const st = useStore();
  const all = st.allGoals();
  if (st.editMode) return <AreaInlineEditor />;
  return (
    <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 4, alignItems: "center" }}>
      {st.listAreas().map((a) => {
        const gs = all.filter((g) => g.area === a.name || (g.areas || []).includes(a.name));
        const done = gs.filter((g) => g.status === "Completed").length;
        return (
          <button key={a.name} onClick={() => onOpen(a.name)} title={`${done} / ${gs.length} ${L("cílů", "goals")}`} className="tm-nav-item tm-lift" style={{ display: "inline-flex", alignItems: "center", gap: 7, background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 18, padding: "6px 13px", cursor: "pointer" }}>
          <span style={{ fontSize: 14 }}>{a.icon}</span>
            <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.text }}>{areaLabel(a.name)}</span>
            <span style={{ width: 34, height: 3, borderRadius: 2, background: t.borderSoft, position: "relative", overflow: "hidden" }}>
              <span style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: `${gs.length ? Math.round((done / gs.length) * 100) : 0}%`, background: t.accent, transition: "width .55s cubic-bezier(.25,.8,.3,1)" }} />
            </span>
          </button>
        );
      })}
      {onAdd && <button onClick={onAdd} title={L("Nová oblast", "New area")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 18, padding: "6px 12px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13 }}>＋ {L("nová", "new")}</button>}
    </div>
  );
}

function PageGoals({ go }) {
  const { t } = useT();
  const st = useStore();
  const live = st.allGoals().filter((g) => !g.archive);
  const nProg = live.filter((g) => g.status === "In progress").length;
  const nDone = live.filter((g) => g.status === "Completed").length;
  return (
    <>
      {go && <button onClick={() => go("kompas")} className="tm-nav-item" style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "0 8px 14px 0", display: "inline-flex", alignItems: "center", gap: 6, borderRadius: 8 }}>‹ {L("Kompas", "Compass")}</button>}
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcCile size={34} /></span>} pageKey="cile" kicker={L("Kompas", "Compass")}>{L("Cíle", "Goals")}</PageTitle>
      <p style={pProse(t)}>{live.length} {L("cílů", "goals")} · {nProg} {L("rozpracovaných", "in progress")} · {nDone} {L("hotových.", "done.")}{st.editMode && <span style={{ color: t.textMuted }}>{L(" Klikni na kartu a otevři detail.", " Click a card to open its detail.")}</span>}</p>
      <GoalWorkspace />
    </>
  );
}
// ---- Rich text · lightweight brand formatting ----
// # Nadpis (Cormorant) · ## Podnadpis (Barlow tag) · **tučně** · *kurzíva*
// ---- brand ink · the only colours writing may wear (§6: copper/sage/sand as accents) ----
// stored by NAME so it re-tunes to light/dark; recognised across both palettes.
const BRAND_INK = {
  copper: ["b87333", "a5622a", "c98e4f"],
  sage: ["7c8c6e", "57684a", "566a45", "98a47f"],
  sand: ["c5b49a", "9a8763", "8f7a55", "d2be97"],
};
function inkHex(name, t) { return name === "copper" ? t.accent : name === "sage" ? t.sage : name === "sand" ? t.sand : null; }
function normHex(c) {
  if (!c) return "";
  const s = String(c).trim().toLowerCase();
  const m = s.match(/rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
  if (m) return [1, 2, 3].map((i) => (+m[i]).toString(16).padStart(2, "0")).join("");
  return s.replace(/[^0-9a-f]/g, "");
}
function inkName(color) { const h = normHex(color); if (!h) return null; for (const k in BRAND_INK) if (BRAND_INK[k].includes(h)) return k; return null; }

// inline renderer · recursive over {c|name}…{/c}, **bold**, *italic* (any nesting order)
function richInline(s, t) {
  const out = [];
  const re = /\{c\|(copper|sage|sand)\}([\s\S]*?)\{\/c\}|\*\*([^*\n]+)\*\*|\*([^*\n]+)\*/g;
  let last = 0, m, key = 0;
  while ((m = re.exec(String(s)))) {
    if (m.index > last) out.push(<React.Fragment key={key++}>{String(s).slice(last, m.index)}</React.Fragment>);
    if (m[1] != null) out.push(<span key={key++} style={{ color: inkHex(m[1], t) }}>{richInline(m[2], t)}</span>);
    else if (m[3] != null) out.push(<strong key={key++} style={{ fontWeight: 700 }}>{richInline(m[3], t)}</strong>);
    else if (m[4] != null) out.push(<em key={key++}>{richInline(m[4], t)}</em>);
    last = re.lastIndex;
  }
  if (last < String(s).length) out.push(<React.Fragment key={key++}>{String(s).slice(last)}</React.Fragment>);
  return out;
}

function RichText({ text, style }) {
  const { t } = useT();
  const lines = String(text || "").split("\n");
  return (
    <div style={{ fontFamily: FONT_BODY, fontSize: 14.5, lineHeight: 1.75, color: t.textSec, maxWidth: 700, ...style }}>
      {lines.map((ln, i) => {
        const mi = ln.match(IMG_RE);
        if (mi) return <img key={i} src={r2Url(mi[1])} alt="" style={{ width: Math.min(+mi[2], 680), maxWidth: "100%", display: "block", borderRadius: 8, margin: "10px 0", border: `1px solid ${t.borderSoft}` }} />;
        if (/^##\s/.test(ln)) return <div key={i} style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.14em", fontSize: 11.5, color: t.sage, margin: `${i === 0 ? 0 : 14}px 0 3px` }}>{richInline(ln.slice(3), t)}</div>;
        if (/^#\s/.test(ln)) return <div key={i} style={{ fontFamily: FONT_DISPLAY, fontSize: 20, color: t.heading, lineHeight: 1.3, margin: `${i === 0 ? 0 : 14}px 0 3px` }}>{richInline(ln.slice(2), t)}</div>;
        if (ln.trim() === "") return <div key={i} style={{ height: "0.85em" }} />;
        return <div key={i}>{richInline(ln, t)}</div>;
      })}
    </div>
  );
}

// obrázek v textu · vlastní blok, drží se v R2, ukládá se jako řádek !img(ID|ŠÍŘKA)
const IMG_RE = /^!img\(([^|)]+)\|(\d+)\)$/;
function figHtml(id, w, t) {
  const url = r2Url(id);
  const b = 'style="all:unset;cursor:pointer;color:#F4F0EB;font-size:12px;line-height:1;padding:3px 6px;border-radius:5px;font-family:sans-serif;"';
  const bar = 'style="position:absolute;top:6px;right:6px;display:flex;gap:1px;background:rgba(20,18,16,0.62);border-radius:8px;padding:2px;"';
  return '<figure contenteditable="false" data-img="' + id + '" data-w="' + w + '" class="tm-fig" style="position:relative;display:block;margin:10px 0;width:' + w + 'px;max-width:100%;">'
    + '<img src="' + url + '" alt="" draggable="false" style="width:100%;display:block;border-radius:8px;border:1px solid ' + t.borderSoft + ';" />'
    + '<span class="tm-fig-tools" contenteditable="false" ' + bar + '>'
    + '<button type="button" data-act="up" title="Nahoru" ' + b + '>↑</button>'
    + '<button type="button" data-act="down" title="Dolů" ' + b + '>↓</button>'
    + '<button type="button" data-act="minus" title="Zmenšit" ' + b + '>–</button>'
    + '<button type="button" data-act="plus" title="Zvětšit" ' + b + '>+</button>'
    + '<button type="button" data-act="del" title="Odebrat" ' + b + '>✕</button>'
    + '</span></figure>';
}
function mdToHtml(md, t) {
  const esc = (s) => s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const inline = (s) => {
    let html = "", last = 0, m;
    const re = /\{c\|(copper|sage|sand)\}([\s\S]*?)\{\/c\}|\*\*([^*\n]+)\*\*|\*([^*\n]+)\*/g;
    while ((m = re.exec(s))) {
      if (m.index > last) html += esc(s.slice(last, m.index));
      if (m[1] != null) html += '<span style="color:' + (inkHex(m[1], t) || "") + '">' + inline(m[2]) + "</span>";
      else if (m[3] != null) html += "<b>" + inline(m[3]) + "</b>";
      else if (m[4] != null) html += "<i>" + inline(m[4]) + "</i>";
      last = re.lastIndex;
    }
    html += esc(s.slice(last));
    return html;
  };
  return String(md || "").split("\n").map((ln) => {
    const mi = ln.match(IMG_RE);
    if (mi) return figHtml(mi[1], mi[2], t);
    if (/^##\s/.test(ln)) return "<h2>" + inline(ln.slice(3)) + "</h2>";
    if (/^#\s/.test(ln)) return "<h1>" + inline(ln.slice(2)) + "</h1>";
    if (ln.trim() === "") return "<div><br></div>";
    return "<div>" + inline(ln) + "</div>";
  }).join("");
}

function htmlToMd(root) {
  const inline = (node) => {
    let out = "";
    node.childNodes.forEach((n) => {
      if (n.nodeType === 3) { out += n.nodeValue; return; }
      if (n.nodeType !== 1) return;
      if (n.tagName === "BR") { out += "\n"; return; }
      if (n.classList && n.classList.contains("tm-fig-tools")) return;
      if (n.tagName === "FIGURE" && n.getAttribute("data-img")) { out += "\n!img(" + n.getAttribute("data-img") + "|" + (n.getAttribute("data-w") || "320") + ")\n"; return; }
      const st = (n.getAttribute && n.getAttribute("style")) || "";
      const isB = n.tagName === "B" || n.tagName === "STRONG" || /font-weight:\s*(bold|[6-9]00)/i.test(st);
      const isI = n.tagName === "I" || n.tagName === "EM" || /font-style:\s*italic/i.test(st);
      const cName = inkName((n.style && n.style.color) || (n.getAttribute && n.getAttribute("color")) || "");
      let inner = inline(n);
      if (isB && inner.trim()) inner = "**" + inner + "**";
      if (isI && inner.trim()) inner = "*" + inner + "*";
      if (cName && inner.trim()) inner = "{c|" + cName + "}" + inner + "{/c}";
      out += inner;
    });
    return out;
  };
  const lines = [];
  root.childNodes.forEach((n) => {
    if (n.nodeType === 3) { if (n.nodeValue !== "") lines.push(n.nodeValue); return; }
    if (n.nodeType !== 1) return;
    const tag = n.tagName;
    if (tag === "BR") { lines.push(""); return; }
    const onlyBr = n.childNodes.length === 1 && n.firstChild.nodeType === 1 && n.firstChild.tagName === "BR";
    if (tag === "FIGURE" && n.getAttribute("data-img")) lines.push("!img(" + n.getAttribute("data-img") + "|" + (n.getAttribute("data-w") || "320") + ")");
    else if (tag === "H1") lines.push(onlyBr ? "# " : "# " + inline(n));
    else if (tag === "H2" || tag === "H3") lines.push(onlyBr ? "## " : "## " + inline(n));
    else if (onlyBr) lines.push("");
    else inline(n).split("\n").forEach((x) => lines.push(x));
  });
  return lines.join("\n").replace(/\n+$/, "");
}

function MdToolbar({ exec, onImage }) {
  const { t } = useT();
  const [, force] = useState(0);
  const [palOpen, setPalOpen] = useState(false);
  React.useEffect(() => {
    const h = () => force((x) => x + 1);
    document.addEventListener("selectionchange", h);
    return () => document.removeEventListener("selectionchange", h);
  }, []);
  const state = (c) => { try { return document.queryCommandState(c); } catch (err) { return false; } };
  const blockOn = (tag) => { try { return (document.queryCommandValue("formatBlock") || "").toLowerCase() === tag; } catch (err) { return false; } };
  const curInk = (() => { try { return inkName(document.queryCommandValue("foreColor")); } catch (err) { return null; } })();
  const btn = (on) => ({ background: on ? hexA(t.accent, 0.16) : "transparent", border: `1px solid ${on ? t.accent : t.borderSoft}`, borderRadius: 8, cursor: "pointer", color: on ? t.accent : t.textSec, padding: "2px 9px", minWidth: 30, height: 24, display: "inline-flex", alignItems: "center", justifyContent: "center" });
  const block = (tag) => () => {
    const cur = (document.queryCommandValue("formatBlock") || "").toLowerCase();
    document.execCommand("formatBlock", false, cur === tag ? "div" : tag.toUpperCase());
  };
  const inks = [["copper", t.accent], ["sage", t.sage], ["sand", t.sand]];
  return (
    <div style={{ display: "flex", gap: 5, alignItems: "center", marginBottom: 7, flexWrap: "wrap" }}>
      <button type="button" title="Nadpis" onPointerDown={exec(block("h1"))} style={{ ...btn(blockOn("h1")), fontFamily: FONT_DISPLAY, fontSize: 14 }}>Aa</button>
      <button type="button" title="Podnadpis" onPointerDown={exec(block("h2"))} style={{ ...btn(blockOn("h2")), fontFamily: FONT_TAG, fontSize: 10, letterSpacing: "0.1em" }}>AA</button>
      <button type="button" title={L("Tučně · Ctrl+B", "Bold · Ctrl+B")} onPointerDown={exec(() => document.execCommand("bold"))} style={{ ...btn(state("bold")), fontFamily: FONT_BODY, fontWeight: 700, fontSize: 12.5 }}>B</button>
      <button type="button" title={L("Kurzíva · Ctrl+I", "Italic · Ctrl+I")} onPointerDown={exec(() => document.execCommand("italic"))} style={{ ...btn(state("italic")), fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 12.5 }}>I</button>
      <span style={{ width: 1, height: 16, background: t.borderSoft, margin: "0 2px" }} />
      <span style={{ position: "relative", display: "inline-flex" }}>
        <button type="button" title={L("Barva textu", "Text colour")} onPointerDown={(e) => { e.preventDefault(); setPalOpen((x) => !x); }} style={{ ...btn(curInk !== null), padding: "2px 6px", gap: 4 }}>
          <span style={{ width: 13, height: 13, borderRadius: "50%", background: curInk === "copper" ? t.accent : curInk === "sage" ? t.sage : curInk === "sand" ? t.sand : t.text, border: `1px solid ${t.borderSoft}` }} />
          <span style={{ fontSize: 9 }}>▾</span>
        </button>
        {palOpen && (
          <span style={{ position: "absolute", top: "calc(100% + 5px)", left: 0, zIndex: 30, display: "inline-flex", gap: 6, alignItems: "center", background: t.card, border: `1px solid ${t.border}`, borderRadius: 10, padding: "6px 9px", boxShadow: t.shadow }}>
            {inks.map(([name, hex]) => (
              <button key={name} type="button" title={name} onPointerDown={(e) => { exec(() => document.execCommand("foreColor", false, hex))(e); setPalOpen(false); }} style={{ width: 20, height: 20, borderRadius: "50%", cursor: "pointer", background: hex, border: curInk === name ? `2px solid ${t.text}` : `1px solid ${t.borderSoft}`, padding: 0 }} />
            ))}
            <span style={{ width: 1, height: 16, background: t.borderSoft }} />
            <button type="button" onPointerDown={(e) => { exec(() => document.execCommand("foreColor", false, t.text))(e); setPalOpen(false); }} style={{ ...btn(curInk === null), fontFamily: FONT_BODY, fontSize: 11, minWidth: 30, padding: "2px 8px" }}>{L("výchozí", "default")}</button>
          </span>
        )}
      </span>
      {onImage && <><span style={{ width: 1, height: 16, background: t.borderSoft, margin: "0 2px" }} />
      <button type="button" title={L("Vložit obrázek", "Insert image")} onPointerDown={(e) => { e.preventDefault(); onImage(); }} style={{ ...btn(false), padding: "2px 7px" }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="16" rx="2" /><circle cx="8.5" cy="9.5" r="1.5" /><path d="M21 16l-5-5L5 21" /></svg></button></>}
    </div>
  );
}

// WYSIWYG editor · renders brand formatting directly while typing; stores plain text with markers
function RichArea({ value, onChange, placeholder = L("Piš…", "Write…") }) {
  const { t } = useT();
  const ref = React.useRef(null);
  const last = React.useRef(null);
  const imgRef = React.useRef(null);
  const [focused, setFocused] = useState(false);
  const updEmpty = (el) => el.setAttribute("data-empty", el.textContent.trim() === "" && !el.querySelector("b,i,span,img") ? "true" : "false");
  React.useEffect(() => {
    const el = ref.current; if (!el) return;
    if ((value || "") !== (last.current || "")) {
      el.innerHTML = mdToHtml(value, t);
      last.current = value || "";
      updEmpty(el);
    }
  }, [value]);
  // browsers preserve visual styles as inline color/font-size spans (e.g. when
  // un-heading a block) — strip everything except bold/italic semantics
  const cleanup = (el) => {
    el.querySelectorAll("font").forEach((f) => {
      if (f.closest && f.closest("figure.tm-fig")) return;
      const cName = inkName(f.getAttribute("color"));
      f.removeAttribute("color"); f.removeAttribute("size"); f.removeAttribute("face");
      if (cName) f.style.color = inkHex(cName, t);
    });
    el.querySelectorAll("[style]").forEach((n) => {
      if (n.closest && n.closest("figure.tm-fig")) return;
      const stAttr = n.getAttribute("style") || "";
      const keepB = /font-weight:\s*(bold|[6-9]00)/i.test(stAttr);
      const keepI = /font-style:\s*italic/i.test(stAttr);
      const cName = inkName(n.style && n.style.color);
      n.removeAttribute("style");
      if (keepB) n.style.fontWeight = "700";
      if (keepI) n.style.fontStyle = "italic";
      if (cName) n.style.color = inkHex(cName, t);
    });
  };
  const sync = () => {
    const el = ref.current; if (!el) return;
    cleanup(el);
    const md = htmlToMd(el);
    last.current = md;
    updEmpty(el);
    onChange(md);
  };
  const exec = (fn) => (e) => { e.preventDefault(); const el = ref.current; if (!el) return; el.focus(); fn(); sync(); };
  const insertImage = async (file) => {
    if (!file) return;
    try {
      const blob = await resizeImageToBlob(file, 1200);
      const gid = uid() + "g";
      await r2Put(gid, blob, file.name);
      const el = ref.current;
      if (el) { el.focus(); document.execCommand("insertHTML", false, "<div><br></div>" + figHtml(gid, 320, t) + "<div><br></div>"); sync(); }
    } catch (err) {}
    if (imgRef.current) imgRef.current.value = "";
  };
  const figAction = (e) => {
    const tgt = e.target && (e.target.nodeType === 1 ? e.target : e.target.parentElement);
    const b = tgt && tgt.closest && tgt.closest("[data-act]");
    if (!b) return;
    e.preventDefault(); e.stopPropagation();
    const fig = b.closest("figure"); if (!fig) return;
    const act = b.getAttribute("data-act");
    if (act === "del") fig.remove();
    else if (act === "up") { const p = fig.previousElementSibling; if (p) fig.parentNode.insertBefore(fig, p); }
    else if (act === "down") { const nx = fig.nextElementSibling; if (nx) fig.parentNode.insertBefore(nx, fig); }
    else { let w = parseInt(fig.getAttribute("data-w") || "320", 10); w = act === "plus" ? Math.min(680, w + 60) : Math.max(120, w - 60); fig.setAttribute("data-w", String(w)); fig.style.width = w + "px"; }
    sync();
  };
  return (
    <div>
      {focused && <MdToolbar exec={exec} onImage={() => imgRef.current && imgRef.current.click()} />}
      <input ref={imgRef} type="file" accept="image/*" onChange={(e) => insertImage(e.target.files && e.target.files[0])} style={{ display: "none" }} />
      <div
        ref={ref}
        className="tm-rich"
        contentEditable
        suppressContentEditableWarning
        data-placeholder={placeholder}
        spellCheck={false}
        onMouseDown={figAction}
        onInput={sync}
        onFocus={() => { setFocused(true); try { document.execCommand("styleWithCSS", false, true); } catch (err) {} }}
        onBlur={() => setFocused(false)}
        onPaste={(e) => { e.preventDefault(); const txt = e.clipboardData.getData("text/plain"); document.execCommand("insertText", false, txt); }}
        onKeyDown={(e) => {
          if (e.key === "Enter" && !e.shiftKey) {
            requestAnimationFrame(() => {
              const cur = (document.queryCommandValue("formatBlock") || "").toLowerCase();
              if (cur === "h1" || cur === "h2" || cur === "h3") { document.execCommand("formatBlock", false, "div"); sync(); }
            });
          }
        }}
      />
    </div>
  );
}

function InlineText({ value, placeholder, onSave }) {
  const { t } = useT();
  const [edit, setEdit] = useState(false);
  const [v, setV] = useState(value || "");
  if (edit) return (
    <input autoFocus value={v} onChange={(e) => setV(e.target.value)} onBlur={() => { onSave(v); setEdit(false); }} onKeyDown={(e) => { if (e.key === "Enter") { onSave(v); setEdit(false); } }} style={{ width: "100%", background: "transparent", border: "none", borderBottom: `1px solid ${t.accent}`, color: t.text, fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 14, padding: "2px 0", outline: "none" }} />
  );
  return <span onClick={() => { setV(value || ""); setEdit(true); }} title="Klikni a uprav" style={{ cursor: "text", fontFamily: FONT_BODY, fontStyle: value ? "italic" : "normal", fontSize: 14, color: value ? t.textSec : t.textMuted }}>{value || placeholder}</span>;
}


function ContentDetail({ id, onClose, onExpand, wide }) {
  const { t } = useT();
  const st = useStore();
  const e = (st.coll.content || []).find((x) => x.id === id);
  const coverRef = React.useRef(null);
  const fileRef = React.useRef(null);
  const taRef = React.useRef(null);
  const autosize = () => { const el = taRef.current; if (el) { el.style.height = "auto"; el.style.height = el.scrollHeight + 2 + "px"; } };
  React.useEffect(() => { autosize(); }, [id]);
  if (!e) return null;
  const upd = (patch) => st.updateEntry("content", e.id, patch);
  const cycle = (list, cur, key) => upd({ [key]: list[(list.indexOf(cur) + 1) % list.length] });
  const pickCover = async (file) => {
    if (!file) return;
    try {
      const old = e.icon;
      const blob = await resizeImageToBlob(file, 360);
      const id = uid() + "i";
      await r2Put(id, blob, file.name);
      upd({ icon: { r2id: id } });
      if (old && old.r2id) r2Del(old.r2id);
    } catch (err) {}
    if (coverRef.current) coverRef.current.value = "";
  };
  const findCover = () => {
    const q = ((e.title || "") + " " + (e.author || "")).trim() || L("obálka", "cover");
    window.open("https://www.google.com/search?tbm=isch&q=" + encodeURIComponent(q + " cover"), "_blank", "noopener,noreferrer");
  };
  const sourceLink = () => {
    const q = encodeURIComponent(((e.title || "") + " " + (e.author || "")).trim());
    if (e.type === "Movie") return { url: "https://www.imdb.com/find/?q=" + encodeURIComponent(e.title || ""), label: "IMDb" };
    if (e.type === "Podcast" || e.type === "Feed") return { url: "https://www.google.com/search?q=" + q, label: "Google" };
    return { url: "https://www.goodreads.com/search?q=" + q, label: "Goodreads" };
  };
  const attach = async (fileList) => {
    const added = await filesToAtts(fileList, st.ask);
    if (added.length) upd({ att: [...(e.att || []), ...added] });
    if (fileRef.current) fileRef.current.value = "";
  };
  const scoreN = e.score === "" || e.score == null ? null : +e.score;
  return (
    <div style={wide ? { maxWidth: 640 } : undefined}>
      <input ref={coverRef} type="file" accept="image/*" onChange={(ev) => pickCover(ev.target.files && ev.target.files[0])} style={{ display: "none" }} />
      <button title={L("Nahrát obálku", "Upload cover")} onClick={() => coverRef.current && coverRef.current.click()} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0, marginBottom: 12, display: "block" }}>
        {e.icon
          ? <img src={imgSrc(e.icon)} alt="" style={{ width: 92, height: 128, objectFit: "cover", borderRadius: 8, border: `1px solid ${t.border}`, boxShadow: "0 8px 20px rgba(0,0,0,0.3)", display: "block" }} />
          : <span style={{ width: 92, height: 128, borderRadius: 8, border: `1px dashed ${t.border}`, display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 6, color: t.textMuted, fontFamily: FONT_BODY, fontSize: 11 }}><span style={{ color: t.sand }}>{React.createElement(C_TYPE_GLYPH[e.type] || TmIcKniha, { size: 26 })}</span>{L("nahrát obálku", "upload cover")}<span onClick={(ev) => { ev.stopPropagation(); findCover(); }} title={L("Otevře Google obrázky s názvem — obrázek stáhni a nahraj", "Opens Google Images for the title — download and upload it")} style={{ marginTop: 4, paddingTop: 6, borderTop: `1px dashed ${t.borderSoft}`, width: "72%", textAlign: "center", color: t.sand, fontSize: 11.5 }}>{L("Najít obálku", "Find cover")}</span></span>}
      </button>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 8, alignItems: "center", marginBottom: 12 }}>
        {e.icon && <button onClick={() => { if (e.icon && e.icon.r2id) r2Del(e.icon.r2id); upd({ icon: null }); }} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Odebrat", "Remove")}</button>}
      </div>
      <div style={{ marginBottom: 14 }}>
        {st.editMode
          ? <input value={e.title} onChange={(ev) => upd({ title: ev.target.value })} placeholder={L("Název…", "Title…")} style={{ width: "100%", background: "transparent", border: "none", fontFamily: FONT_DISPLAY, fontSize: 28, fontWeight: 500, color: t.heading, outline: "none", padding: 0, lineHeight: 1.2 }} />
          : (() => { const s = sourceLink(); return <a href={e.title ? s.url : undefined} target="_blank" rel="noopener noreferrer" title={e.title ? L("Vyhledat · ", "Search · ") + s.label : ""} onMouseOver={(ev) => { if (e.title) ev.currentTarget.style.color = t.accent; }} onMouseOut={(ev) => { ev.currentTarget.style.color = t.heading; }} style={{ display: "block", fontFamily: FONT_DISPLAY, fontSize: 28, fontWeight: 500, color: t.heading, lineHeight: 1.2, textDecoration: "none", cursor: e.title ? "pointer" : "default", transition: "color .18s ease" }}>{e.title || L("Bez názvu", "Untitled")}</a>; })()}
      </div>
      <PropRow icon="◌" label={L("Stav", "Progress")}><button onClick={() => cycle(C_PROGRESS, e.progress, "progress")} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0 }}><Tag label={C_PROG_LABEL(e.progress, e.type)} color={C_PROG_COLOR[e.progress] || "default"} /></button></PropRow>
      <PropRow icon="≡" label={L("Autor", "Author")}><input value={e.author || ""} onChange={(ev) => upd({ author: ev.target.value })} placeholder="—" style={{ width: "100%", background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 14, outline: "none" }} /></PropRow>
      <PropRow icon="▦" label={L("Dokončeno dne", "Date finished")}><input type="date" value={e.dateFinished || ""} onChange={(ev) => upd({ dateFinished: ev.target.value })} style={{ background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 14, outline: "none", colorScheme: t.mode === "light" ? "light" : "dark" }} /></PropRow>
      <PropRow icon="#" label={L("Skóre /10", "Score /10")}>
        <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
          <button onClick={() => upd({ score: String(Math.max(0, (scoreN == null ? 5 : scoreN) - 1)) })} style={{ ...iconBtn(t), width: 22, height: 22 }}>−</button>
          <span style={{ fontFamily: FONT_DISPLAY, fontSize: 18, color: scoreN != null ? t.heading : t.textMuted, minWidth: 26, textAlign: "center" }}>{scoreN != null ? scoreN : "—"}</span>
          <button onClick={() => upd({ score: String(Math.min(10, (scoreN == null ? 5 : scoreN) + 1)) })} style={{ ...iconBtn(t), width: 22, height: 22 }}>＋</button>
        </span>
      </PropRow>
      <PropRow icon="⊙" label={L("Typ", "Type")}><button onClick={() => cycle(C_TYPES, e.type, "type")} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0 }}><Tag label={e.type ? C_TYPE_LABEL(e.type) : "—"} color={C_TYPE_COLOR[e.type] || "default"} /></button></PropRow>
      <PropRow icon="⊙" label={L("Žánr", "Genre")}><Select small value={e.category || ""} onChange={(v) => upd({ category: v })} placeholder="—" style={{ maxWidth: 170, width: 170 }} options={(C_CATS_BY_TYPE[e.type] || C_CATS).map((c) => ({ v: c, label: C_CAT_LABEL(c) }))} /></PropRow>
      <PropRow icon="▤" label={L("Archiv", "Archive")}>
        <button onClick={() => upd({ archive: !e.archive })} title={e.archive ? L("Vrátit z archivu", "Restore from archive") : L("Archivovat", "Archive")} style={{ width: 18, height: 18, borderRadius: 4, border: `1.5px solid ${e.archive ? t.accent : t.border}`, background: e.archive ? t.accent : "transparent", cursor: "pointer", color: t.bg, fontSize: 11, lineHeight: 1, padding: 0 }}>{e.archive ? "✓" : ""}</button>
      </PropRow>

      <div style={{ display: "flex", gap: 8, alignItems: "center", padding: "12px 0 6px" }}>
        <input ref={fileRef} type="file" multiple accept=".pdf,audio/*,image/*,.doc,.docx,.txt" onChange={(ev) => attach(ev.target.files)} style={{ display: "none" }} />
        <button onClick={() => fileRef.current && fileRef.current.click()} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5, display: "inline-flex", alignItems: "center", gap: 7 }}><ClipIcon size={13} />{L("PDF · audio shrnutí · soubor", "PDF · audio summary · file")}</button>
        {onExpand && <button title={L("Otevřít jako stránku", "Open as page")} onClick={onExpand} style={{ ...iconBtn(t), border: "none", color: t.textMuted, fontSize: 14 }}>⤢</button>}
        {wide && <PinToggle entry={e} />}
        <span style={{ flex: 1 }} />
        {(st.editMode || wide) && <button onClick={() => st.ask(L(`Přesunout „${e.title}" do koše?`, `Move "${e.title}" to trash?`), () => { st.removeEntry("content", e.id); onClose && onClose(); })} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 14, padding: "4px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Do koše", "To trash")}</button>}
      </div>
      <AttachmentStrip att={e.att} onRemove={(aid) => upd({ att: (e.att || []).filter((x) => x.id !== aid) })} />

      <div style={{ borderTop: `1px solid ${t.borderSoft}`, marginTop: 14, paddingTop: 12 }}>
        <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 6 }}>{L("Postřehy", "Notes")}</div>
        <RichArea value={e.text || ""} onChange={(v) => upd({ text: v })} placeholder={L("Co si z toho odnáším…", "What I take from it…")} />
      </div>
    </div>
  );
}

function ContentRow({ e, cols, last, onOpen, noDrag, selecting, selected, onToggleSel }) {
  const { t } = useT();
  const st = useStore();
  const rootRef = React.useRef(null);
  const onOverRef = React.useRef(null);
  onOverRef.current = (overId) => st.reorderEntry("content", e.id, overId);
  const disRef = React.useRef(false); disRef.current = !!noDrag || !!selecting;
  const dragging = useHoldReorder(rootRef, e.id, "data-cid", onOverRef, disRef);
  return (
    <div
      ref={rootRef}
      data-cid={e.id}
      draggable={!noDrag && !selecting}
      onDragStart={!noDrag && !selecting ? (ev) => { ev.dataTransfer.setData("text/plain", "cid:" + e.id); ev.dataTransfer.effectAllowed = "move"; } : undefined}
      onDragOver={(ev) => ev.preventDefault()}
      onDrop={(ev) => { ev.preventDefault(); const d = (ev.dataTransfer.getData("text/plain") || "").split(":"); if (d[0] === "cid" && d[1] && d[1] !== e.id) st.reorderEntry("content", d[1], e.id); }}
      className="tm-nav-item"
      onClick={selecting ? () => onToggleSel(e.id) : () => onOpen(e.id)}
      style={{ display: "flex", alignItems: "center", gap: 12, border: `1px solid ${selected || dragging ? t.accent : t.borderSoft}`, borderRadius: 10, margin: "8px 0", padding: "10px 12px", cursor: "pointer", background: selected ? hexA(t.accent, 0.07) : dragging ? hexA(t.accent, 0.08) : t.card, boxShadow: dragging ? t.shadowLift : t.shadow, transform: dragging ? "scale(1.008)" : "none", transition: "transform .12s ease, box-shadow .12s ease", userSelect: dragging ? "none" : "auto" }}
    >
      {selecting && <span style={{ width: 17, height: 17, flexShrink: 0, borderRadius: 6, border: `1.5px solid ${selected ? t.accent : t.border}`, background: selected ? t.accent : "transparent", color: t.bg, fontSize: 11, lineHeight: "15px", textAlign: "center" }}>{selected ? "✓" : ""}</span>}
      {e.icon
        ? <img src={imgSrc(e.icon)} alt="" style={{ width: 30, height: 40, objectFit: "cover", borderRadius: 5, flexShrink: 0, border: `1px solid ${t.borderSoft}` }} />
        : <span style={{ width: 30, flexShrink: 0, display: "inline-flex", justifyContent: "center", color: t.sand }}>{React.createElement(C_TYPE_GLYPH[e.type] || TmIcKniha, { size: 19 })}</span>}
      <span style={{ flex: 1, minWidth: 0 }}>
        <span style={{ display: "flex", alignItems: "center", gap: 8, minWidth: 0 }}>
          <span style={{ fontFamily: FONT_DISPLAY, fontSize: 17.5, color: t.heading, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{e.title}</span>
          <PinDot id={e.id} />
        </span>
        <span style={{ display: "flex", alignItems: "center", gap: 7, marginTop: 4, flexWrap: "wrap" }} onClick={(ev) => ev.stopPropagation()}>
          <button onClick={() => st.updateEntry("content", e.id, { progress: C_PROGRESS[(C_PROGRESS.indexOf(e.progress) + 1) % C_PROGRESS.length] })} title={L("Klikni a přepínej", "Click to cycle")} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0 }}>
            <Tag label={C_PROG_LABEL(e.progress, e.type)} color={C_PROG_COLOR[e.progress] || "default"} />
          </button>
          {e.category ? <Tag label={C_CAT_LABEL(e.category)} color="default" /> : null}
          {e.author ? <span style={{ fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", maxWidth: 180 }}>{e.author}</span> : null}
        </span>
      </span>
      <span title="/10" style={{ flexShrink: 0, fontFamily: FONT_DISPLAY, fontSize: 16.5, color: e.score ? t.sand : t.textMuted }}>{e.score || "—"}</span>
    </div>
  );
}

function PageContent() {
  const { t } = useT();
  const st = useStore();
  React.useEffect(() => { st.importContent(); st.migrateContentSchema(); }, []);
  const all = st.coll.content || [];
  const [view, setView] = useState("Vše");
  const [fProg, setFProg] = useState("Vše");
  const [fCat, setFCat] = useState("Vše");
  const [offlineOnly, setOfflineOnly] = useState(false);
  const [sortBy, setSortBy] = useState("manual");
  const [sel, setSel] = useState(null);   // drawer id
  const [full, setFull] = useState(null); // full-page id
  const [adding, setAdding] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newType, setNewType] = useState("Book");
  const [q, setQ] = useState("");
  const [qOpen, setQOpen] = useState(false);
  const [fOpen, setFOpen] = useState(false);
  const [selecting, setSelecting] = useState(false);
  const [selIds, setSelIds] = useState([]);
  const toggleSelC = (id) => setSelIds((xs) => xs.includes(id) ? xs.filter((x) => x !== id) : [...xs, id]);
  const exitSelectC = () => { setSelecting(false); setSelIds([]); };

  const TABS = ["Vše", ...C_TYPES];
  const live = all.filter((e) => !e.archive);
  let shown = view === "Archiv" ? all.filter((e) => e.archive) : view === "Vše" ? live : live.filter((e) => e.type === view);
  if (fProg !== "Vše") shown = shown.filter((e) => e.progress === fProg);
  if (fCat !== "Vše") shown = shown.filter((e) => e.category === fCat);
  const catOpts = Array.from(new Set(live.map((e) => e.category).filter(Boolean))).sort((a, b) => C_CAT_LABEL(a).localeCompare(C_CAT_LABEL(b), "cs"));
  const sorters = {
    score: (a, b) => (+(b.score || -1)) - (+(a.score || -1)),
    dateDesc: (a, b) => (b.dateFinished || "").localeCompare(a.dateFinished || ""),
    name: (a, b) => (a.title || "").localeCompare(b.title || "", "cs"),
    cat: (a, b) => (a.category || "").localeCompare(b.category || "") || (+(b.score || -1)) - (+(a.score || -1)),
  };
  if (sortBy !== "manual") shown = [...shown].sort(sorters[sortBy] || sorters.score);
  if (q.trim()) { const needle = q.trim().toLowerCase(); shown = shown.filter((e) => ((e.title || "") + " " + (e.author || "")).toLowerCase().includes(needle)); }
  if (offlineOnly) shown = shown.filter((e) => isEntryPinned(e.id));
  const counts = { "Vše": live.length, "Archiv": all.length - live.length };
  C_TYPES.forEach((x) => { counts[x] = live.filter((e) => e.type === x).length; });

  const addNew = () => {
    const v = newTitle.trim();
    if (!v) return;
    const id = uid();
    st.addEntry("content", { id, title: v, author: "", score: "", type: newType, progress: "Ready to start", category: (C_CATS_BY_TYPE[newType] || [])[0] || "", dateFinished: "", text: "", icon: null });
    setNewTitle(""); setAdding(false); setSel(id);
  };

  if (full) {
    return (
      <>
        <button onClick={() => setFull(null)} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "0 0 16px", display: "inline-flex", alignItems: "center", gap: 6 }}>‹ {L("Prameny", "Sources")}</button>
        <ContentDetail id={full} wide onClose={() => setFull(null)} />
      </>
    );
  }

  const cols = "minmax(200px, 1fr) 118px 112px 42px 128px";

  return (
    <>
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcPrameny size={38} /></span>} pageKey="prameny" kicker={L("Co si nést dál", "What to carry on")}>{L("Prameny", "Sources")}</PageTitle>
      {st.editMode && <p style={pProse(t)}><span style={{ color: t.textMuted }}>{L("Klik otevře detail · podrž a přetáhni ve vlastním pořadí · progress přepneš přímo v řádku.", "Click opens the detail · hold and drag in custom order · toggle progress right in the row.")}</span></p>}

      <div className="tm-typerow" style={{ display: "flex", gap: 2, flexWrap: "wrap", alignItems: "center", borderBottom: `1px solid ${t.border}`, marginBottom: 12 }}>
        {TABS.map((v) => (
          <button key={v} onClick={() => setView(v)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: "8px 10px 9px", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.08em", fontSize: 11.5, color: view === v ? t.accent : t.textMuted, borderBottom: view === v ? `2px solid ${t.accent}` : "2px solid transparent", marginBottom: -1 }}>
            {C_TYPES.includes(v) ? C_TYPE_LABEL(v) : LV(v)}<span style={{ marginLeft: 5, opacity: 0.6, fontSize: 10 }}>{counts[v] || 0}</span>
          </button>
        ))}
        <span style={{ flex: 1 }} />
        <span className="tm-deskonly" style={{ display: "inline-flex", alignItems: "center", gap: 6, borderBottom: `1px solid ${q ? t.accent : t.borderSoft}`, marginRight: 4, flexShrink: 0 }}><span style={{ color: t.textMuted, display: "inline-flex" }}><TmIcLupa size={13} /></span><input value={q} onChange={(e) => setQ(e.target.value)} placeholder={L("Hledat…", "Search…")} style={{ background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 13, outline: "none", padding: "4px 2px", width: 120 }} /></span>
        <button className="tm-monly" onClick={() => setQOpen((x) => !x)} title={L("Hledat", "Search")} style={{ display: "none", alignItems: "center", justifyContent: "center", width: 32, height: 32, flexShrink: 0, background: qOpen ? hexA(t.accent, 0.12) : "transparent", border: "none", borderRadius: 8, cursor: "pointer", color: qOpen ? t.accent : t.textMuted }}><TmIcLupa size={15} /></button>
        <button className="tm-monly" onClick={() => setFOpen((x) => !x)} title={L("Filtry a řazení", "Filters and sorting")} style={{ display: "none", alignItems: "center", justifyContent: "center", width: 32, height: 32, flexShrink: 0, background: fOpen ? hexA(t.accent, 0.12) : "transparent", border: "none", borderRadius: 8, cursor: "pointer", color: fOpen ? t.accent : t.textMuted, fontSize: 13 }}>▾</button>
      </div>
      {qOpen && (
        <div style={{ display: "flex", alignItems: "center", gap: 6, borderBottom: `1px solid ${q ? t.accent : t.borderSoft}`, margin: "0 0 12px", paddingBottom: 6 }}>
          <span style={{ color: t.textMuted, display: "inline-flex" }}><TmIcLupa size={13} /></span>
          <input autoFocus value={q} onChange={(e) => setQ(e.target.value)} placeholder={L("Hledat v pramenech…", "Search the sources…")} style={{ flex: 1, background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 13.5, outline: "none", padding: "4px 2px" }} />
        </div>
      )}
      <div className={"tm-cfilters" + (fOpen ? " open" : "")} style={{ display: "flex", gap: 8, alignItems: "center", margin: "10px 0 12px", flexWrap: "wrap" }}>
        <Select ghost value={fProg} onChange={setFProg} style={{ width: "auto" }} options={[{ v: "Vše", label: L("progress: vše", "progress: all") }, ...C_PROGRESS.map((p) => ({ v: p, label: C_PROG_LABEL(p).toLowerCase() }))]} />
        {catOpts.length > 0 && <Select ghost value={fCat} onChange={setFCat} style={{ width: "auto" }} options={[{ v: "Vše", label: L("žánr: vše", "genre: all") }, ...catOpts.map((c) => ({ v: c, label: C_CAT_LABEL(c) }))]} />}
        <Select ghost value={sortBy} onChange={setSortBy} style={{ width: "auto" }} options={[{ v: "manual", label: L("vlastní pořadí", "custom order") }, { v: "score", label: L("skóre", "score") }, { v: "dateDesc", label: L("nejnovější", "newest") }, { v: "cat", label: L("žánr", "genre") }, { v: "name", label: "A–Z" }]} />
        <button onClick={() => setOfflineOnly((x) => !x)} title={L("Zobrazit jen offline uložené", "Show only offline-saved")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: offlineOnly ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${offlineOnly ? t.accent : "transparent"}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: offlineOnly ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: offlineOnly ? t.accent : t.textMuted, flexShrink: 0 }} />offline</button>
        <button onClick={() => setView(view === "Archiv" ? "Vše" : "Archiv")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: view === "Archiv" ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${view === "Archiv" ? t.accent : "transparent"}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: view === "Archiv" ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}>{LV("Archiv")} {counts["Archiv"] || 0}</button>
        {st.editMode && <button onClick={() => selecting ? exitSelectC() : setSelecting(true)} style={{ background: selecting ? t.activeNav : "transparent", border: `1px solid ${selecting ? t.accent : t.border}`, borderRadius: 14, padding: "3px 12px", cursor: "pointer", color: selecting ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, marginLeft: 6 }}>{selecting ? L("Zrušit výběr", "Cancel selection") : L("☑ Vybrat", "☑ Select")}</button>}
      </div>

      {adding ? (
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center", background: t.callout, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12, marginBottom: 12 }}>
          <input autoFocus value={newTitle} onChange={(e) => setNewTitle(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") addNew(); }} placeholder={L("Název titulu…", "Title name…")} style={{ ...fieldStyle(t), flex: 1, minWidth: 180 }} />
          <Select value={newType} onChange={setNewType} style={{ maxWidth: 130, width: 130 }} options={C_TYPES.map((x) => ({ v: x, label: C_TYPE_LABEL(x) }))} />
          <button onClick={addNew} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13.5 }}>{L("Přidat", "Add")}</button>
          <button onClick={() => setAdding(false)} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "8px 16px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13.5 }}>{L("Zrušit", "Cancel")}</button>
        </div>
      ) : (
        <button onClick={() => setAdding(true)} className="tm-dash" style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "10px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 14, width: "100%", textAlign: "left", marginBottom: 12 }}>＋ {L("Nový titul", "New title")}</button>
      )}

      <div className="tm-scroll" style={{ marginTop: 6, maxHeight: "min(620px, 62vh)", overflowY: "auto", border: `1px solid ${t.borderSoft}`, borderRadius: 12, padding: "4px 10px 10px" }}>
        <div>
          {shown.map((e, i) => (
            <ContentRow key={e.id} e={e} cols={cols} last={i === shown.length - 1} onOpen={setSel} noDrag={sortBy !== "manual" || view !== "Vše" || fProg !== "Vše"} selecting={selecting} selected={selIds.includes(e.id)} onToggleSel={toggleSelC} />
          ))}
          {shown.length === 0 && <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13.5, color: t.textMuted, padding: "18px 14px" }}>{L("V tomto pohledu zatím nic není.", "Nothing in this view yet.")}</p>}
        </div>
      </div>

      {selecting && selIds.length > 0 && (
        <div style={{ position: "sticky", bottom: 16, display: "flex", alignItems: "center", gap: 10, background: t.bg, border: `1px solid ${t.border}`, borderRadius: 12, padding: "10px 14px", boxShadow: "0 10px 30px rgba(0,0,0,0.3)", zIndex: 50, flexWrap: "wrap", marginTop: 10 }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.heading }}>{selIds.length} {L("vybráno", "selected")}</span>
          <span style={{ flex: 1 }} />
          <button onClick={() => st.ask(L(`Přesunout ${selIds.length} titulů do koše?`, `Move ${selIds.length} titles to trash?`), () => { st.removeEntries("content", selIds); exitSelectC(); })} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13 }}>{L("Do koše", "To trash")}</button>
        </div>
      )}

      {sel && (
        <CenterSheet center title={(((st.coll.content || []).find((x) => x.id === sel) || {}).title) || L("Titul", "Title")} onClose={() => setSel(null)}>
          <ContentDetail id={sel} onClose={() => setSel(null)} onExpand={() => { setFull(sel); setSel(null); }} />
        </CenterSheet>
      )}
    </>
  );
}
// více štítků na jeden zápis · `tags` je zdroj pravdy, `tag` zůstává (první) kvůli zpětné kompatibilitě
const entryTags = (e) => (e && Array.isArray(e.tags) && e.tags.length) ? e.tags : (e && e.tag ? [e.tag] : []);
function NotebookCard({ entry, tags, selecting, selected, onToggleSel, onDragSel, noDrag, kind = "notebook", onExpand, full }) {
  const { t } = useT();
  const st = useStore();
  const [open, setOpen] = useState(false);
  const effOpen = full || open;
  const [over, setOver] = useState(false);
  const [tagPick, setTagPick] = useState(false);
  const taRef = React.useRef(null);
  const rootRef = React.useRef(null);
  const fileRef = React.useRef(null);
  const stRef = React.useRef(st); stRef.current = st;
  const selRef = React.useRef(selecting); selRef.current = selecting || !!noDrag;
  const autosize = () => { const el = taRef.current; if (el) { el.style.height = "auto"; el.style.height = el.scrollHeight + 2 + "px"; } };
  React.useEffect(() => { if (effOpen) autosize(); }, [effOpen]);

  const onOverRef = React.useRef(null);
  onOverRef.current = (overId) => stRef.current.reorderEntry(kind, entry.id, overId);
  const isTouchDraggingLocal = useHoldReorder(rootRef, entry.id, "data-card-" + kind, onOverRef, selRef);

  const attachFiles = async (fileList) => {
    const added = await filesToAtts(fileList, st.ask);
    if (added.length) { st.updateEntry(kind, entry.id, { att: [...(entry.att || []), ...added] }); setOpen(true); }
    if (fileRef.current) fileRef.current.value = "";
  };

  const colorOf = (name) => ((tags.find((x) => x[0] === name)) || [])[1] || "default";
  const selTags = entryTags(entry);
  const toggleTag = (name) => { const cur = entryTags(entry); const next = cur.includes(name) ? cur.filter((x) => x !== name) : [...cur, name]; st.updateEntry(kind, entry.id, { tags: next, tag: next[0] || "" }); };
  const isTouchDragging = isTouchDraggingLocal;
  const preview = (entry.text || "").split("\n").filter(Boolean).slice(0, 2).join(" · ");
  return (
    <div
      ref={rootRef}
      className={effOpen || selecting ? undefined : kind === "journal" ? "tm-grow" : "tm-lift"}
      {...{ ["data-card-" + kind]: entry.id }}
      draggable={!selecting && !noDrag && !full}
      onDragStart={!selecting ? (e) => { e.dataTransfer.setData("text/plain", "card-" + kind + ":" + entry.id); e.dataTransfer.effectAllowed = "move"; } : undefined}
      onDragOver={(e) => { e.preventDefault(); setOver(true); }}
      onDragLeave={() => setOver(false)}
      onDrop={(e) => { e.preventDefault(); setOver(false); const d = (e.dataTransfer.getData("text/plain") || "").split(":"); if (d[0] === "card-" + kind && d[1] && d[1] !== entry.id) st.reorderEntry(kind, d[1], entry.id); }}
      onMouseDown={selecting ? () => onToggleSel(entry.id) : undefined}
      onMouseEnter={selecting ? (e) => { if (e.buttons === 1) onDragSel(entry.id); } : undefined}
      style={{ border: `1px solid ${isTouchDragging ? t.accent : selected ? t.accent : over ? t.sage : t.borderSoft}`, borderRadius: 10, margin: "8px 0", overflow: "hidden", background: isTouchDragging ? hexA(t.accent, 0.09) : selected ? hexA(t.accent, 0.07) : t.sheet, boxShadow: isTouchDragging ? "0 8px 22px rgba(0,0,0,0.28)" : effOpen ? t.shadow : "none", transform: isTouchDragging ? "scale(1.015)" : "none", transition: "border-color .12s ease, background .12s ease, transform .12s ease, box-shadow .12s ease", userSelect: selecting || isTouchDragging ? "none" : "auto" }}
    >
      <div style={{ display: "flex", alignItems: "flex-start", gap: 10, padding: "12px 12px 12px 14px" }}>
        {selecting && (
          <span style={{ width: 17, height: 17, marginTop: 3, borderRadius: 6, flexShrink: 0, border: `1.5px solid ${selected ? t.accent : t.border}`, background: selected ? t.accent : "transparent", color: t.bg, fontSize: 11, lineHeight: "15px", textAlign: "center" }}>{selected ? "✓" : ""}</span>
        )}
        {effOpen && !selecting ? (
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
              <input value={entry.title} onChange={(e) => st.updateEntry(kind, entry.id, { title: e.target.value })} placeholder={kind === "journal" ? L("Název (nepovinný)…", "Title (optional)…") : L("Název…", "Title…")} style={{ flex: 1, minWidth: 160, background: "transparent", border: "none", borderBottom: `1px dashed ${hexA(t.textMuted, 0.35)}`, fontFamily: FONT_DISPLAY, fontSize: full ? 26 : 18, color: t.heading, outline: "none", padding: "0 0 2px" }} />
              <button onClick={() => setTagPick((x) => !x)} title={L("Změnit kategorie", "Change categories")} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0, display: "inline-flex", gap: 5, flexWrap: "wrap" }}>{selTags.length ? selTags.map((n) => <Tag key={n} label={n} color={colorOf(n)} />) : <Tag label={L("+ štítek", "+ tag")} color="default" />}</button>
              <input type="date" value={entry.date || ""} onChange={(e) => st.updateEntry(kind, entry.id, { date: e.target.value })} title={L("Datum poznámky — podle něj se řadí", "Note date — used for sorting")} style={{ background: "transparent", border: "none", color: entry.date ? t.textMuted : hexA(t.textMuted, 0.5), fontFamily: FONT_BODY, fontSize: 11.5, outline: "none", padding: 0, colorScheme: t.mode === "light" ? "light" : "dark", width: 110 }} />
            </div>
            {tagPick && (
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginTop: 8 }}>
                {tags.map(([label, color]) => (
                  <button key={label} onClick={() => toggleTag(label)} style={{ border: "none", cursor: "pointer", background: "transparent", padding: 0, opacity: selTags.includes(label) ? 1 : 0.4 }}><Tag label={label} color={color} /></button>
                ))}
              </div>
            )}
          </div>
        ) : (
          <button onClick={() => { if (selecting) return; if (!full && onExpand) onExpand(entry.id); else setOpen(true); }} style={{ flex: 1, minWidth: 0, textAlign: "left", background: "transparent", border: "none", cursor: "pointer", padding: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
              {kind === "journal"
                ? <><span style={{ fontFamily: FONT_DISPLAY, fontSize: 18, color: t.heading }}>{entry.date ? fmtCZ(entry.date) : (entry.title || L("Bez data", "No date"))}</span>
                  {entry.title && entry.date && <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textSec }}>{entry.title}</span>}</>
                : <span style={{ fontFamily: FONT_DISPLAY, fontSize: 18, color: t.heading }}>{entry.title}</span>}
              <PinDot id={entry.id} />
              {selTags.map((n) => <Tag key={n} label={n} color={colorOf(n)} />)}
              {kind !== "journal" && entry.date && <span style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted }}>{entry.date}</span>}
            </div>
            {preview && <div className={kind === "journal" ? "tm-jsnip" : undefined} style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textMuted, marginTop: 4, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{preview}</div>}
          </button>
        )}
        {!selecting && (
          <span style={{ display: "flex", gap: 5, flexShrink: 0, alignItems: "center" }}>
            {full && <PinToggle entry={entry} />}
            {open && !full && <button title="Sbalit" onClick={() => { setOpen(false); setTagPick(false); }} style={{ ...iconBtn(t), border: "none", color: t.textMuted }}>▴</button>}
            <button title={entry.star ? L("Odebrat hvězdičku", "Remove star") : L("Označit hvězdičkou", "Star it")} onClick={() => st.updateEntry(kind, entry.id, { star: !entry.star })} style={{ ...iconBtn(t), border: "none", color: entry.star ? t.accent : t.textMuted, opacity: entry.star ? 1 : 0.55, fontSize: 14 }}>{entry.star ? "★" : "☆"}</button>
            <input ref={fileRef} type="file" multiple onChange={(e) => attachFiles(e.target.files)} style={{ display: "none" }} />
            <button title={L("Přiložit obrázek / soubor", "Attach image / file")} onClick={() => fileRef.current && fileRef.current.click()} className={kind === "journal" && !effOpen ? "tm-mhide" : undefined} style={{ ...iconBtn(t), border: "none", color: t.textMuted, display: "inline-flex", alignItems: "center", justifyContent: "center" }}><ClipIcon /></button>
            {(st.editMode || full) && <button title={L("Do koše", "To trash")} onClick={() => st.ask(L(`Přesunout „${entry.title}" do koše?`, `Move "${entry.title}" to trash?`), () => st.removeEntry(kind, entry.id))} style={{ ...iconBtn(t), border: "none", color: t.textMuted }}>✕</button>}
          </span>
        )}
      </div>
      {effOpen && !selecting && (
        <div style={{ padding: "2px 16px 16px 14px" }}>
          <RichArea value={entry.text || ""} onChange={(v) => st.updateEntry(kind, entry.id, { text: v })} />
          <AttachmentStrip att={entry.att} onRemove={st.editMode ? ((id) => st.updateEntry(kind, entry.id, { att: (entry.att || []).filter((x) => x.id !== id) })) : undefined} />
        </div>
      )}
    </div>
  );
}

function NbTagRow({ n, c, ops, renaming, setRenaming, newName, setNewName }) {
  const { t } = useT();
  const st = useStore();
  const rowRef = React.useRef(null);
  const onOverRef = React.useRef(null);
  onOverRef.current = (overName) => ops.reorder(n, overName);
  const dragging = useHoldReorder(rowRef, n, ops.attr, onOverRef, null);
  const attrProps = { [ops.attr]: n };
  return (
    <div
      ref={rowRef}
      {...attrProps}
      draggable
      onDragStart={(e) => { e.dataTransfer.setData("text/plain", ops.attr + ":" + n); }}
      onDragOver={(e) => e.preventDefault()}
      onDrop={(e) => { e.preventDefault(); const idx = (e.dataTransfer.getData("text/plain") || "").lastIndexOf(":"); const pref = (e.dataTransfer.getData("text/plain") || "").slice(0, idx); const dn = (e.dataTransfer.getData("text/plain") || "").slice(idx + 1); if (pref === ops.attr && dn && dn !== n) ops.reorder(dn, n); }}
      style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 2px", borderBottom: `1px solid ${t.borderSoft}`, background: dragging ? hexA(t.accent, 0.08) : "transparent", borderRadius: dragging ? 6 : 0, cursor: "grab", userSelect: dragging ? "none" : "auto" }}
    >
      {renaming === n ? (
        <>
          <input autoFocus value={newName} onChange={(e) => setNewName(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter" && newName.trim()) { ops.rename(n, newName.trim()); setRenaming(null); } if (e.key === "Escape") setRenaming(null); }} style={{ ...fieldStyle(t), padding: "4px 8px", fontSize: 13, flex: 1 }} />
          <button onClick={() => { if (newName.trim()) { ops.rename(n, newName.trim()); } setRenaming(null); }} style={{ ...iconBtn(t), border: "none", color: t.sand }}>✓</button>
        </>
      ) : (
        <>
          <span style={{ flex: 1 }}><Tag label={n} color={c} /></span>
          {n !== ops.protectedName && <button title={L("Přejmenovat", "Rename")} onClick={() => { setRenaming(n); setNewName(n); }} style={{ ...iconBtn(t), border: "none", color: t.textMuted }}>✎</button>}
          {n !== ops.protectedName && <button title={L(`Smazat kategorii — položky přejdou do ${ops.protectedName}`, `Delete category — items move to ${ops.protectedName}`)} onClick={() => st.ask(L(`Smazat kategorii „${n}"? Položky přejdou do ${ops.protectedName}.`, `Delete category "${n}"? Items move to ${ops.protectedName}.`), () => ops.remove(n))} style={{ ...iconBtn(t), border: "none", color: t.textMuted }}>✕</button>}
        </>
      )}
    </div>
  );
}

function NbTagManager({ ops, onDone }) {
  const { t, tags } = useT();
  const st = useStore();
  const list = ops.list;
  const [name, setName] = useState("");
  const [color, setColor] = useState("green");
  const COLORS = ["stone", "sage", "moss", "sand", "taupe", "ochre", "burgundy", "rose"];
  const [renaming, setRenaming] = useState(null);
  const [newName, setNewName] = useState("");
  return (
    <div style={{ background: t.callout, border: `1px solid ${t.border}`, borderRadius: 10, padding: 14, marginBottom: 12 , boxShadow: t.shadow }}>
      <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 11, color: t.sage, marginBottom: 10 }}>Kategorie</div>
      {list.map(([n, c]) => (
        <NbTagRow key={n} n={n} c={c} ops={ops} renaming={renaming} setRenaming={setRenaming} newName={newName} setNewName={setNewName} />
      ))}
      <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 12, flexWrap: "wrap" }}>
        <input value={name} onChange={(e) => setName(e.target.value)} placeholder={L("Nová kategorie…", "New category…")} onKeyDown={(e) => { if (e.key === "Enter" && name.trim()) { ops.add(name.trim(), color); setName(""); } }} style={{ ...fieldStyle(t), padding: "6px 10px", fontSize: 13, flex: 1, minWidth: 150 }} />
        <span style={{ display: "inline-flex", gap: 5 }}>
          {COLORS.map((c) => (
            <button key={c} title={c} onClick={() => setColor(c)} style={{ width: 16, height: 16, borderRadius: "50%", cursor: "pointer", background: (tags[c] || tags.default).fg, border: color === c ? `2px solid ${t.heading}` : "2px solid transparent", padding: 0 }} />
          ))}
        </span>
        <button onClick={() => { if (name.trim()) { ops.add(name.trim(), color); setName(""); } }} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "6px 14px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13 }}>{L("Přidat", "Add")}</button>
        <button onClick={onDone} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13 }}>{L("Hotovo", "Done")}</button>
      </div>
    </div>
  );
}

function PageNotebook() {
  const { t } = useT();
  const st = useStore();
  React.useEffect(() => { st.importNotebook(); st.migrateCzNotebook(); }, []);
  React.useEffect(() => { if (st.coll.nbImported) st.importPractices(); }, [st.coll.nbImported]);
  const tags = st.nbTags();
  const all = st.coll.notebook || [];
  const [qOpen, setQOpen] = useState(false);
  const [fOpen, setFOpen] = useState(false);
  const [view, setView] = useState("Vše");
  const [selecting, setSelecting] = useState(false);
  const [sel, setSel] = useState([]);
  const [quick, setQuick] = useState("");
  const [managing, setManaging] = useState(false);
  const [moveTag, setMoveTag] = useState("");
  const [offlineOnly, setOfflineOnly] = useState(false);
  const [sortBy, setSortBy] = useState("manual");
  const [full, setFull] = useState(null);
  const [q, setQ] = useState("");

  let shown = view === "Vše" ? all : all.filter((e) => entryTags(e).includes(view));
  if (q.trim()) { const nq = tmNorm(q); shown = shown.filter((e) => tmNorm((e.title || "") + " " + (e.text || "")).includes(nq)); }
  if (sortBy === "dateDesc") shown = [...shown].sort((a, b) => (b.date || "").localeCompare(a.date || ""));
  if (sortBy === "dateAsc") shown = [...shown].sort((a, b) => (a.date || "9999").localeCompare(b.date || "9999"));
  shown = [...shown.filter((e) => e.star), ...shown.filter((e) => !e.star)];
  const toggleSel = (id) => setSel((xs) => xs.includes(id) ? xs.filter((x) => x !== id) : [...xs, id]);
  const dragSel = (id) => setSel((xs) => xs.includes(id) ? xs : [...xs, id]);
  const exitSelect = () => { setSelecting(false); setSel([]); setMoveTag(""); };

  const saveQuick = () => {
    const v = quick.trim();
    if (!v) return;
    const title = v.length > 46 ? v.slice(0, 44).trimEnd() + "…" : v;
    st.addEntry("notebook", { id: uid(), date: todayISO(), title, tag: "Poznámky", text: v });
    setQuick("");
  };

  const counts = { "Vše": all.length };
  tags.forEach(([n]) => { counts[n] = all.filter((e) => entryTags(e).includes(n)).length; });

  if (offlineOnly) shown = shown.filter((e) => isEntryPinned(e.id));
  const fullEntry = full ? all.find((e) => e.id === full) : null;

  return (
    <>
      {fullEntry && (
        <CenterSheet title={fullEntry.title || (fullEntry.date ? fmtCZ(fullEntry.date) : L("Poznámka", "Note"))} onClose={() => setFull(null)}>
          <NotebookCard entry={fullEntry} tags={tags} full />
        </CenterSheet>
      )}
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcZapisnik size={38} /></span>} pageKey="zapisnik" kicker={L("Jeden prostor pro cokoliv", "One space for anything")}>{L("Zápisník", "Notebook")}</PageTitle>
      {st.editMode && <p style={pProse(t)}><span style={{ color: t.textMuted }}>{L("Klik otevře a rovnou píšeš · podrž a přetáhni · výběrem označíš víc najednou.", "Click opens and you write right away · hold and drag · select to mark several at once.")}</span></p>}

      <div style={{ display: "flex", gap: 10, alignItems: "center", background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "10px 14px", marginBottom: 14 }}>
        <span style={{ color: t.sand, display: "inline-flex" }}><PenIcon size={14} /></span>
        <input value={quick} onChange={(e) => setQuick(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") saveQuick(); }} placeholder={L("Rychlá poznámka… (Enter uloží do Poznámek)", "Quick note… (Enter saves it)")} style={{ flex: 1, background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 14.5, outline: "none" }} />
        {quick.trim() && <button onClick={saveQuick} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "5px 13px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Uložit", "Save")}</button>}
      </div>

      <div className="tm-typerow" style={{ display: "flex", gap: 2, flexWrap: "wrap", alignItems: "center", borderBottom: `1px solid ${t.border}`, marginBottom: 12 }}>
        <span className="tm-deskonly" style={{ display: "inline-flex", alignItems: "center", gap: 6, borderBottom: `1px solid ${q ? t.accent : t.borderSoft}`, marginRight: 6 }}><span style={{ color: t.textMuted, display: "inline-flex" }}><TmIcLupa size={13} /></span><input value={q} onChange={(e) => setQ(e.target.value)} placeholder={L("Hledat…", "Search…")} style={{ background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 13, outline: "none", padding: "4px 2px", width: 110 }} /></span>
        {["Vše", ...tags.map(([n]) => n)].map((v) => (
          <button key={v} onClick={() => setView(v)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: "8px 10px 9px", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.08em", fontSize: 11.5, color: view === v ? t.accent : t.textMuted, borderBottom: view === v ? `2px solid ${t.accent}` : "2px solid transparent", marginBottom: -1 }}>
            {LV(v)}<span style={{ marginLeft: 5, opacity: 0.6, fontSize: 10 }}>{counts[v] || 0}</span>
          </button>
        ))}
        <span style={{ flex: 1 }} />
        <button className="tm-monly" onClick={() => setQOpen((x) => !x)} title={L("Hledat", "Search")} style={{ display: "none", alignItems: "center", justifyContent: "center", width: 32, height: 32, flexShrink: 0, background: qOpen ? hexA(t.accent, 0.12) : "transparent", border: "none", borderRadius: 8, cursor: "pointer", color: qOpen ? t.accent : t.textMuted }}><TmIcLupa size={15} /></button>
        <button className="tm-monly" onClick={() => setFOpen((x) => !x)} title={L("Filtry a řazení", "Filters and sorting")} style={{ display: "none", alignItems: "center", justifyContent: "center", width: 32, height: 32, flexShrink: 0, background: fOpen ? hexA(t.accent, 0.12) : "transparent", border: "none", borderRadius: 8, cursor: "pointer", color: fOpen ? t.accent : t.textMuted, fontSize: 13 }}>▾</button>
        <span className="tm-deskonly" style={{ display: "contents" }}>
        <button onClick={() => setOfflineOnly((x) => !x)} title={L("Zobrazit jen offline uložené", "Show only offline-saved")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: offlineOnly ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${offlineOnly ? t.accent : "transparent"}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: offlineOnly ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: offlineOnly ? t.accent : t.textMuted, flexShrink: 0 }} />offline</button>
        <Select ghost value={sortBy} onChange={setSortBy} style={{ width: "auto" }} options={[{ v: "manual", label: L("vlastní pořadí", "custom order") }, { v: "dateDesc", label: L("nejnovější", "newest") }, { v: "dateAsc", label: L("nejstarší", "oldest") }]} />
        </span>
        <button title="Spravovat kategorie" onClick={() => setManaging((x) => !x)} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontSize: 14, padding: "4px 8px" }}>⋯</button>
        {st.editMode && <button onClick={() => selecting ? exitSelect() : setSelecting(true)} style={{ background: selecting ? t.activeNav : "transparent", border: `1px solid ${selecting ? t.accent : t.border}`, borderRadius: 14, padding: "3px 12px", cursor: "pointer", color: selecting ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, marginLeft: 6 }}>{selecting ? L("Zrušit výběr", "Cancel selection") : L("☑ Vybrat", "☑ Select")}</button>}
      </div>

      {qOpen && (
        <div style={{ display: "flex", alignItems: "center", gap: 6, borderBottom: `1px solid ${q ? t.accent : t.borderSoft}`, margin: "0 0 12px", paddingBottom: 6 }}>
          <span style={{ color: t.textMuted, display: "inline-flex" }}><TmIcLupa size={13} /></span>
          <input autoFocus value={q} onChange={(e) => setQ(e.target.value)} placeholder={L("Hledat v zápisníku…", "Search the notebook…")} style={{ flex: 1, background: "transparent", border: "none", color: t.text, fontFamily: FONT_BODY, fontSize: 13.5, outline: "none", padding: "4px 2px" }} />
        </div>
      )}
      {fOpen && (
        <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 8, margin: "0 0 12px" }}>
          <button onClick={() => setOfflineOnly((x) => !x)} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: offlineOnly ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${offlineOnly ? t.accent : t.borderSoft}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: offlineOnly ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: offlineOnly ? t.accent : t.textMuted, flexShrink: 0 }} />offline</button>
          <Select ghost value={sortBy} onChange={setSortBy} style={{ width: "auto" }} options={[{ v: "manual", label: L("vlastní pořadí", "custom order") }, { v: "dateDesc", label: L("nejnovější", "newest") }, { v: "dateAsc", label: L("nejstarší", "oldest") }]} />
        </div>
      )}

      {managing && <NbTagManager onDone={() => setManaging(false)} ops={{ list: tags, add: st.addNbTag, rename: st.renameNbTag, reorder: st.reorderNbTag, remove: st.removeNbTag, protectedName: "Poznámky", attr: "data-nbtag" }} />}
      {!selecting && <AddEntry kind="notebook" tags={tags} label={L("Nová poznámka", "New note")} />}

      <div className="tm-scroll" style={{ marginTop: 18, maxHeight: "min(620px, 62vh)", overflowY: "auto", border: `1px solid ${t.borderSoft}`, borderRadius: 12, padding: "4px 10px 10px" }}>
        {shown.map((e) => (
          <NotebookCard key={e.id} entry={e} tags={tags} selecting={selecting} selected={sel.includes(e.id)} onToggleSel={toggleSel} onDragSel={dragSel} noDrag={sortBy !== "manual"} onExpand={setFull} />
        ))}
        {shown.length === 0 && <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13.5, color: t.textMuted, padding: "18px 0" }}>{L("V této kategorii zatím nic není.", "Nothing in this category yet.")}</p>}
      </div>

      {selecting && sel.length > 0 && (
        <div style={{ position: "sticky", bottom: 16, display: "flex", alignItems: "center", gap: 10, background: t.bg, border: `1px solid ${t.border}`, borderRadius: 12, padding: "10px 14px", boxShadow: "0 10px 30px rgba(0,0,0,0.3)", zIndex: 50, flexWrap: "wrap" }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.heading }}>{sel.length} {L("vybráno", "selected")}</span>
          <span style={{ flex: 1 }} />
          <Select small value={moveTag} onChange={(v) => { st.setEntriesTag("notebook", sel, v); exitSelect(); }} placeholder={L("Přesunout do…", "Move to…")} style={{ maxWidth: 170, width: 170 }} options={tags.map(([n]) => n)} />
          <button onClick={() => st.ask(L(`Přesunout ${sel.length} poznámek do koše?`, `Move ${sel.length} notes to trash?`), () => { st.removeEntries("notebook", sel); exitSelect(); })} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13 }}>{L("Do koše", "To trash")}</button>
        </div>
      )}
    </>
  );
}

const JARS = [
  ["NEC", "Necessities", 55],
  ["FFA", "Financial Freedom", 10],
  ["LTSS", "Long-term Savings", 10],
  ["EDU", "Education", 10],
  ["PLAY", "Play", 10],
  ["GIVE", "Give", 5],
];
const money = (n) => (Number(n) || 0).toLocaleString("cs-CZ") + " Kč";
// ---- finance date helpers · rows use ISO dates, Notion archive may use "d. m. yyyy" ----
const finMonthKey = (d) => {
  const s = String(d || "");
  const iso = s.match(/^(\d{4})-(\d{2})/);
  if (iso) return iso[1] + "-" + iso[2];
  const cz = s.match(/^(\d{1,2})\.\s*(\d{1,2})\.\s*(\d{4})/);
  if (cz) return cz[3] + "-" + String(cz[2]).padStart(2, "0");
  return "";
};
const finShortDate = (d) => { const m = String(d || "").match(/^(\d{4})-(\d{2})-(\d{2})/); return m ? (+m[3]) + ". " + (+m[2]) + "." : String(d || ""); };
const MONTHS_CZ = () => L(["leden", "únor", "březen", "duben", "květen", "červen", "červenec", "srpen", "září", "říjen", "listopad", "prosinec"], ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"]);
const MONTHS_CZ_SHORT = () => L(["led", "úno", "bře", "dub", "kvě", "čvn", "čvc", "srp", "zář", "říj", "lis", "pro"], ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"]);
const finShiftMonth = (ym, dir) => { const [y, m] = ym.split("-").map(Number); const d = new Date(y, m - 1 + dir, 1); return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0"); };
const finThisMonth = () => todayISO().slice(0, 7);
const finSum = (rows) => rows.reduce((s, r) => s + (parseFloat(r.amount) || 0), 0);

function LedgerForm({ fields, initial, onSave, onCancel }) {
  const { t } = useT();
  const [vals, setVals] = useState(() => { const o = { date: (initial && initial.date) || todayISO() }; fields.forEach((f) => { o[f.key] = (initial && initial[f.key] != null) ? initial[f.key] : (f.type === "select" ? f.options[0] : ""); }); return o; });
  const setV = (k, v) => setVals((s) => ({ ...s, [k]: v }));
  return (
    <div style={{ background: t.card, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12, margin: "8px 0" }}>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
        <input type="date" value={vals.date} onChange={(e) => setV("date", e.target.value)} style={{ ...fieldStyle(t), maxWidth: 160, colorScheme: t.mode === "light" ? "light" : "dark" }} />
        {fields.map((f) => f.type === "select" ? (
          <Select key={f.key} value={vals[f.key]} onChange={(v) => setV(f.key, v)} style={{ maxWidth: 140, width: 140 }} options={f.options} />
        ) : (
          <input key={f.key} type={f.type === "number" ? "number" : "text"} value={vals[f.key]} onChange={(e) => setV(f.key, e.target.value)} placeholder={f.label} style={{ ...fieldStyle(t), maxWidth: f.type === "number" ? 130 : undefined, flex: f.type === "text" ? "1 1 140px" : undefined }} />
        ))}
      </div>
      <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
        <button onClick={() => onSave(vals)} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "7px 15px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14, fontWeight: 500 }}>{L("Uložit", "Save")}</button>
        <button onClick={onCancel} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "7px 15px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 14 }}>{L("Zrušit", "Cancel")}</button>
      </div>
    </div>
  );
}

function LedgerSection({ kind, fields, addLabel, seed, month }) {
  const { t } = useT();
  const st = useStore();
  const inMonth = (r) => !month || finMonthKey(r.date) === month;
  const rows = (st.coll[kind] || []).filter(inMonth);
  const seedRows = (seed || []).filter(inMonth);
  const [adding, setAdding] = useState(false);
  const [editId, setEditId] = useState(null);
  const textFields = fields.filter((f) => f.key !== "amount" && f.key !== "jar");
  const hasJar = fields.some((f) => f.key === "jar");
  const total = finSum([...rows, ...seedRows]);
  const em = st.editMode;
  return (
    <div>
      {rows.length + seedRows.length === 0 && !adding && <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted, padding: "6px 0" }}>{L("V tomto měsíci zatím nic.", "Nothing this month yet.")}</div>}
      {rows.map((r) => em && editId === r.id ? (
        <LedgerForm key={r.id} fields={fields} initial={r} onSave={(v) => { st.updateEntry(kind, r.id, v); setEditId(null); }} onCancel={() => setEditId(null)} />
      ) : (
        <div key={r.id} style={{ display: "grid", gridTemplateColumns: "44px 1fr auto auto", alignItems: "center", gap: 10, padding: "9px 2px", borderBottom: `1px solid ${t.borderSoft}` }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textMuted }}>{finShortDate(r.date)}</span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.text, minWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
            {textFields.map((f) => r[f.key]).filter(Boolean).join(" · ")}
            {hasJar && r.jar && <span style={{ marginLeft: 7, fontFamily: FONT_TAG, letterSpacing: "0.06em", fontSize: 10.5, color: t.sage, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "1px 7px", verticalAlign: "1px" }}>{r.jar}</span>}
          </span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.heading, fontWeight: 500 }}>{money(r.amount)}</span>
          <span style={{ display: "flex", gap: 5 }}>
            {em && <button title="Upravit" onClick={() => setEditId(r.id)} style={iconBtn(t)}>✎</button>}
            {em && <button title={L("Smazat", "Delete")} onClick={() => st.ask(L("Smazat záznam?", "Delete record?"), () => st.removeEntry(kind, r.id))} style={{ ...iconBtn(t), border: "none", color: t.textMuted }}>✕</button>}
          </span>
        </div>
      ))}
      {seedRows.map((r, i) => (
        <div key={"s" + i} style={{ display: "grid", gridTemplateColumns: "44px 1fr auto", alignItems: "center", gap: 10, padding: "9px 2px", borderBottom: `1px solid ${t.borderSoft}`, opacity: 0.7 }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.textMuted }}>{finShortDate(r.date)}</span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.textSec }}>{textFields.map((f) => r[f.key]).filter(Boolean).join(" · ")} <span style={{ fontSize: 11, color: t.textMuted }}>· z Notionu</span></span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.textSec }}>{money(r.amount)}</span>
        </div>
      ))}
      {adding ? (
        <LedgerForm fields={fields} onSave={(v) => { st.addEntry(kind, { id: uid(), ...v }); setAdding(false); }} onCancel={() => setAdding(false)} />
      ) : (
        <button onClick={() => setAdding(true)} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "9px 13px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 13.5, marginTop: 8 }}>＋ {addLabel}</button>
      )}
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 10, paddingTop: 8, borderTop: `1px solid ${t.border}` }}>
        <span style={{ ...subLabel(t), marginBottom: 0 }}>Celkem{month ? " · " + MONTHS_CZ()[+month.split("-")[1] - 1] : ""}</span>
        <span style={{ fontFamily: FONT_DISPLAY, fontSize: 18, color: t.heading }}>{money(total)}</span>
      </div>
    </div>
  );
}

function Jars({ month }) {
  const { t } = useT();
  const st = useStore();
  const em = st.editMode;
  const pctCfg = (st.coll.finCfg || {}).jarPct || {};
  const pctOf = (code, dflt) => (pctCfg[code] != null ? pctCfg[code] : dflt);
  const inMonth = (r) => finMonthKey(r.date) === month;
  const income = finSum((st.coll.income || []).filter(inMonth));
  const expenses = (st.coll.expenses || []).filter(inMonth);
  const sumPct = JARS.reduce((s, [c, , d]) => s + (parseFloat(pctOf(c, d)) || 0), 0);
  const setPct = (code, v) => st.setFinCfg({ jarPct: { ...pctCfg, [code]: Math.max(0, Math.min(100, parseFloat(v) || 0)) } });
  return (
    <div>
      {JARS.map(([code, name, dfltPct]) => {
        const pct = pctOf(code, dfltPct);
        const alloc = (income * pct) / 100;
        const spent = finSum(expenses.filter((e) => e.jar === code));
        const frac = alloc > 0 ? Math.min(1, spent / alloc) : (spent > 0 ? 1 : 0);
        const over = alloc > 0 && spent > alloc;
        return (
          <div key={code} style={{ padding: "10px 0", borderBottom: `1px solid ${t.borderSoft}` }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", flexWrap: "wrap", gap: "2px 10px", marginBottom: 5 }}>
              <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.text }}>
                <b style={{ color: t.accent, fontFamily: FONT_TAG, letterSpacing: "0.05em" }}>{code}</b> · {name}{" "}
                {em
                  ? <span style={{ whiteSpace: "nowrap" }}><input type="number" value={pct} onChange={(e) => setPct(code, e.target.value)} style={{ ...fieldStyle(t), width: 52, padding: "2px 6px", fontSize: 12.5, textAlign: "right" }} /><span style={{ color: t.textMuted, fontSize: 12 }}> %</span></span>
                  : <span style={{ color: t.textMuted, fontSize: 12 }}>{pct}%</span>}
              </span>
              <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: over ? t.accent : t.textSec }}>{money(spent)} / {money(alloc)}{over && L(" · přes limit", " · over limit")}</span>
            </div>
            <ProgressBar value={frac} />
          </div>
        );
      })}
      {em && sumPct !== 100 && <p style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: t.accent, marginTop: 8 }}>{L("Součet sklenic je", "Jars add up to")} {sumPct} % — {L("má být 100 %.", "should be 100 %.")}</p>}
      {income === 0 && <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 12.5, color: t.textMuted, marginTop: 10 }}>{L("Přidej příjem za tento měsíc a sklenice se rozpočítají.", "Add this month's income and the jars will be allocated.")}</p>}
    </div>
  );
}

// ---- Quick expense · lowest possible friction, saves to today ----
function QuickExpense() {
  const { t } = useT();
  const st = useStore();
  const [amount, setAmount] = useState("");
  const [item, setItem] = useState("");
  const lastJar = (st.coll.finCfg || {}).lastJar || "NEC";
  const [jar, setJar] = useState(lastJar);
  const save = () => {
    const a = parseFloat(amount);
    if (!a || a <= 0) return;
    st.addEntry("expenses", { id: uid(), date: todayISO(), item: item.trim() || "—", jar, amount: a });
    st.setFinCfg({ lastJar: jar });
    setAmount(""); setItem("");
  };
  const onKey = (e) => { if (e.key === "Enter") save(); };
  return (
    <div style={{ boxShadow: t.shadow, background: t.card, border: `1px solid ${t.borderSoft}`, borderLeft: `3px solid ${t.accent}`, borderRadius: 10, padding: "12px 14px", marginBottom: 14 }}>
      <div style={{ ...subLabel(t), marginBottom: 8 }}>{L("Rychlý výdaj · dnes", "Quick expense · today")}</div>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
        <input type="number" inputMode="decimal" value={amount} onChange={(e) => setAmount(e.target.value)} onKeyDown={onKey} placeholder="Kč" style={{ ...fieldStyle(t), width: 96, fontFamily: FONT_DISPLAY, fontSize: 17 }} />
        <input value={item} onChange={(e) => setItem(e.target.value)} onKeyDown={onKey} placeholder="za co…" style={{ ...fieldStyle(t), flex: "1 1 140px", minWidth: 120 }} />
        {amount && <button onClick={save} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "7px 15px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13.5, fontWeight: 500 }}>{L("Uložit", "Save")}</button>}
      </div>
      <div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginTop: 9 }}>
        {JARS.map(([code, name]) => (
          <button key={code} title={name} onClick={() => setJar(code)} style={{ background: jar === code ? hexA(t.accent, 0.14) : "transparent", border: `1px solid ${jar === code ? t.accent : t.borderSoft}`, borderRadius: 12, padding: "3px 11px", cursor: "pointer", color: jar === code ? t.accent : t.textMuted, fontFamily: FONT_TAG, letterSpacing: "0.08em", fontSize: 11 }}>{code}</button>
        ))}
      </div>
    </div>
  );
}

function WishRow({ r, buy, letGo }) {
  const { t } = useT();
  const st = useStore();
  const rootRef = React.useRef(null);
  const [over, setOver] = useState(false);
  const onOverRef = React.useRef(null);
  onOverRef.current = (overId) => st.reorderEntry("wishlist", r.id, overId);
  const dragging = useHoldReorder(rootRef, r.id, "data-wish", onOverRef, null);
  const [noteVal, setNoteVal] = useState(r.note || "");
  React.useEffect(() => { setNoteVal(r.note || ""); }, [r.id]);
  const days = Math.max(0, Math.floor((Date.now() - new Date(r.date + "T00:00:00").getTime()) / 86400000));
  const ripe = days >= 30;
  const need = r.need === "need";
  const saved = (r.note || "").trim();
  const isUrl = /^https?:\/\/\S+$/i.test(saved);
  return (
    <div
      ref={rootRef}
      data-wish={r.id}
      draggable
      onDragStart={(e) => { e.dataTransfer.setData("text/plain", "wish:" + r.id); e.dataTransfer.effectAllowed = "move"; }}
      onDragOver={(e) => { e.preventDefault(); setOver(true); }}
      onDragLeave={() => setOver(false)}
      onDrop={(e) => { e.preventDefault(); setOver(false); const d = (e.dataTransfer.getData("text/plain") || "").split(":"); if (d[0] === "wish" && d[1] && d[1] !== r.id) st.reorderEntry("wishlist", d[1], r.id); }}
      style={{ padding: "10px 6px 10px 2px", borderBottom: `1px solid ${t.borderSoft}`, borderRadius: dragging || over ? 8 : 0, background: dragging ? hexA(t.accent, 0.08) : over ? t.card : "transparent", boxShadow: dragging ? "0 8px 22px rgba(0,0,0,0.26)" : "none", transition: "background .12s ease", userSelect: dragging ? "none" : "auto" }}
    >
      <div style={{ display: "flex", alignItems: "baseline", gap: 9, flexWrap: "wrap", marginBottom: 5 }}>
        <span title={L("Podrž a přetáhni pro pořadí", "Hold and drag to reorder")} style={{ color: t.textMuted, cursor: "grab", fontSize: 13, alignSelf: "center", flexShrink: 0, opacity: 0.6 }}>⠿</span>
        <span style={{ fontFamily: FONT_BODY, fontSize: 14, color: t.text, flex: 1, minWidth: 110 }}>
          {r.item}
          {r.cat && <span style={{ marginLeft: 7, fontFamily: FONT_TAG, letterSpacing: "0.06em", fontSize: 10, color: t.sage, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "1px 7px", textTransform: "uppercase", verticalAlign: "1px" }}>{r.cat}</span>}
        </span>
        <button onClick={() => st.updateEntry("wishlist", r.id, { need: need ? "want" : "need" })} title={need ? L("Potřeba — klikni pro Chci", "Need — click for Want") : L("Chci — klikni pro Potřeba", "Want — click for Need")} style={{ background: need ? hexA(t.accent, 0.14) : "transparent", border: `1px solid ${need ? t.accent : t.borderSoft}`, borderRadius: 12, padding: "2px 10px", cursor: "pointer", color: need ? t.accent : t.textMuted, fontFamily: FONT_TAG, letterSpacing: "0.07em", fontSize: 10, textTransform: "uppercase" }}>{need ? L("potřeba", "need") : L("chci", "want")}</button>
        <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textSec }}>{money(r.amount)}</span>
        <span style={{ fontFamily: FONT_TAG, letterSpacing: "0.08em", fontSize: 10.5, color: ripe ? t.accent : t.textMuted, textTransform: "uppercase" }}>{ripe ? L("dozráno", "ripe") : `${L("zraje", "ripening")} ${days}/30`}</span>
        <button onClick={() => letGo(r)} title={L("Do koše", "To trash")} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontSize: 13, padding: 0, lineHeight: 1, flexShrink: 0 }}>✕</button>
      </div>
      <ProgressBar value={Math.min(1, days / 30)} />
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 7 }}>
        <input value={noteVal} onChange={(e) => setNoteVal(e.target.value)} onBlur={() => { if (noteVal !== (r.note || "")) st.updateEntry("wishlist", r.id, { note: noteVal }); }} placeholder={L("odkaz nebo poznámka…", "link or note…")} style={{ flex: 1, minWidth: 0, background: "transparent", border: "none", borderBottom: `1px dashed ${hexA(t.textMuted, 0.3)}`, color: t.textSec, fontFamily: FONT_BODY, fontSize: 12.5, outline: "none", padding: "2px 0" }} />
        {isUrl && <a href={saved} target="_blank" rel="noopener noreferrer" title={L("Otevřít odkaz", "Open link")} style={{ color: t.accent, textDecoration: "none", fontSize: 14, flexShrink: 0 }}>↗</a>}
      </div>
      {ripe && (
        <div style={{ display: "flex", gap: 8, marginTop: 8, alignItems: "center", flexWrap: "wrap" }}>
          <span style={{ fontFamily: FONT_DISPLAY, fontStyle: "italic", fontSize: 14, color: t.sand }}>{L("Pořád to chceš?", "Still want it?")}</span>
          <button onClick={() => buy(r)} style={{ background: "transparent", border: `1px solid ${t.accent}`, borderRadius: 12, padding: "3px 13px", cursor: "pointer", color: t.accent, fontFamily: FONT_BODY, fontSize: 12.5 }}>Koupit</button>
          <button onClick={() => letGo(r)} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 12, padding: "3px 13px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}>Pustit</button>
        </div>
      )}
    </div>
  );
}

// ---- Wishlist · the 30-day rule against impulse buying ----
const WISH_CATS = ["Style", "Tech", "Gifts", "Domov", "Praxe"];
function Wishlist() {
  const { t } = useT();
  const st = useStore();
  const rows = st.coll.wishlist || [];
  const cfg = st.coll.finCfg || {};
  const cats = [...WISH_CATS, ...(cfg.wishCats || [])];
  const [item, setItem] = useState("");
  const [amount, setAmount] = useState("");
  const [cat, setCat] = useState(cfg.lastWishCat && cats.includes(cfg.lastWishCat) ? cfg.lastWishCat : cats[0]);
  const [view, setView] = useState("Vše");
  const [addingCat, setAddingCat] = useState(false);
  const [newCat, setNewCat] = useState("");
  const add = () => {
    const v = item.trim();
    if (!v) return;
    st.addEntry("wishlist", { id: uid(), date: todayISO(), item: v, amount: parseFloat(amount) || 0, cat });
    st.setFinCfg({ lastWishCat: cat });
    setItem(""); setAmount("");
  };
  const saveCat = () => {
    const v = newCat.trim();
    if (!v || cats.some((c) => c.toLowerCase() === v.toLowerCase())) { setAddingCat(false); setNewCat(""); return; }
    st.setFinCfg({ wishCats: [...(cfg.wishCats || []), v] });
    setCat(v); setAddingCat(false); setNewCat("");
  };
  const daysOf = (d) => Math.floor((Date.now() - new Date(d + "T00:00:00").getTime()) / 86400000);
  const buy = (r) => st.ask(L(`Koupit „${r.item}" za ${money(r.amount)}? Zapíše se jako dnešní výdaj (PLAY).`, `Buy "${r.item}" for ${money(r.amount)}? It will be logged as today's expense (PLAY).`), () => {
    st.addEntry("expenses", { id: uid(), date: todayISO(), item: r.item, jar: "PLAY", amount: r.amount });
    st.removeEntry("wishlist", r.id);
  });
  const letGo = (r) => st.ask(`Pustit „${r.item}"?`, () => st.removeEntry("wishlist", r.id));
  const counts = { "Vše": rows.length };
  cats.forEach((c) => { counts[c] = rows.filter((r) => r.cat === c).length; });
  const shown = [...rows].filter((r) => view === "Vše" || r.cat === view); // manual order (drag to reorder)
  const chip = (active) => ({ background: active ? hexA(t.accent, 0.14) : "transparent", border: `1px solid ${active ? t.accent : t.borderSoft}`, borderRadius: 12, padding: "3px 11px", cursor: "pointer", color: active ? t.accent : t.textMuted, fontFamily: FONT_TAG, letterSpacing: "0.08em", fontSize: 11, textTransform: "uppercase" });
  return (
    <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><SproutIcon size={20} /></span>} title={L("Wishlist · pravidlo 30 dní", "Wishlist · the 30-day rule")}>
      <p style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textSec, margin: "0 0 10px", lineHeight: 1.6 }}>{L("Impuls sem, ne do košíku — přání zraje třicet dní.", "The impulse goes here, not in the cart — a wish ripens for thirty days.")}</p>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 8 }}>
        <input value={item} onChange={(e) => setItem(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") add(); }} placeholder={L("Co tě láká…", "What tempts you…")} style={{ ...fieldStyle(t), flex: "1 1 150px", minWidth: 130 }} />
        <input type="number" inputMode="decimal" value={amount} onChange={(e) => setAmount(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") add(); }} placeholder="Kč" style={{ ...fieldStyle(t), width: 96 }} />
        {item.trim() && <button onClick={add} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "7px 14px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13 }}>Zasadit</button>}
      </div>
      <div style={{ display: "flex", gap: 5, flexWrap: "wrap", alignItems: "center", marginBottom: 12 }}>
        {cats.map((c) => <button key={c} onClick={() => setCat(c)} style={chip(cat === c)}>{LV(c)}</button>)}
        {st.editMode && (addingCat
          ? <span style={{ display: "inline-flex", gap: 5 }}>
              <input autoFocus value={newCat} onChange={(e) => setNewCat(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") saveCat(); if (e.key === "Escape") { setAddingCat(false); setNewCat(""); } }} placeholder={L("nová…", "new…")} style={{ ...fieldStyle(t), width: 92, padding: "2px 8px", fontSize: 12 }} />
              <button onClick={saveCat} style={chip(true)}>ok</button>
            </span>
          : <button title={L("Přidat kategorii", "Add category")} onClick={() => setAddingCat(true)} style={{ ...chip(false), borderStyle: "dashed" }}>＋</button>)}
      </div>
      {rows.length > 0 && (
        <div style={{ display: "flex", gap: 2, flexWrap: "wrap", borderBottom: `1px solid ${t.borderSoft}`, marginBottom: 6 }}>
          {["Vše", ...cats.filter((c) => counts[c] > 0)].map((c) => (
            <button key={c} onClick={() => setView(c)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: "6px 9px 7px", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.08em", fontSize: 10.5, color: view === c ? t.accent : t.textMuted, borderBottom: view === c ? `2px solid ${t.accent}` : "2px solid transparent", marginBottom: -1 }}>
              {LV(c)}<span style={{ marginLeft: 4, opacity: 0.6, fontSize: 9.5 }}>{counts[c] || 0}</span>
            </button>
          ))}
        </div>
      )}
      {shown.length === 0 && <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13, color: t.textMuted }}>Nic tu nezraje.</div>}
      {shown.map((r) => <WishRow key={r.id} r={r} buy={buy} letGo={letGo} />)}
    </Callout>
  );
}

// ---- 6-month history · income vs expenses, columns navigate ----
function FinChart({ month, onPick }) {
  const { t } = useT();
  const st = useStore();
  const months = [];
  for (let i = 5; i >= 0; i--) months.push(finShiftMonth(month, -i));
  const data = months.map((m) => ({
    m,
    inc: finSum((st.coll.income || []).filter((r) => finMonthKey(r.date) === m)),
    exp: finSum((st.coll.expenses || []).filter((r) => finMonthKey(r.date) === m)),
  }));
  const max = Math.max(1, ...data.map((d) => Math.max(d.inc, d.exp)));
  const H = 88;
  return (
    <div>
      <div style={{ display: "grid", gridTemplateColumns: `repeat(${data.length}, 1fr)`, gap: 10, alignItems: "end", height: H + 26 }}>
        {data.map((d) => (
          <button key={d.m} onClick={() => onPick(d.m)} title={`${MONTHS_CZ()[+d.m.split("-")[1] - 1]} · ${L("příjmy", "income")} ${money(d.inc)} · ${L("výdaje", "expenses")} ${money(d.exp)}`} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 0, display: "flex", flexDirection: "column", justifyContent: "flex-end", height: "100%" }}>
            <span style={{ display: "flex", gap: 3, alignItems: "flex-end", justifyContent: "center", width: "100%", height: H }}>
              <span style={{ width: "34%", maxWidth: 16, height: Math.max(2, (d.inc / max) * H), borderRadius: 3, background: t.sage, opacity: d.m === month ? 1 : 0.55 }} />
              <span style={{ width: "34%", maxWidth: 16, height: Math.max(2, (d.exp / max) * H), borderRadius: 3, background: t.accent, opacity: d.m === month ? 1 : 0.55 }} />
            </span>
            <span style={{ fontFamily: FONT_TAG, letterSpacing: "0.08em", fontSize: 10.5, color: d.m === month ? t.heading : t.textMuted, textTransform: "uppercase", width: "100%", textAlign: "center", marginTop: 6 }}>{MONTHS_CZ_SHORT()[+d.m.split("-")[1] - 1]}</span>
          </button>
        ))}
      </div>
      <div style={{ display: "flex", gap: 14, marginTop: 8, flexWrap: "wrap" }}>
        <span style={{ ...subLabel(t), marginBottom: 0, display: "inline-flex", alignItems: "center", gap: 6 }}><span style={{ width: 10, height: 10, borderRadius: 3, background: t.sage, display: "inline-block" }} />{L("Příjmy", "Income")}</span>
        <span style={{ ...subLabel(t), marginBottom: 0, display: "inline-flex", alignItems: "center", gap: 6 }}><span style={{ width: 10, height: 10, borderRadius: 3, background: t.accent, display: "inline-block" }} />{L("Výdaje", "Expenses")}</span>
      </div>
    </div>
  );
}

function PageFinances() {
  const { t } = useT();
  const st = useStore();
  const [month, setMonth] = useState(finThisMonth());
  const inMonth = (r) => finMonthKey(r.date) === month;
  const seedExpenses = [{ date: "2024-12-06", item: "Birthday gift for sister", amount: 100 }];
  const income = finSum((st.coll.income || []).filter(inMonth));
  const spent = finSum([...(st.coll.expenses || []), ...seedExpenses].filter(inMonth));
  const rate = income > 0 ? Math.round(((income - spent) / income) * 100) : null;
  const [my, mm] = month.split("-");
  const expFields = [{ key: "item", label: L("Položka", "Item"), type: "text" }, { key: "jar", label: "Jar", type: "select", options: JARS.map((j) => j[0]) }, { key: "amount", label: L("Částka", "Amount"), type: "number" }];
  const incFields = [{ key: "source", label: L("Zdroj", "Source"), type: "text" }, { key: "amount", label: L("Částka", "Amount"), type: "number" }];
  const invFields = [{ key: "asset", label: L("Aktivum", "Asset"), type: "text" }, { key: "amount", label: L("Hodnota", "Value"), type: "number" }];
  return (
    <>
      <div className="tm-mhide" style={{ borderRadius: 16, overflow: "hidden", border: `1px solid ${t.borderSoft}`, marginBottom: 26, boxShadow: t.shadow }}>
        <div style={{ background: t.hero, padding: "20px 24px 18px" }}>
          <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.26em", fontSize: 16, color: t.heroInk, display: "flex", alignItems: "center", flexWrap: "wrap", gap: "0 14px" }}>
            <span>Earn</span>
            <span style={{ width: 5, height: 5, borderRadius: "50%", background: t.heroInkSoft, display: "inline-block" }} />
            <span>Allocate</span>
            <span style={{ width: 5, height: 5, borderRadius: "50%", background: t.heroInkSoft, display: "inline-block" }} />
            <span>Give</span>
          </div>
          <div style={{ width: 44, height: 1, background: t.heroLine, margin: "14px 0" }} />
          {st.editMode
            ? <BufferedInput value={st.pageMetaOf("hospodareni").sub || L("Peníze jako praxe. Příjem se rozdělí dřív, než se rozhodne sám — šest sklenic, jeden měsíc v dohledu. Přání zrají třicet dní.", "Money as practice. Income is divided before it decides for itself — six jars, one month in view. Wishes ripen for thirty days.")} onCommit={(v) => st.setPageMeta("hospodareni", { sub: v })} style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.heroInkSoft, margin: 0, lineHeight: 1.65, maxWidth: 520, borderBottom: `1px dashed ${t.heroLine}` }} />
            : <p style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.heroInkSoft, margin: 0, lineHeight: 1.65, maxWidth: 520 }}>{st.pageMetaOf("hospodareni").sub || L("Peníze jako praxe. Příjem se rozdělí dřív, než se rozhodne sám — šest sklenic, jeden měsíc v dohledu. Přání zrají třicet dní.", "Money as practice. Income is divided before it decides for itself — six jars, one month in view. Wishes ripen for thirty days.")}</p>}
        </div>
      </div>

      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcHospodareni size={38} /></span>} pageKey="hospodareni" kicker="System · 6 Jars">{L("Hospodaření", "Stewardship")}</PageTitle>

      <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "14px 0 4px", flexWrap: "wrap" }}>
        <button onClick={() => setMonth(finShiftMonth(month, -1))} style={calBtn(t, false)}>‹</button>
        <span style={{ fontFamily: FONT_DISPLAY, fontSize: 21, color: t.heading, minWidth: 168, textAlign: "center" }}>{MONTHS_CZ()[+mm - 1]} {my}</span>
        <button onClick={() => setMonth(finShiftMonth(month, 1))} style={calBtn(t, false)}>›</button>
        {month !== finThisMonth() && <button onClick={() => setMonth(finThisMonth())} style={{ ...calBtn(t, false), fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, padding: "4px 10px" }}>{L("tento měsíc", "this month")}</button>}
      </div>

      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", margin: "12px 0 8px" }}>
        <StatCard value={money(income)} label={L("Příjmy", "Income")} />
        <StatCard value={money(spent)} label={L("Výdaje", "Expenses")} />
        <StatCard value={money(income - spent)} label={L("Zůstatek", "Balance")} />
        <StatCard value={rate == null ? "—" : rate + " %"} label={L("Uloženo z příjmu", "Saved from income")} />
      </div>

      <QuickExpense />

      <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><JarIcon size={20} /></span>} title={L("6 Jars · kam měsíc teče", "6 Jars · where the month flows")}><Jars month={month} /></Callout>

      <div style={twoCol}>
        <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><ArrowOutIcon size={20} /></span>} title={L("Výdaje", "Expenses")}>
          <LedgerSection kind="expenses" fields={expFields} addLabel={L("Přidat výdaj", "Add expense")} seed={seedExpenses} month={month} />
        </Callout>
        <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><ArrowInIcon size={20} /></span>} title={L("Příjmy", "Income")}>
          <LedgerSection kind="income" fields={incFields} addLabel={L("Přidat příjem", "Add income")} month={month} />
        </Callout>
      </div>

      <Wishlist />

      <Divider />
      <Eyebrow>{L("Posledních 6 měsíců", "Last 6 months")}</Eyebrow>
      <FinChart month={month} onPick={setMonth} />

      <Divider />
      <Callout icon={<span style={{ color: t.sand, display: "inline-flex" }}><TrendIcon size={20} /></span>} title={L("Investments · aktuální hodnoty", "Investments · current values")}>
        <LedgerSection kind="investments" fields={invFields} addLabel={L("Přidat investici", "Add investment")} />
      </Callout>
    </>
  );
}

function PageJournal() {
  const { t } = useT();
  const st = useStore();
  React.useEffect(() => { st.importJournal(); st.migrateCzJournal(); }, []);
  const tags = st.jTags();
  const all = st.coll.journal || [];
  const [view, setView] = useState("Vše");
  const [fMonth, setFMonth] = useState("vše");
  const [q, setQ] = useState("");
  const [selecting, setSelecting] = useState(false);
  const [sel, setSel] = useState([]);
  const [managing, setManaging] = useState(false);
  const [sortBy, setSortBy] = useState("dateDesc");
  const [limit, setLimit] = useState(40);
  const [offlineOnly, setOfflineOnly] = useState(false);
  const [starOnly, setStarOnly] = useState(false);
  const [full, setFull] = useState(null);
  const [draftId, setDraftId] = useState(null);
  const [editingToday, setEditingToday] = useState(false);
  const todayFileRef = React.useRef(null);
  const [qOpen, setQOpen] = useState(false);
  const [fOpen, setFOpen] = useState(false);
  const [openMonths, setOpenMonths] = useState({});

  // ---- Dnes · jedna psací plocha — deník začíná dneškem, ne archivem ----
  const today = todayISO();
  const todayEntry = all.find((e) => e.date === today) || (draftId ? all.find((e) => e.id === draftId) : null);
  const writeToday = (v) => {
    if (todayEntry) { st.updateEntry("journal", todayEntry.id, { text: v }); return; }
    if (!v || !v.trim()) return;
    const id = uid();
    st.addEntry("journal", { id, date: today, title: "", tag: "Den", text: v });
    setDraftId(id);
  };
  const composerOpen = !todayEntry || !todayEntry.committed || editingToday;
  const attachToday = async (fl) => { if (!todayEntry || !fl || !fl.length) return; const added = await filesToAtts(fl, st.ask); if (added.length) st.updateEntry("journal", todayEntry.id, { att: [...(todayEntry.att || []), ...added] }); if (todayFileRef.current) todayFileRef.current.value = ""; };

  // ---- Na tento den · návrat na stejné místo v jiném roce ----
  const md = today.slice(5);
  const echoes = all.filter((e) => e.date && e.date !== today && e.date.slice(5) === md)
    .sort((x, y) => (y.date || "").localeCompare(x.date || ""));

  let shown = view === "Vše" ? all : all.filter((e) => entryTags(e).includes(view));
  if (fMonth !== "vše") shown = shown.filter((e) => (e.date || "").slice(0, 7) === fMonth);
  if (q.trim()) { const nq = tmNorm(q); shown = shown.filter((e) => tmNorm((e.title || "") + " " + (e.text || "")).includes(nq)); }
  if (sortBy === "dateDesc") shown = [...shown].sort((x, y) => (y.date || "").localeCompare(x.date || ""));
  if (sortBy === "dateAsc") shown = [...shown].sort((x, y) => (x.date || "9999").localeCompare(y.date || "9999"));
  if (offlineOnly) shown = shown.filter((e) => isEntryPinned(e.id));
  if (starOnly) shown = shown.filter((e) => e.star);
  if (!selecting && todayEntry && composerOpen) shown = shown.filter((e) => e.id !== todayEntry.id);
  const visible = q.trim() ? shown : shown.slice(0, limit);
  const months = Array.from(new Set(all.map((e) => (e.date || "").slice(0, 7)).filter((m) => /^\d{4}-\d{2}$/.test(m)))).sort().reverse();
  const monthLabel = (ym) => { const s = new Date(ym + "-01T12:00:00").toLocaleDateString(LANG === "cs" ? "cs-CZ" : "en-GB", { month: "long", year: "numeric" }); return s.charAt(0).toUpperCase() + s.slice(1); };
  const dayName = new Date(today + "T12:00:00").toLocaleDateString(LANG === "cs" ? "cs-CZ" : "en-GB", { weekday: "long" });

  const fullEntry = full ? all.find((e) => e.id === full) : null;

  const toggleSel = (id) => setSel((xs) => xs.includes(id) ? xs.filter((x) => x !== id) : [...xs, id]);
  const dragSel = (id) => setSel((xs) => xs.includes(id) ? xs : [...xs, id]);
  const exitSelect = () => { setSelecting(false); setSel([]); };
  const starred = all.filter((e) => e.star).length;
  const todayTagColor = todayEntry && todayEntry.tag ? ((tags.find(([n]) => n === todayEntry.tag) || [])[1] || "default") : "default";

  return (
    <>
      {fullEntry && (
        <CenterSheet center title={(fullEntry.date ? fmtCZ(fullEntry.date) + (fullEntry.title ? " · " : "") : "") + (fullEntry.title || "")} onClose={() => setFull(null)}>
          <NotebookCard kind="journal" entry={fullEntry} tags={tags} full />
        </CenterSheet>
      )}
      <PageTitle icon={<span style={{ color: t.sand, display: "inline-flex" }}><TmIcDenik size={38} /></span>} pageKey="denik" kicker={L("Psaná praxe · od prosince 2020", "Written practice · since December 2020")}>{L("Deník", "Journal")}</PageTitle>
      <p style={pProse(t)}>{L("Psáno z cesty, ne z vrcholu.", "Written from the path, not the summit.")}</p>

      {!selecting && composerOpen && (
        <div style={{ background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "14px 16px", margin: "12px 0 6px", boxShadow: t.shadow }}>
          <div style={{ ...subLabel(t), marginBottom: 8, display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ color: t.sand, display: "inline-flex" }}><PenIcon size={12} /></span>
            <span>{L("Dnes", "Today")} · {dayName} {fmtCZ(today)}</span>
            {todayEntry && entryTags(todayEntry).map((n) => <Tag key={n} label={n} color={((tags.find(([x]) => x === n)) || [])[1] || "default"} />)}
            <span style={{ flex: 1 }} />
            {todayEntry && <><input ref={todayFileRef} type="file" multiple onChange={(ev) => attachToday(ev.target.files)} style={{ display: "none" }} /><button title={L("Přiložit soubor", "Attach file")} onClick={() => todayFileRef.current && todayFileRef.current.click()} style={{ ...iconBtn(t), border: "none", color: t.textMuted, width: 22, height: 22, display: "inline-flex", alignItems: "center", justifyContent: "center" }}><ClipIcon size={13} /></button></>}
            {todayEntry && (todayEntry.text || "").trim() && <button onClick={() => { st.updateEntry("journal", todayEntry.id, { committed: true }); setEditingToday(false); setDraftId(null); }} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "4px 14px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Uložit", "Save")}</button>}
            {todayEntry && <button title={L("Otevřít jako stránku", "Open as page")} onClick={() => setFull(todayEntry.id)} style={{ ...iconBtn(t), border: "none", color: t.textMuted, fontSize: 13 }}>⤢</button>}
            {todayEntry && <button title={L("Zahodit dnešní zápis", "Discard today's entry")} onClick={() => st.ask(L("Odstranit dnešní zápis a začít znovu?", "Remove today's entry and start over?"), () => { st.removeEntry("journal", todayEntry.id); setDraftId(null); setEditingToday(false); })} style={{ ...iconBtn(t), border: "none", color: t.textMuted, fontSize: 13, padding: 0, width: 22, height: 22, display: "inline-flex", alignItems: "center", justifyContent: "center" }}><TrashIcon size={13} /></button>}
          </div>
          <RichArea key={todayEntry ? todayEntry.id : "novy"} value={todayEntry ? todayEntry.text || "" : ""} onChange={writeToday} placeholder={L("Piš…", "Write…")} />
          {todayEntry && <AttachmentStrip att={todayEntry.att} onRemove={st.editMode ? ((id) => st.updateEntry("journal", todayEntry.id, { att: (todayEntry.att || []).filter((x) => x.id !== id) })) : undefined} />}
        </div>
      )}
      {!selecting && !composerOpen && todayEntry && (
        <div style={{ display: "flex", alignItems: "center", gap: 10, background: t.card, border: `1px solid ${t.borderSoft}`, borderRadius: 10, padding: "10px 14px", margin: "12px 0 6px", boxShadow: t.shadow }}>
          <span style={{ color: t.sand, display: "inline-flex" }}><PenIcon size={12} /></span>
          <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.textSec }}>{L("Dnešní zápis uložen", "Today's entry saved")} · {fmtCZ(today)}</span>
          <span style={{ flex: 1 }} />
          <button onClick={() => setEditingToday(true)} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 8, padding: "4px 14px", cursor: "pointer", color: t.textSec, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Upravit", "Edit")}</button>
        </div>
      )}

      {!selecting && echoes.length > 0 && (
        <div style={{ margin: "12px 0 4px" }}>
          <div style={{ ...subLabel(t), marginBottom: 4 }}>{L("Na tento den", "On this day")}</div>
          {echoes.map((e) => (
            <button key={e.id} onClick={() => setFull(e.id)} className="tm-nav-item" style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", textAlign: "left", background: "transparent", border: "none", borderRadius: 8, padding: "6px 8px", cursor: "pointer" }}>
              <span style={{ fontFamily: FONT_DISPLAY, fontSize: 16, color: t.sand, flexShrink: 0 }}>{(e.date || "").slice(0, 4)}</span>
              <span style={{ fontFamily: FONT_BODY, fontSize: 13, color: t.textSec, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{e.title || (e.text || "").split("\n").filter(Boolean)[0] || ""}</span>
            </button>
          ))}
        </div>
      )}

      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center", borderBottom: `1px solid ${t.border}`, margin: "10px 0 12px", paddingBottom: 8 }}>
        <button className="tm-monly" onClick={() => setQOpen((x) => !x)} title={L("Hledat", "Search")} style={{ display: "none", alignItems: "center", gap: 7, background: "transparent", border: "none", borderBottom: `1px solid ${qOpen ? t.accent : t.borderSoft}`, borderRadius: 0, cursor: "pointer", color: qOpen ? t.accent : t.textMuted, fontFamily: FONT_BODY, fontSize: 13.5, padding: "5px 4px 6px", minWidth: 120 }}><TmIcLupa size={14} />{L("hledat v deníku…", "search the journal…")}</button>
        <button className="tm-monly" onClick={() => setFOpen((x) => !x)} title={L("Filtry", "Filters")} style={{ display: "none", alignItems: "center", justifyContent: "center", width: 32, height: 32, background: fOpen ? hexA(t.accent, 0.12) : "transparent", border: "none", borderRadius: 8, cursor: "pointer", color: fOpen ? t.accent : t.textMuted, fontSize: 13 }}>▾</button>
        <input className={"tm-jsearch" + (qOpen ? " open" : "")} value={q} onChange={(e) => { setQ(e.target.value); }} placeholder={L("Hledat v deníku…", "Search the journal…")} style={{ background: "transparent", border: "none", borderBottom: `1px solid ${q ? t.accent : t.borderSoft}`, color: t.text, fontFamily: FONT_BODY, fontSize: 13.5, outline: "none", padding: "4px 2px", width: 150 }} />
        <div className={"tm-jfilters" + (fOpen ? " open" : "")} style={{ display: "contents" }}>
        <Select ghost value={view} onChange={setView} style={{ width: "auto" }} options={[{ v: "Vše", label: LV("Vše") }, ...tags.map(([n]) => ({ v: n, label: n }))]} />
        <Select ghost value={fMonth} onChange={(v) => { setFMonth(v); setLimit(40); }} style={{ width: "auto" }} options={[{ v: "vše", label: L("celý proud", "all time") }, ...months.map((m) => ({ v: m, label: monthLabel(m) }))]} />
        <button onClick={() => setStarOnly((x) => !x)} title={L("Jen oblíbené", "Only starred")} style={{ display: "inline-flex", alignItems: "center", gap: 5, background: starOnly ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${starOnly ? t.accent : "transparent"}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: starOnly ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}><span style={{ fontSize: 11, lineHeight: 1 }}>★</span>{L("oblíbené", "starred")}</button>
        <span style={{ flex: 1 }} />
        <button onClick={() => setOfflineOnly((x) => !x)} title={L("Zobrazit jen offline uložené", "Show only offline-saved")} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: offlineOnly ? hexA(t.accent, 0.12) : "transparent", border: `1px solid ${offlineOnly ? t.accent : "transparent"}`, borderRadius: 999, padding: "4px 10px", cursor: "pointer", color: offlineOnly ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.09em", fontSize: 10.5 }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: offlineOnly ? t.accent : t.textMuted, flexShrink: 0 }} />offline</button>
        <Select ghost value={sortBy} onChange={setSortBy} style={{ width: "auto" }} options={[{ v: "dateDesc", label: L("nejnovější", "newest") }, { v: "dateAsc", label: L("nejstarší", "oldest") }, { v: "manual", label: L("vlastní pořadí", "custom order") }]} />
        </div>
        <button title="Spravovat kategorie" onClick={() => setManaging((x) => !x)} style={{ background: "transparent", border: "none", cursor: "pointer", color: t.textMuted, fontSize: 14, padding: "4px 8px" }}>⋯</button>
        {st.editMode && <button onClick={() => selecting ? exitSelect() : setSelecting(true)} style={{ background: selecting ? t.activeNav : "transparent", border: `1px solid ${selecting ? t.accent : t.border}`, borderRadius: 14, padding: "3px 12px", cursor: "pointer", color: selecting ? t.accent : t.textMuted, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, marginLeft: 6 }}>{selecting ? L("Zrušit výběr", "Cancel selection") : L("☑ Vybrat", "☑ Select")}</button>}
      </div>

      {managing && <NbTagManager onDone={() => setManaging(false)} ops={{ list: tags, add: st.addJTag, rename: st.renameJTag, reorder: st.reorderJTag, remove: st.removeJTag, protectedName: "Den", attr: "data-jtag" }} />}
      {!selecting && <AddEntry kind="journal" tags={tags} label={L("Samostatný zápisek", "Separate entry")} />}

      <div className="tm-wave tm-scroll" style={{ marginTop: 12, maxHeight: "min(680px, 64vh)", overflowY: "auto", border: `1px solid ${t.borderSoft}`, borderRadius: 12, padding: "4px 12px 12px" }}>
        {(() => {
          let lastYM = null;
          const curYM0 = months[0] || todayISO().slice(0, 7);
          const grouping = sortBy !== "manual" && !q.trim();
          const out = [];
          visible.forEach((e) => {
            const ym = (e.date || "").slice(0, 7);
            if (grouping && ym && ym !== lastYM) {
              lastYM = ym;
              const openM = ym === curYM0 || !!openMonths[ym];
              out.push(
                <button key={"m" + ym} onClick={() => setOpenMonths((x) => ({ ...x, [ym]: !openM }))} style={{ width: "100%", textAlign: "left", background: "transparent", border: "none", cursor: "pointer", fontFamily: FONT_DISPLAY, fontSize: 19, color: t.textSec, margin: "22px 0 2px", padding: 0, display: "flex", alignItems: "center", gap: 12 }}>
                  <span style={{ transition: "transform .18s ease", transform: openM ? "rotate(90deg)" : "none", color: t.sage, display: "inline-flex" }}><TmIcChev size={14} /></span>
                  {monthLabel(ym)}
                  <span style={{ flex: 1, height: 1, background: t.borderSoft }} />
                  {!openM && <span style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, color: t.textMuted }}>{all.filter((x) => (x.date || "").slice(0, 7) === ym).length} {L("zápisků", "entries")}</span>}
                </button>
              );
            }
            const shownM = !grouping || !ym || ym === curYM0 || !!openMonths[ym];
            if (shownM) out.push(<NotebookCard key={e.id} kind="journal" entry={e} tags={tags} selecting={selecting} selected={sel.includes(e.id)} onToggleSel={toggleSel} onDragSel={dragSel} noDrag={sortBy !== "manual"} onExpand={setFull} />);
          });
          return out;
        })()}
        {!q.trim() && shown.length > limit && (
          <button onClick={() => setLimit((l) => l + 40)} className="tm-dash" style={{ width: "100%", background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "10px 14px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 13.5, margin: "8px 0 4px" }}>{L("Načíst starší · zbývá", "Load older · remaining")} {shown.length - limit}</button>
        )}
        {shown.length === 0 && <p style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 13.5, color: t.textMuted, padding: "18px 0" }}>{L("V tomto pohledu zatím nic není.", "Nothing in this view yet.")}</p>}
      </div>

      {selecting && sel.length > 0 && (
        <div style={{ position: "sticky", bottom: 16, display: "flex", alignItems: "center", gap: 10, background: t.bg, border: `1px solid ${t.border}`, borderRadius: 12, padding: "10px 14px", boxShadow: "0 10px 30px rgba(0,0,0,0.3)", zIndex: 50, flexWrap: "wrap", marginTop: 10 }}>
          <span style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: t.heading }}>{sel.length} {L("vybráno", "selected")}</span>
          <span style={{ flex: 1 }} />
          <Select small value="" onChange={(v) => { st.setEntriesTag("journal", sel, v); exitSelect(); }} placeholder={L("Přesunout do…", "Move to…")} style={{ maxWidth: 170, width: 170 }} options={tags.map(([n]) => n)} />
          <button onClick={() => st.ask(L(`Přesunout ${sel.length} zápisků do koše?`, `Move ${sel.length} entries to trash?`), () => { st.removeEntries("journal", sel); exitSelect(); })} style={{ background: "transparent", border: `1px solid ${t.border}`, borderRadius: 8, padding: "6px 14px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 13 }}>{L("Do koše", "To trash")}</button>
        </div>
      )}
    </>
  );
}
function AddAreaForm({ onDone }) {
  const { t } = useT();
  const st = useStore();
  const [name, setName] = useState("");
  const [icon, setIcon] = useState("▦");
  const save = () => {
    const v = name.trim();
    if (!v) return;
    if (st.listAreas().some((a) => a.name.toLowerCase() === v.toLowerCase())) { st.ask(L("Oblast s tímto jménem už existuje.", "An area with this name already exists."), null); return; }
    st.addArea({ name: v, icon: icon.trim() || "▦" });
    onDone && onDone();
  };
  return (
    <div style={{ background: t.callout, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12, marginBottom: 14 , boxShadow: t.shadow }}>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center", marginBottom: 10 }}>
        <input value={icon} onChange={(e) => setIcon(e.target.value)} placeholder="◈" maxLength={4} style={{ ...fieldStyle(t), width: 60, textAlign: "center", fontSize: 16 }} />
        <input autoFocus value={name} onChange={(e) => setName(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") save(); }} placeholder={L("Název oblasti…", "Area name…")} style={{ ...fieldStyle(t), flex: 1, minWidth: 180 }} />
      </div>
      <div style={{ display: "flex", gap: 8 }}>
        <button onClick={save} style={{ background: t.accent, color: t.bg, border: "none", borderRadius: 8, padding: "7px 15px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13.5, fontWeight: 500 }}>{L("Vytvořit", "Create")}</button>
        <button onClick={onDone} style={{ background: "transparent", color: t.textSec, border: `1px solid ${t.border}`, borderRadius: 8, padding: "7px 15px", cursor: "pointer", fontFamily: FONT_BODY, fontSize: 13.5 }}>{L("Zrušit", "Cancel")}</button>
      </div>
      <div style={{ fontFamily: FONT_BODY, fontSize: 12, color: t.textMuted, fontStyle: "italic", marginTop: 8 }}>{L("Ikona: emoji nebo znak. Oblast se objeví ve všech filtrech a chips.", "Icon: an emoji or a symbol. The area appears in all filters and chips.")}</div>
    </div>
  );
}

