function TMuscleMap({ mp = [], ms = [], size = 150, fluid = false }) {
  const { t } = useT();
  const body = t.mode === "dark" ? "#3B3B37" : "#D9D0BE";
  const lvl = (k) => (mp.includes(k) ? 0.85 : ms.includes(k) ? 0.35 : 0);
  const view = (side) => (
    <svg viewBox="0 0 120 186" style={{ width: fluid ? "100%" : size * 0.62, height: "auto", display: "block" }}>
      <ellipse cx="60" cy="14" rx="8.5" ry="10.5" fill={body} />
      <path d={T_BODY_D} fill={body} />
      {Object.entries(T_MUSCLE_SHAPES[side]).map(([k, make]) => {
        const o = lvl(k);
        return o ? <React.Fragment key={k}>{make(o)}</React.Fragment> : null;
      })}
    </svg>
  );
  const lab = { fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.18em", fontSize: 10, color: t.sage, marginTop: 5, textAlign: "center" };
  return (
    <div>
      <div style={{ display: "flex", gap: fluid ? "6%" : 12, alignItems: "flex-start" }}>
        <div style={fluid ? { flex: 1, minWidth: 0 } : undefined}>{view("front")}<div style={lab}>{L("zepředu", "front")}</div></div>
        <div style={fluid ? { flex: 1, minWidth: 0 } : undefined}>{view("back")}<div style={lab}>{L("zezadu", "back")}</div></div>
      </div>
      <div style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: t.textMuted, marginTop: 7 }}>
        <span style={{ color: t.accent }}>●</span> {L("hlavní", "primary")} &nbsp; <span style={{ color: t.accent, opacity: 0.4 }}>●</span> {L("vedlejší", "secondary")}
      </div>
    </div>
  );
}

