// ---- Vital Institut · kapitoly (Etapa 1: kostra v jejich terminologii; obsah se doplňuje z přepisů) ----
const KB_VITAL = [
  { cz: "Jak je tahle knihovna postavená", en: "How this library is built", blocks: [
    { t: "p", cz: "Tohle jsou věrné poznámky z trenérského kurzu Vital Institutu — v jejich vlastní terminologii, ať tě nic nemate. Každá kapitola vychází z konkrétní přednášky; podrobný obsah sem doplňuji z přepisů. Úplný seznam zdrojů je dole.", en: "These are faithful notes from the Vital Institut trainer course — in their own terminology. Each chapter comes from a specific lecture; the detailed content is being filled in from transcripts. The full list of sources is at the bottom." },
  ] },

  { cz: "Anatomie · úvod, kostra, HZS + DZS", en: "Anatomy · intro, skeleton, UCS + LCS", blocks: [
    { t: "p", cz: "Anatomii popisujeme pomocí rovin a směrů — mediálně (blíž střední rovině), laterálně (dál od ní) a dalších relativních popisů. Kostra a klouby jsou opora, na které stojí veškerý pohyb.", en: "Anatomy is described with planes and directions — medial (closer to the midline), lateral (further from it) and other relative terms. The skeleton and joints are the support the whole movement stands on." },
    { t: "p", cz: "Pro trenéra jsou klíčové dva posturální syndromy — horní (HZS) a dolní zkřížený syndrom (DZS) — a dva dechově-stabilizační: rozevřených nůžek a přesýpacích hodin.", en: "For a trainer, two postural syndromes matter — upper (HZS) and lower crossed syndrome (DZS) — and two breathing-stabilization ones: open scissors and hourglass." },
    { t: "sub", cz: "Dolní zkřížený syndrom (DZS)", en: "Lower crossed syndrome (DZS)" },
    { t: "k", cz: ["Typické zkrácení: m. rectus femoris, m. tensor fasciae latae (TFL), m. iliopsoas a vzpřimovače bederní oblasti.", "Důsledky: prohloubení lordózy a anteverze pánve, nedostatečná extenze v kyčli při chůzi, přetížení bederní páteře až degenerace plotének (protruze / herniace)."], en: ["Typical shortening: rectus femoris, tensor fasciae latae (TFL), iliopsoas and the lumbar erectors.", "Consequences: deeper lordosis and pelvic anteversion, poor hip extension in gait, lumbar overload up to disc degeneration (protrusion / herniation)."] },
    { t: "sub", cz: "Horní zkřížený syndrom (HZS)", en: "Upper crossed syndrome (HZS)" },
    { t: "k", cz: ["Vzniká řetězením při špatné stabilizaci a dýchání — přetížení šíje a horní části trupu, předsunuté držení hlavy a ramen."], en: ["Arises from chaining under poor stabilization and breathing — overloaded neck and upper trunk, forward-held head and shoulders."] },
    { t: "sub", cz: "Dechově-stabilizační syndromy", en: "Breathing-stabilization syndromes" },
    { t: "k", cz: ["Rozevřené nůžky — inspirační (nádechové) postavení hrudníku, bez aktivace HSS a nitrobřišního tlaku.", "Přesýpací hodiny — zvýšená aktivita horní části břišních svalů a vtažení břišní stěny; paradoxní funkce bránice."], en: ["Open scissors — an inspiratory chest position, without HSS activation or intra-abdominal pressure.", "Hourglass — increased activity of the upper abdominals and an indrawn belly wall; paradoxical diaphragm function."] },
  ] },

  { cz: "Anatomie · lopatka a horní končetina", en: "Anatomy · scapula and upper limb", blocks: [
    { t: "p", cz: "Lopatka nese jamku ramenního kloubu — je základem funkce ramene. O zdravém pohybu paže rozhodují její stabilizátory.", en: "The scapula carries the shoulder socket — it is the basis of shoulder function. Its stabilizers decide whether the arm moves healthily." },
    { t: "k", cz: ["Stabilizátory lopatky (mezilopatkové svaly, dolní trapéz) drží lopatku při pohybu; jejich oslabení vede k bolestem ramene a šíje.", "Horní končetina: rameno, paže (biceps, triceps), předloktí a ruka — cviky volíme s ohledem na centraci ramenního kloubu."], en: ["Scapular stabilizers (interscapular muscles, lower trapezius) hold the scapula during movement; weakness leads to shoulder and neck pain.", "Upper limb: shoulder, arm (biceps, triceps), forearm and hand — exercises are chosen with shoulder-joint centration in mind."] },
  ] },

  { cz: "Anatomie · svaly krku a trupu", en: "Anatomy · neck and trunk muscles", blocks: [
    { t: "p", cz: "Svaly krku a trupu drží osu těla a přenášejí sílu mezi dolní a horní polovinou.", en: "Neck and trunk muscles hold the body axis and transfer force between the lower and upper halves." },
    { t: "k", cz: ["Krk: kloněné svaly (mm. scaleni) a zdvihač hlavy (SCM) — pomocné nádechové svaly; při špatném dýchání se přetěžují.", "Trup: břišní svaly (přímý, šikmé a příčný — m. transversus abdominis), zádové a paravertebrální svaly. Společně tvoří 'břišní lis', který chrání páteř."], en: ["Neck: the scalene muscles and sternocleidomastoid (SCM) — accessory breathing muscles; overloaded under poor breathing.", "Trunk: abdominal muscles (rectus, obliques and transversus abdominis), back and paravertebral muscles. Together they form the 'abdominal press' that protects the spine."] },
  ] },

  { cz: "Anatomie · svaly dolní končetiny", en: "Anatomy · lower limb muscles", blocks: [
    { t: "p", cz: "Svaly dolní končetiny — od kyčle po nohu — nesou většinu zátěže při dřepech, výpadech a chůzi.", en: "The lower-limb muscles — from hip to foot — carry most of the load in squats, lunges and walking." },
    { t: "k", cz: ["Kyčel: flexory (m. iliopsoas), abduktory a hýžďové svaly; jejich rovnováha řídí postavení pánve.", "Stehno: čtyřhlavý sval (kvadriceps — extenze kolene) a zadní strana (hamstringy — flexe); lýtko pro odraz.", "Časté dysbalance (zkrácený iliopsoas a TFL) souvisí s dolním zkříženým syndromem."], en: ["Hip: flexors (iliopsoas), abductors and glutes; their balance drives pelvic position.", "Thigh: quadriceps (knee extension) and the back (hamstrings — flexion); calf for push-off.", "Common imbalances (short iliopsoas and TFL) relate to the lower crossed syndrome."] },
  ] },

  { cz: "Výživa · makroživiny", en: "Nutrition · macronutrients", blocks: [
    { t: "p", cz: "Tři makroživiny — bílkoviny, sacharidy a tuky — dodávají energii i stavební materiál.", en: "Three macronutrients — protein, carbohydrates and fats — supply both energy and building material." },
    { t: "sub", cz: "Bílkoviny", en: "Protein" },
    { t: "k", cz: ["Řetězce z 20 aminokyselin. Esenciální (valin, leucin, izoleucin, threonin, lysin, methionin, fenylalanin, tryptofan, arginin, histidin) musíme přijmout stravou; neesenciální si tělo vytvoří.", "Dusíková bilance = rozdíl mezi přijatým a vyloučeným dusíkem; u dospělých rovnováha, u dětí pozitivní (růst)."], en: ["Chains of 20 amino acids. The essential ones (valine, leucine, isoleucine, threonine, lysine, methionine, phenylalanine, tryptophan, arginine, histidine) must come from food; the body makes the non-essential ones.", "Nitrogen balance = intake minus excreted nitrogen; balanced in adults, positive in children (growth)."] },
    { t: "sub", cz: "Sacharidy a tuky", en: "Carbohydrates and fats" },
    { t: "k", cz: ["Sacharidy — hlavní zdroj energie (glukóza), zásoba glykogen; objemově největší část makroživin. Mono-, oligo- a polysacharidy.", "Tuky — nejvydatnější zdroj energie (1 g = 38 kJ), stavba membrán, vstřebávání vitaminů. Nasycené (SAFA) vs. nenasycené; esenciální polynenasycené mastné kyseliny."], en: ["Carbohydrates — the main energy source (glucose), stored as glycogen; the largest part of macronutrients by volume. Mono-, oligo- and polysaccharides.", "Fats — the densest energy source (1 g = 38 kJ), membrane building, vitamin absorption. Saturated (SAFA) vs. unsaturated; essential polyunsaturated fatty acids."] },
  ] },

  { cz: "Výživa · mikroživiny", en: "Nutrition · micronutrients", blocks: [
    { t: "p", cz: "Vitamíny a minerály tělo potřebuje v malém množství, ale jsou nezbytné pro metabolismus.", en: "The body needs vitamins and minerals in small amounts, yet they are essential for metabolism." },
    { t: "k", cz: ["Vitamíny dělíme podle rozpustnosti na rozpustné ve vodě (nutný pravidelný příjem) a rozpustné v tucích (A, D, E, K — ukládají se v těle).", "Vláknina (nestravitelné polysacharidy): rozpustná (bobtná, dlouhodobě snižuje LDL) a nerozpustná (váže toxiny, detoxikace). Doporučeno cca 25–35 g/den; v ČR jí bývá nedostatek."], en: ["By solubility, vitamins are water-soluble (need regular intake) or fat-soluble (A, D, E, K — stored in the body).", "Fibre (indigestible polysaccharides): soluble (swells, lowers LDL over time) and insoluble (binds toxins, detox). Recommended about 25–35 g/day; often lacking in the Czech diet."] },
  ] },

  { cz: "Výživa · trávicí trakt", en: "Nutrition · digestive tract", blocks: [
    { t: "p", cz: "Trávicí trakt zpracovává potravu na živiny, které se vstřebávají — od úst po tlusté střevo.", en: "The digestive tract turns food into nutrients that get absorbed — from the mouth to the large intestine." },
    { t: "k", cz: ["Trávení a vstřebávání živin určuje, kolik z přijaté potravy tělo skutečně využije.", "Parasympatikus (klid) zlepšuje prokrvení trávicího traktu a vstřebávání — proto jíst v klidu, ne ve stresu."], en: ["Digestion and absorption decide how much of the food the body actually uses.", "The parasympathetic system (rest) improves blood flow to the gut and absorption — so eat calmly, not under stress."] },
  ] },

  { cz: "Výživa · výpočet a sestavení jídelníčku", en: "Nutrition · calculating and building a meal plan", blocks: [
    { t: "p", cz: "Jídelníček stavíme od energetické potřeby klienta.", en: "A meal plan is built from the client energy need." },
    { t: "k", cz: ["BMR (bazální metabolismus) = energie pro základní chod těla. Denní příjem = BMR × faktor aktivity: lehká práce ×1,5, středně těžká ×1,6, těžká ×1,7.", "Redukce = mírný kalorický deficit; podle cíle upravíme poměr makroživin. Detailní výpočty jsou v materiálech dietologie."], en: ["BMR (basal metabolic rate) = energy for the basic running of the body. Daily intake = BMR × activity factor: light work ×1.5, moderate ×1.6, heavy ×1.7.", "Cutting = a mild caloric deficit; the macronutrient ratio is adjusted by goal. Detailed calculations are in the dietetics materials."] },
  ] },

  { cz: "Výživa · sportovní výživa a doping", en: "Nutrition · sports nutrition and doping", blocks: [
    { t: "p", cz: "Výživa kolem výkonu podporuje trénink i regeneraci; doplňky mají smysl až nad rámec kvalitní stravy.", en: "Nutrition around performance supports training and recovery; supplements make sense only on top of a good diet." },
    { t: "k", cz: ["Načasování živin (sacharidy a bílkoviny kolem tréninku) podporuje výkon a zotavení.", "Doping je za hranicí — trenér vede klienta k výkonu přirozenými prostředky: tréninkem, stravou a regenerací."], en: ["Nutrient timing (carbohydrates and protein around training) supports performance and recovery.", "Doping is over the line — the trainer leads the client to performance by natural means: training, diet and recovery."] },
  ] },

  { cz: "Fyziologie a první pomoc", en: "Physiology and first aid", blocks: [
    { t: "p", cz: "Seminář propojuje základní fyziologii zátěže s první pomocí v praxi trenéra.", en: "The seminar links basic exercise physiology with first aid in a trainer practice." },
    { t: "k", cz: ["Fyziologie: kosti (opora, ochrana, krvetvorba), svaly (příčně pruhované — volní pohyb; kontrakce a energetické krytí) a trávicí soustava.", "Energetické krytí: bílá svalová vlákna využívají rychle svalový glykogen, červená vlákna tuky při delší vytrvalostní aktivitě.", "První pomoc: rozpoznat přetížení či kolaps a adekvátně reagovat — podrobně na semináři."], en: ["Physiology: bones (support, protection, blood formation), muscles (striated — voluntary movement; contraction and energy supply) and the digestive system.", "Energy supply: white muscle fibres use muscle glycogen quickly, red fibres use fat during longer endurance work.", "First aid: recognize overload or collapse and respond appropriately — covered in detail at the seminar."] },
  ] },

  { cz: "TČM — tradiční čínská medicína", en: "TCM — traditional Chinese medicine", blocks: [
    { t: "p", cz: "Seminář TČM přidává pohled na tělo jako na tok energie a rovnováhu.", en: "The TCM seminar adds a view of the body as a flow of energy and balance." },
    { t: "k", cz: ["Základní pojmy: Qi (čchi) — životní energie — a Krev; proudí drahami zvanými meridiány.", "Cílem je rovnováha. TČM slouží jako doplňkový pohled k tréninku a regeneraci, ne jako náhrada lékařské péče."], en: ["Core terms: Qi — life energy — and Blood; they flow through channels called meridians.", "The aim is balance. TCM serves as a complementary view to training and recovery, not a substitute for medical care."] },
  ] },

  { cz: "Regenerace", en: "Recovery", blocks: [
    { t: "p", cz: "Regenerace je souhrn biologických procesů obnovujících psychické a tělesné síly narušené zátěží. Začíná už během tréninku.", en: "Recovery is the set of biological processes that restore the mental and physical strength disturbed by load. It begins already during training." },
    { t: "sub", cz: "Únava a přetrénování", en: "Fatigue and overtraining" },
    { t: "k", cz: ["Únava je obranný mechanismus (pokles výkonu). Rychlá (anaerobní, acidóza) vs. pomalá (vyčerpání glykogenu).", "Patologická únava = přetížení; dlouhodobě přetrénování (chronická únava) — nechuť k tréninku, poruchy spánku a apetitu, časté infekce, podrážděnost. Prevence: zátěž úměrná regeneraci."], en: ["Fatigue is a protective mechanism (drop in performance). Fast (anaerobic, acidosis) vs. slow (glycogen depletion).", "Pathological fatigue = overload; long-term overtraining (chronic fatigue) — aversion to training, sleep and appetite issues, frequent infections, irritability. Prevention: load proportional to recovery."] },
    { t: "sub", cz: "Formy regenerace", en: "Forms of recovery" },
    { t: "k", cz: ["Pasivní (vůlí neovlivnitelná) a aktivní: pasivní odpočinek (relaxace, masáž, termoterapie, hydroterapie, sauna) a aktivní odpočinek (kompenzační cvičení, lehká cyklická aktivita pro prokrvení).", "Regeneraci řídí parasympatikus — zklidnění, prokrvení trávení, anabolické procesy. Klíčové je načasování dle biorytmu, zejména spánek."], en: ["Passive (not under will) and active: passive rest (relaxation, massage, thermo- and hydrotherapy, sauna) and active rest (compensatory exercise, light cyclic activity for circulation).", "Recovery is driven by the parasympathetic system — calming, gut circulation, anabolic processes. Timing to the biorhythm, especially sleep, is key."] },
    { t: "q", cz: "Tréninková zátěž by měla být úměrná možnostem regenerace sportovce.", en: "The training load should be proportional to the athlete capacity for recovery.", by: "Vital Institut" },
  ] },

  { cz: "Diagnostika pohybového aparátu", en: "Diagnostics of the movement system", blocks: [
    { t: "p", cz: "Diagnostice předchází vstupní pohovor (anamnéza); pak následuje aspekce a funkční testy. Z nich vychází zařazení klienta do kategorie A, B nebo C.", en: "Diagnostics is preceded by an intake interview (history); then come inspection and functional tests. From these the client is placed into category A, B or C." },
    { t: "sub", cz: "Anamnéza — vstupní pohovor", en: "History — the intake interview" },
    { t: "k", cz: ["Základní informace (věk, výška, váha), sportovní a pracovní pohybové stereotypy, zdravotní anamnéza (zranění, operace), cíle, preference a limitace."], en: ["Basic info (age, height, weight), sport and work movement patterns, health history (injuries, surgeries), goals, preferences and limitations."] },
    { t: "sub", cz: "Aspekce a funkční testy", en: "Inspection and functional tests" },
    { t: "k", cz: ["Aspekci vedeme odspodu: chodidla a nožní klenba, kolena (genua valga 'X' / vara 'O'), symetrie pánve (přední spiny), thorakobrachiální trojúhelníky, případná skolióza.", "Funkční testy: test dřepu a vývojové pozice (3měsíční, 6měsíční) + schopnost udržet nitrobřišní tlak — určují kategorii klienta."], en: ["Inspection goes bottom-up: feet and arch, knees (genua valga 'X' / vara 'O'), pelvic symmetry (anterior spines), thoraco-brachial triangles, possible scoliosis.", "Functional tests: the squat test and developmental positions (3-month, 6-month) + the ability to hold intra-abdominal pressure — these set the client category."] },
  ] },

  { cz: "HSS — hluboký stabilizační systém", en: "Deep stabilization system (HSS)", blocks: [
    { t: "p", cz: "Pro hluboký stabilizační systém používáme zkratku HSS, v zahraniční terminologii 'core'. Je to systém funkčně propojených svalů v oblasti středu těla; jejich vzájemná koordinace vytváří oporu pro jakýkoliv pohyb.", en: "We abbreviate the deep stabilization system as HSS — internationally, the 'core'. It is a system of functionally interconnected muscles around the center of the body; their coordination creates the support base for any movement." },
    { t: "k", cz: ["Základ opory při stabilizaci — vytváří nitrobřišní tlak a pevný oporný bod při každém pohybu.", "Umožňuje správné postavení a funkci orgánů v břišní dutině (např. kontinence).", "Chrání páteř — prevence přetížení svalů v bederní oblasti.", "Lepší ekonomika pohybu = úspora energie a vyšší sportovní výkon."], en: ["The base of support in stabilization — it creates intra-abdominal pressure and a firm anchor for every movement.", "Enables the correct position and function of the organs in the abdominal cavity (e.g. continence).", "Protects the spine — prevents overload of the muscles in the lumbar region.", "Better movement economy = energy saving and higher performance."] },
    { t: "q", cz: "Trenér by měl klientovi popsat HSS jako válec kolem celé oblasti břišní krajiny.", en: "A trainer should describe HSS to the client as a cylinder around the whole abdominal region.", by: "Vital Institut" },
    { t: "sub", cz: "Z čeho se HSS skládá — 4 svaly", en: "What HSS is made of — 4 muscles" },
    { t: "g", k: "vi_hss" },
    { t: "k", cz: ["Bránice (diaphragma thoracis) — hlavní nádechový sval; reguluje nitrobřišní tlak a ovlivňuje postavení hrudníku a páteře.", "M. transversus abdominis — nejhlubší vrstva břišní stěny, 'vnitřní opasek'; aktivuje se první při každém pohybu končetin.", "M. multifidi — hluboká vrstva zádových svalů mezi obratli a kostí křížovou; napřímení páteře.", "Pánevní dno (diaphragma pelvis) — pružná spodina pánve; s bránicí a transversem reguluje nitrobřišní tlak."], en: ["Diaphragm (diaphragma thoracis) — the main inhalation muscle; regulates intra-abdominal pressure and influences the position of the chest and spine.", "M. transversus abdominis — the deepest layer of the abdominal wall, the inner belt; it activates first with every limb movement.", "M. multifidi — the deep layer of back muscles between the vertebrae and the sacrum; straightens the spine.", "Pelvic floor (diaphragma pelvis) — the elastic base of the pelvis; with the diaphragm and transversus it regulates intra-abdominal pressure."] },
    { t: "img", src: "https://commons.wikimedia.org/wiki/Special:FilePath/Transversus_abdominis.png?width=460", w: 340, cap: "M. transversus abdominis — 'vnitřní opasek'. Gray's Anatomy, public domain.", capen: "M. transversus abdominis — the inner belt. Gray's Anatomy, public domain." },
    { t: "p", cz: "Když se bránice aktivuje ve špatném řetězci (paradoxní funkce bránice), páteř se destabilizuje a přetěžují se pomocné nádechové svaly. Odtud pramení typické syndromy: přesýpací hodiny, rozevřené nůžky, horní zkřížený syndrom (HZS) a dolní zkřížený syndrom (DZS).", en: "When the diaphragm activates in the wrong chain (paradoxical diaphragm function), the spine is destabilized and the accessory breathing muscles get overloaded. This is where the typical syndromes come from: hourglass, open scissors, upper crossed syndrome (HZS) and lower crossed syndrome (DZS)." },
    { t: "q", cz: "Stabilizace trupu není dána silou břišních nebo zádových svalů, ale je výsledkem optimální regulace nitrobřišního tlaku.", en: "Trunk stabilization is not given by the strength of the abdominal or back muscles — it is the result of optimal regulation of intra-abdominal pressure.", by: "Vital Institut" },
  ] },

  { cz: "Silový trénink", en: "Strength training", blocks: [
    { t: "p", cz: "Cviky řadíme od velkých svalových partií (prsa, záda, nohy) po malé (biceps, triceps, ramena). Základní pauza mezi sériemi je cca 1 minuta; podle cíle klienta ji spolu s počtem opakování a sérií upravujeme.", en: "Order exercises from large muscle groups (chest, back, legs) to small ones (biceps, triceps, shoulders). The default rest between sets is about 1 minute; we adjust it together with reps and sets according to the client goal." },
    { t: "g", k: "vi_dose" },
    { t: "sub", cz: "Modifikace dle cíle klienta", en: "Modification by client goal" },
    { t: "k", cz: ["Síla — 3–8 opakování, pauza 2–3 min, 3–4 silové cviky, převaha cviků s činkami.", "Objem — 6–12 opakování, pauza cca 2 min, 3–5 sérií na partii.", "Tvarování — 10–15 opakování, pauza cca 1 min, 3–5 sérií.", "Redukce / kondice — 15–30 opakování, pauza pod 1 min; kruhový, intervalový (TABATA) nebo lehké kardio."], en: ["Strength — 3–8 reps, rest 2–3 min, 3–4 strength lifts, mostly with barbells/dumbbells.", "Volume — 6–12 reps, rest about 2 min, 3–5 sets per group.", "Shaping — 10–15 reps, rest about 1 min, 3–5 sets.", "Cutting / fitness — 15–30 reps, rest under 1 min; circuit, interval (TABATA) or light cardio."] },
    { t: "p", cz: "Sílu budujeme převahou cviků s činkami a nižšími opakováními. Zátěž řídíme mimo jiné principem pyramidy (zátěž nahoru, opakování dolů) a jeho obrácenou variantou.", en: "Strength is built mainly with free-weight lifts at lower reps. Load is managed among other things by the pyramid principle (load up, reps down) and its reverse." },
  ] },

  { cz: "Anatomická rozcvička a štěpený trénink", en: "Anatomical warm-up and split training", blocks: [
    { t: "p", cz: "Každou jednotku otevírá zahřátí a dynamický (anatomický) strečink — připraví klouby a svaly na zátěž.", en: "Every session opens with a warm-up and a dynamic (anatomical) stretch — it prepares the joints and muscles for load." },
    { t: "sub", cz: "Funkční vs. štěpený trénink", en: "Functional vs. split training" },
    { t: "k", cz: ["Funkční trénink — komplexní cvičení zapojující co nejvíc svalových skupin; hlavní pohyby jsou tlak, tah, předklon, výpad, dřep a rotace. Patří k nejlepší prevenci úrazu.", "Štěpený trénink (split) — cílené procvičení konkrétní partie, zatímco ostatní regenerují. Partie dělíme do 3–4 skupin; stejná partie se opakuje jednou za 2 až 7 dní."], en: ["Functional training — compound work engaging as many muscle groups as possible; the main patterns are push, pull, hinge, lunge, squat and rotation. Among the best injury prevention.", "Split training — targeted work on one group while the others recover. Groups are split into 3–4; the same group returns every 2–7 days."] },
    { t: "g", k: "vi_split" },
    { t: "sub", cz: "Systémy štěpení", en: "Split systems" },
    { t: "k", cz: ["Celotělový (full-body) — 3× týdně, vhodný pro klienty A/B i pro redukci.", "Push–pull–legs — 1. den tlakové cviky, 2. den tahové, 3. den nohy.", "Systémy dnů: 2+1, 3+1, 4+1, 2+1+2+1 (počet tréninkových dnů + dny volna).", "Každý den jiná partie — pro pokročilé (klient C)."], en: ["Full-body — 3× a week, good for clients A/B and for cutting.", "Push–pull–legs — day 1 pushes, day 2 pulls, day 3 legs.", "Day systems: 2+1, 3+1, 4+1, 2+1+2+1 (training days + rest days).", "One part per day — for advanced clients (type C)."] },
    { t: "sub", cz: "Stavba tréninkové jednotky", en: "Structure of a training unit" },
    { t: "g", k: "vi_session" },
    { t: "p", cz: "Zahřátí + dynamický strečink → základní část (HSS, stabilizátory lopatky, břicho) → nadstavba od velkých partií po malé → statický strečink.", en: "Warm-up + dynamic stretch → base block (core, scapular stabilizers, abs) → add-on from large to small groups → static stretch." },
  ] },

  { cz: "Mikro, mezo, makrocykly", en: "Micro, meso, macrocycles", blocks: [
    { t: "p", cz: "Tréninkový cyklus je časově uzavřený celek, který svou strukturou a dynamikou zatížení opakovaně vyvolává změny trénovanosti. Plánujeme shora dolů — od makrocyklu k mikrocyklu — protože obsah kratších cyklů vychází z těch delších.", en: "A training cycle is a closed unit whose structure and load dynamics repeatedly drive changes in fitness. We plan top-down — from the macrocycle to the microcycle — because the content of the shorter cycles follows from the longer ones." },
    { t: "g", k: "vi_cycles" },
    { t: "sub", cz: "Tři úrovně cyklů", en: "Three levels of cycles" },
    { t: "k", cz: ["Mikrocyklus — 1–4 týdny, několik tréninkových jednotek; základní stavební kámen tréninku.", "Mezocyklus — 3–12 týdnů, několik mikrocyklů; vytváří a udržuje adaptace.", "Makrocyklus — nejčastěji roční tréninkový cyklus (RTC); cílem je dosáhnout vytyčeného cíle."], en: ["Microcycle — 1–4 weeks, several sessions; the basic building block.", "Mesocycle — 3–12 weeks, several microcycles; creates and maintains adaptations.", "Macrocycle — usually the annual training cycle; aims at the set goal."] },
    { t: "sub", cz: "Typy mikrocyklů", en: "Types of microcycle" },
    { t: "k", cz: ["Úvodní — po delší pauze (zranění, nemoc) nebo na začátku cyklu.", "Progresivní (rozvíjející) — rozvoj trénovanosti dle cíle.", "Upevňovací (stabilizační) — udržení dosažené úrovně, menší objem.", "Relaxační — prevence přetrénování; aerobní zátěž a měkké techniky.", "Vylaďovací (soutěžní) — vyladění formy před závodem.", "Regenerační — po dlouhém makrocyklu; aktivní i pasivní odpočinek.", "Kontrolní — vyhodnocení trénovanosti a výkonnosti."], en: ["Introductory — after a longer break (injury, illness) or at the start.", "Progressive (developmental) — building fitness toward the goal.", "Consolidating (stabilizing) — holding the level, smaller volume.", "Relaxation — preventing overtraining; aerobic load and soft techniques.", "Tapering (competition) — sharpening form before a contest.", "Recovery — after a long macrocycle; active and passive rest.", "Control — evaluating fitness and performance."] },
  ] },

  { cz: "Metodika sestavení tréninkového plánu", en: "Methodology of building a training plan", blocks: [
    { t: "p", cz: "Po vstupním pohovoru a diagnostice zařadíme klienta do kategorie A, B nebo C. Rozhoduje schopnost stabilizace (udržení neutrálních segmentů a aktivace HSS) a stupeň trénovanosti. U každého cílíme na postupný progres až do kategorie C.", en: "After the intake interview and diagnostics we place the client into category A, B or C. It is decided by the ability to stabilize (holding neutral segments and activating the HSS) and the training level. For everyone we aim at gradual progress up to category C." },
    { t: "sub", cz: "Klient A (a A+)", en: "Client A (and A+)" },
    { t: "k", cz: ["Zpravidla začátečník; nízká stabilizace, možné dysbalance. HSS aktivuje hlavně vleže a vsedě s oporou (3měsíční poloha).", "Diagnostika: nezvládá vzpor na čtyřech (6měsíční pozici) ani dřep, neudrží nitrobřišní tlak déle (max cca 8 nádechů).", "Cvičí jen základní část: 3–4 cviky ×3 série na HSS + 3–4 cviky ×3 série na stabilizátory lopatky. Okolo 30 min, bez zátěže, bez intenzifikace. Frekvence 2–3× týdně.", "A+ (mezistupeň): navíc nadstavba 3–5 cviků, mírná zátěž kolem 10 opakování, cviky s oporou (floor press, pull-over, abdukce, francouzský tlak, biceps vsedě)."], en: ["Usually a beginner; low stabilization, possible imbalances. Activates the HSS mainly lying and sitting with support (the 3-month position).", "Diagnostics: cannot do the quadruped hold (6-month position) or the squat, cannot hold intra-abdominal pressure for long (max about 8 breaths).", "Trains only the base block: 3–4 exercises ×3 sets for the HSS + 3–4 ×3 for the scapular stabilizers. Around 30 min, no load, no intensification. 2–3× a week.", "A+ (intermediate step): adds an add-on of 3–5 exercises, light load around 10 reps, supported exercises (floor press, pull-over, abduction, French press, seated biceps)."] },
    { t: "sub", cz: "Klient B (a B+)", en: "Client B (and B+)" },
    { t: "k", cz: ["Mírně pokročilý; zvládne 6měsíční pozici, aktivní HSS a správné dýchání.", "Cvičí základní část (těžší modifikace: HSS dle vývojové kineziologie, stabilizátory lopatky, břicho) + nadstavbu dle cíle (2–3 cviky na velké partie, 1–2 na malé).", "Zařazujeme intenzifikační prvky — modifikace zátěže, opakování, pauz, prodloužení negativní fáze."], en: ["Slightly advanced; manages the 6-month position, active HSS and correct breathing.", "Trains the base block (harder modifications: HSS per developmental kinesiology, scapular stabilizers, abs) + an add-on by goal (2–3 exercises for large groups, 1–2 for small).", "We add intensification — load, reps, rest changes, lengthening the negative phase."] },
    { t: "sub", cz: "Klient C", en: "Client C" },
    { t: "k", cz: ["Trénovaný; zvládá náročné cviky bez opory, vícekloubové pohyby (dřep, mrtvý tah, benchpress, shyby, výpady, angličáky).", "Základní část (2–3 cviky na HSS + 2–3 na břicho + 3 na záda) + nadstavba 5–10 cviků od velkých partií po malé.", "Hodně intenzifikačních metod a vyšší variabilita. Celotělový trénink lze uspořádat do splitu (silově-objemový)."], en: ["Trained; handles demanding unsupported, multi-joint movements (squat, deadlift, bench press, pull-ups, lunges, burpees).", "Base block (2–3 HSS + 2–3 abs + 3 back) + an add-on of 5–10 exercises from large to small groups.", "Plenty of intensification and higher variability. A full-body session can be arranged into a split (strength–volume)."] },
    { t: "q", cz: "Klient v dané skupině nezůstane navždy — u každého cílíme na postupný progres do kategorie C.", en: "A client does not stay in a group forever — for each we aim at gradual progress into category C.", by: "Vital Institut" },
    { t: "p", cz: "Z téhle logiky (kategorie klienta × cíl × frekvence) staví i generátor plánů v záložce Plán.", en: "The plan generator in the Plan tab builds on this same logic (client category × goal × frequency)." },
  ] },

  { cz: "Tréninkové metody a intenzifikační postupy", en: "Training methods and intensification", blocks: [
    { t: "sub", cz: "Tréninkové metody", en: "Training methods" },
    { t: "k", cz: ["Funkční trénink — komplexní pohyby, prevence úrazu, přenos do běžného života.", "Redukční — tepová frekvence kolem 70 % maxima, alespoň 45 min, přes 300 min týdně (TFmax = 220 − věk).", "Kondiční — aerobní 50–70 %, anaerobní 80–90 % TFmax.", "Kruhový — stanoviště, pauza 20–30 s, mezi koly 2–4 min; rozvíjí vytrvalostní sílu.", "Intervalový / TABATA — 20 s cvičení a 10 s pauzy ×8 = 4 min ve vysoké intenzitě."], en: ["Functional — compound movements, injury prevention, carryover to daily life.", "Cutting — heart rate around 70 % of max, at least 45 min, over 300 min a week (HRmax = 220 − age).", "Conditioning — aerobic 50–70 %, anaerobic 80–90 % of HRmax.", "Circuit — stations, rest 20–30 s, 2–4 min between rounds; builds strength-endurance.", "Interval / TABATA — 20 s work and 10 s rest ×8 = 4 min at high intensity."] },
    { t: "sub", cz: "Intenzifikační postupy (pro pokročilé)", en: "Intensification methods (advanced)" },
    { t: "k", cz: ["Supersérie (i trisérie, gigantická série) — cviky bez pauzy za sebou.", "Vynucená opakování — s mírnou dopomocí, jen velmi pokročilí.", "Negativní opakování — zpomalení excentrické fáze.", "Shazovací série — během série postupně snižujeme zátěž.", "Princip pyramidy (i obrácené) — zátěž nahoru, opakování dolů.", "Před vyčerpáním — izolovaný cvik před vícekloubovým.", "Jednadvacítka — 7+7+7 opakování (dolní / horní / plný rozsah).", "Izometrická kontrakce — statické cviky (plank, výdrž v dřepu, ve visu)."], en: ["Supersets (also tri-sets, giant sets) — exercises back to back without rest.", "Forced reps — with light assistance, advanced only.", "Negative reps — slowing the eccentric phase.", "Drop sets — lowering the load during the set.", "Pyramid (and reverse) — load up, reps down.", "Pre-exhaustion — an isolation lift before a compound one.", "Twenty-ones — 7+7+7 reps (lower / upper / full range).", "Isometric contraction — static holds (plank, wall-sit, hang)."] },
    { t: "p", cz: "Intenzifikační postupy zařazujeme hlavně u klientů B a C k prolomení stagnace; u klienta A je nepoužíváme.", en: "Intensification is used mainly with clients B and C to break stagnation; with client A we do not use it." },
  ] },

  { cz: "Zásobník cviků", en: "Exercise bank", blocks: [
    { t: "p", cz: "Cviky po partiích — zádové svaly, biceps, triceps + ramena, prsní svaly a strečink — plus sobotní praktická výuka. Zdroj cviků pro generátor plánů.", en: "Exercises by muscle group — back, biceps, triceps + shoulders, chest and stretching — plus the Saturday practical sessions. The exercise source for the plan generator." },
  ] },
];

