function OfflineBadge() {
  const { t } = useT();
  const [online, setOnline] = useState(typeof navigator !== "undefined" ? navigator.onLine : true);
  React.useEffect(() => {
    const on = () => setOnline(true), off = () => setOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
  }, []);
  if (online) return null;
  return (
    <div
      title={L("Jsi offline. Změny se uloží a synchronizují po připojení. Média se načtou jen u stránek uložených offline.", "You are offline. Changes save and sync once you reconnect. Media loads only for pages saved offline.")}
      style={{ position: "fixed", left: 16, bottom: 16, zIndex: 9999, display: "inline-flex", alignItems: "center", gap: 7, background: t.card, border: `1px solid ${t.border}`, borderRadius: 999, padding: "6px 13px", boxShadow: "0 6px 20px rgba(0,0,0,0.28)", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, color: t.textMuted }}
    >
      <span style={{ width: 7, height: 7, borderRadius: "50%", background: t.sand, flexShrink: 0 }} />
      {L("Offline", "Offline")}
    </div>
  );
}


